INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_A1_01','trip','/trɪp/','noun','여행','A short journey to a place and back again.','We went on a {trip} to the beach last summer.','지난 여름에 해변으로 여행을 갔어요.','trip','A1','travel',1,'trip beach travel summer'),
('w_travel_A1_02','hotel','/hoʊˈtel/','noun','호텔','A building where people pay to sleep and eat.','We stayed at a nice {hotel} near the city centre.','시내 중심가 근처 좋은 호텔에 묵었어요.','hotel','A1','travel',1,'hotel building entrance lobby'),
('w_travel_A1_03','map','/mæp/','noun','지도','A drawing that shows streets, rivers, and places.','Can you show me on the {map} where we are?','지도에서 지금 우리가 어디 있는지 알려주실 수 있나요?','map','A1','travel',1,'map navigation street city'),
('w_travel_A1_04','plane','/pleɪn/','noun','비행기','A vehicle with wings that flies through the air.','The {plane} takes off at nine in the morning.','비행기는 아침 9시에 이륙해요.','plane','A1','travel',1,'airplane flight sky clouds'),
('w_travel_A1_05','passport','/ˈpæspɔːrt/','noun','여권','An official document that proves who you are when travelling abroad.','Don''t forget to bring your {passport} to the airport.','공항에 여권 챙기는 것 잊지 마세요.','passport','A1','travel',1,'passport document travel identity'),
('w_travel_A1_06','bag','/bæɡ/','noun','가방','A container made of cloth or leather used to carry things.','I put my camera in my {bag} before leaving.','출발하기 전에 카메라를 가방에 넣었어요.','bag','A1','travel',2,'bag backpack travel luggage'),
('w_travel_A1_07','book','/bʊk/','verb','예약하다','To arrange to have a seat, room, or ticket in advance.','I need to {book} a room for two nights.','2박짜리 방을 예약해야 해요.','book','A1','travel',1,'booking reservation hotel online'),
('w_travel_A1_08','stay','/steɪ/','verb','머물다','To remain in a place for a period of time.','How long do you plan to {stay} in London?','런던에 얼마나 머물 계획이세요?','stay','A1','travel',1,'stay hotel room window'),
('w_travel_A1_09','go','/ɡoʊ/','verb','가다','To move or travel to a place.','Where do you want to {go} on your holiday?','휴가 때 어디 가고 싶으세요?','go','A1','travel',1,'travel destination road journey'),
('w_travel_A1_10','visit','/ˈvɪzɪt/','verb','방문하다','To go to see a person or place.','I want to {visit} the old castle this weekend.','이번 주말에 오래된 성을 방문하고 싶어요.','visit','A1','travel',1,'visit castle tourism landmark'),
('w_travel_A1_11','ticket','/ˈtɪkɪt/','noun','표, 티켓','A piece of paper that shows you have paid to travel or enter somewhere.','I bought a round-trip {ticket} to Paris.','파리행 왕복 티켓을 샀어요.','ticket','A1','travel',1,'ticket train airplane boarding pass'),
('w_travel_A1_12','bus','/bʌs/','noun','버스','A large road vehicle that carries passengers.','Take the number 5 {bus} to the town centre.','5번 버스를 타면 시내 중심가까지 가요.','bus','A1','travel',2,'bus public transport city street'),
('w_travel_A1_13','train','/treɪn/','noun','기차','A vehicle with carriages pulled by an engine along a railway.','The {train} to Barcelona leaves at half past seven.','바르셀로나행 기차는 7시 30분에 떠나요.','train','A1','travel',1,'train station railway travel'),
('w_travel_A1_14','road','/roʊd/','noun','길, 도로','A wide path that vehicles travel on.','Follow this {road} for two kilometres and turn left.','이 길을 2킬로미터 가다가 왼쪽으로 도세요.','road','A1','travel',2,'road highway travel direction'),
('w_travel_A1_15','left','/left/','adjective','왼쪽','On or towards the side that is to the west when you face north.','Turn {left} at the traffic lights.','신호등에서 왼쪽으로 도세요.','left','A1','travel',2,'direction left turn street sign'),
('w_travel_A1_16','right','/raɪt/','adjective','오른쪽','On or towards the side that is to the east when you face north.','The hotel is on your {right}.','호텔이 오른쪽에 있어요.','right','A1','travel',2,'direction right turn street sign'),
('w_travel_A1_17','far','/fɑːr/','adjective','먼, 멀리','At a great distance.','Is the station {far} from here?','역이 여기서 멀어요?','far','A1','travel',2,'distance road horizon far away'),
('w_travel_A1_18','near','/nɪr/','adjective','가까운','At a short distance.','Is there a pharmacy {near} here?','근처에 약국이 있나요?','near','A1','travel',2,'nearby location map pin'),
('w_travel_A1_19','open','/ˈoʊpən/','adjective','열려 있는','Not closed or locked.','What time does the museum {open}?','박물관은 몇 시에 열어요?','open','A1','travel',2,'open door museum entrance'),
('w_travel_A1_20','closed','/kloʊzd/','adjective','닫혀 있는','Not open for business or entry.','The shop is {closed} on Sundays.','그 가게는 일요일에 닫아요.','closed','A1','travel',2,'closed sign shop door'),
('w_travel_A1_21','free','/friː/','adjective','무료의','Not costing any money.','Entrance to the museum is {free} on weekdays.','평일에는 박물관 입장이 무료예요.','free','A1','travel',2,'free entry museum ticket'),
('w_travel_A1_22','price','/praɪs/','noun','가격','The amount of money you pay for something.','What is the {price} of a single room?','1인실 가격이 얼마예요?','price','A1','travel',2,'price tag money hotel room'),
('w_travel_A1_23','city','/ˈsɪti/','noun','도시','A large and important town.','Tokyo is a very exciting {city} to explore.','도쿄는 탐험하기 정말 신나는 도시예요.','city','A1','travel',1,'city skyline urban travel'),
('w_travel_A1_24','country','/ˈkʌntri/','noun','나라, 국가','An area of land with its own government.','France is my favourite {country} to visit.','프랑스는 제가 가장 좋아하는 여행지예요.','country','A1','travel',1,'country flag map travel'),
('w_travel_A1_25','taxi','/ˈtæksi/','noun','택시','A car with a driver you pay to take you somewhere.','Let''s take a {taxi} to the hotel.','택시를 타고 호텔에 가요.','taxi','A1','travel',2,'taxi cab city street yellow'),
('w_travel_A1_26','walk','/wɔːk/','verb','걷다','To move at a regular speed on foot.','Let''s {walk} to the beach — it''s only five minutes.','해변까지 걸어가요. 5분밖에 안 걸려요.','walk','A1','travel',2,'walk path beach travel outdoor'),
('w_travel_A1_27','help','/help/','verb','도와주다','To make it easier for someone to do something.','Excuse me, can you {help} me? I''m lost.','실례합니다, 도와주실 수 있나요? 길을 잃었어요.','help','A1','travel',1,'help direction lost tourist'),
('w_travel_A1_28','camera','/ˈkæmərə/','noun','카메라','A device used for taking photographs.','I always bring my {camera} when I travel.','여행할 때 항상 카메라를 가져가요.','camera','A1','travel',2,'camera photography travel tourist'),
('w_travel_A1_29','money','/ˈmʌni/','noun','돈','Coins and notes used to buy things.','I need to get some local {money} at the bank.','은행에서 현지 화폐를 바꿔야 해요.','money','A1','travel',1,'money cash currency exchange'),
('w_travel_A1_30','key','/kiː/','noun','열쇠, 키','A small metal object used to open a lock.','The front desk will give you a room {key}.','프런트 데스크에서 방 열쇠를 줄 거예요.','key','A1','travel',2,'key hotel room lock card'),
('w_travel_A1_31','water','/ˈwɔːtər/','noun','물','The clear liquid that falls as rain.','Can I have a bottle of {water}, please?','물 한 병 주실 수 있나요?','water','A1','travel',2,'water bottle travel hydration'),
('w_travel_A1_32','food','/fuːd/','noun','음식','Things that people and animals eat.','I love trying local {food} when I travel.','여행할 때 현지 음식을 맛보는 것을 좋아해요.','food','A1','travel',1,'food local restaurant travel cuisine'),
('w_travel_A1_33','airport','/ˈɛrpɔːrt/','noun','공항','A place where planes land and take off.','We need to arrive at the {airport} two hours early.','공항에는 두 시간 일찍 도착해야 해요.','airport','A1','travel',1,'airport terminal airplane departure'),
('w_travel_A1_34','late','/leɪt/','adjective','늦은','After the expected or usual time.','Hurry up or we will be {late} for our flight.','서두르지 않으면 비행기를 놓쳐요.','late','A1','travel',2,'late hurry airport rush'),
('w_travel_A1_35','early','/ˈɜːrli/','adjective','일찍','Before the expected or usual time.','Check-in starts {early} in the morning at six o''clock.','체크인은 아침 6시부터 일찍 시작해요.','early','A1','travel',2,'early morning sunrise departure')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_A2_01','tour','/tʊr/','noun','관광, 투어','An organised trip to see the sights of a place.','We joined a guided {tour} of the old town.','구시가지 가이드 투어에 참가했어요.','tour','A2','travel',1,'tour guide group sightseeing city'),
('w_travel_A2_02','tourist','/ˈtʊrɪst/','noun','관광객','A person who is visiting a place for pleasure.','The market is popular with {tourist}s from all over the world.','그 시장은 전 세계 관광객들에게 인기 있어요.','tourist','A2','travel',1,'tourist group camera sightseeing'),
('w_travel_A2_03','visa','/ˈviːzə/','noun','비자','An official stamp in your passport that allows you to enter a country.','Do I need a {visa} to travel to Thailand?','태국 여행에 비자가 필요한가요?','visa','A2','travel',1,'visa passport stamp travel document'),
('w_travel_A2_04','sightseeing','/ˈsaɪtsiːɪŋ/','noun','관광','The activity of visiting interesting places.','We spent the afternoon {sightseeing} in the city.','오후 내내 도시 관광을 했어요.','sightseeing','A2','travel',1,'sightseeing landmark city tourism'),
('w_travel_A2_05','souvenir','/ˌsuːvəˈnɪr/','noun','기념품','Something you buy to remind you of a place you have visited.','I bought a small {souvenir} for my sister.','여동생한테 줄 작은 기념품을 샀어요.','souvenir','A2','travel',2,'souvenir gift shop market travel'),
('w_travel_A2_06','exchange','/ɪksˈtʃeɪndʒ/','verb','환전하다','To give something and receive something else in return.','Where can I {exchange} my pounds for euros?','파운드를 유로로 환전할 수 있는 곳이 어디예요?','exchange','A2','travel',1,'exchange currency money travel bank'),
('w_travel_A2_07','check-in','/ˈtʃek ɪn/','verb','체크인하다','To register your arrival at a hotel or airport.','We can {check-in} from three o''clock in the afternoon.','오후 3시부터 체크인할 수 있어요.','check-in','A2','travel',1,'check-in hotel reception counter'),
('w_travel_A2_08','hostel','/ˈhɒstəl/','noun','호스텔','A cheap place to stay that provides shared rooms.','We saved money by staying in a {hostel} during the trip.','여행 중 호스텔에 묵어서 돈을 절약했어요.','hostel','A2','travel',2,'hostel dormitory budget travel backpacker'),
('w_travel_A2_09','guide','/ɡaɪd/','noun','가이드','A person who shows tourists around a place.','Our {guide} explained the history of the temple.','가이드가 사원의 역사를 설명해 줬어요.','guide','A2','travel',1,'guide tour group museum landmark'),
('w_travel_A2_10','explore','/ɪkˈsplɔːr/','verb','탐험하다','To travel around an area to learn about it.','I love to {explore} new neighbourhoods when I travel.','여행할 때 새로운 동네를 탐험하는 것을 좋아해요.','explore','A2','travel',1,'explore street city travel adventure'),
('w_travel_A2_11','arrive','/əˈraɪv/','verb','도착하다','To reach a place after travelling.','We will {arrive} at the station at midday.','낮 12시에 역에 도착할 거예요.','arrive','A2','travel',1,'arrive station platform train'),
('w_travel_A2_12','depart','/dɪˈpɑːrt/','verb','출발하다','To leave a place, especially to start a journey.','The coach {depart}s from the central bus stop.','코치 버스는 중앙 버스 정류장에서 출발해요.','depart','A2','travel',1,'depart bus coach departure'),
('w_travel_A2_13','platform','/ˈplætfɔːrm/','noun','플랫폼, 승강장','The raised area in a railway station where passengers get on and off trains.','Your train departs from {platform} four.','열차는 4번 플랫폼에서 출발해요.','platform','A2','travel',2,'platform train station railway'),
('w_travel_A2_14','single','/ˈsɪŋɡəl/','adjective','편도의; 1인용의','For one person or one trip in one direction only.','I''d like a {single} room for three nights, please.','3박 1인실 부탁드려요.','single','A2','travel',2,'single room hotel key'),
('w_travel_A2_15','return','/rɪˈtɜːrn/','noun','왕복 (표)','A ticket for a journey to a place and back again.','Two {return} tickets to Edinburgh, please.','에든버러까지 왕복 표 두 장 주세요.','return','A2','travel',2,'return ticket train station'),
('w_travel_A2_16','schedule','/ˈskedʒuːl/','noun','시간표, 일정','A plan showing when things will happen.','According to the {schedule}, the tour starts at nine.','일정에 따르면 투어는 9시에 시작해요.','schedule','A2','travel',2,'schedule timetable travel plan'),
('w_travel_A2_17','cancel','/ˈkænsəl/','verb','취소하다','To decide that something that was planned will not happen.','We had to {cancel} our trip because of bad weather.','날씨가 나빠서 여행을 취소해야 했어요.','cancel','A2','travel',2,'cancel booking hotel flight'),
('w_travel_A2_18','confirm','/kənˈfɜːrm/','verb','확인하다','To say that something is definitely true or will happen.','Please {confirm} your reservation by email.','이메일로 예약을 확인해 주세요.','confirm','A2','travel',2,'confirm booking reservation email'),
('w_travel_A2_19','entrance','/ˈentrəns/','noun','입구','The door or gate that you use to enter a place.','Meet at the main {entrance} of the museum at ten.','10시에 박물관 정문에서 만나요.','entrance','A2','travel',2,'entrance gate museum door'),
('w_travel_A2_20','exit','/ˈeɡzɪt/','noun','출구','The door or gate that you use to leave a place.','The emergency {exit} is at the back of the plane.','비상구는 비행기 뒤쪽에 있어요.','exit','A2','travel',2,'exit sign door emergency plane'),
('w_travel_A2_21','photo','/ˈfoʊtoʊ/','noun','사진','A picture taken with a camera.','Could you take a {photo} of us in front of the tower?','탑 앞에서 사진 찍어 주실 수 있나요?','photo','A2','travel',1,'photo camera tourist landmark selfie'),
('w_travel_A2_22','share','/ʃer/','verb','공유하다, 나누다','To let others use or enjoy something with you.','I {share} my travel photos on social media.','여행 사진을 소셜 미디어에 공유해요.','share','A2','travel',2,'share social media photo travel'),
('w_travel_A2_23','safe','/seɪf/','adjective','안전한','Not in danger; protected from harm.','This neighbourhood is very {safe} for tourists.','이 동네는 관광객들에게 매우 안전해요.','safe','A2','travel',1,'safe street city travel security'),
('w_travel_A2_24','recommend','/ˌrekəˈmend/','verb','추천하다','To tell someone that something is good.','Can you {recommend} a good local restaurant?','좋은 현지 식당을 추천해 주실 수 있나요?','recommend','A2','travel',1,'recommend restaurant food local'),
('w_travel_A2_25','lost','/lɒst/','adjective','길을 잃은','Unable to find the way.','I got {lost} because I forgot the map.','지도를 놓고 와서 길을 잃었어요.','lost','A2','travel',1,'lost map street direction confused'),
('w_travel_A2_26','straight','/streɪt/','adverb','직진으로','In a straight line without turning.','Go {straight} ahead for about two hundred metres.','약 200미터 직진하세요.','straight','A2','travel',2,'straight ahead road direction'),
('w_travel_A2_27','corner','/ˈkɔːrnər/','noun','모퉁이, 코너','The point where two streets or edges meet.','Turn right at the {corner} of the street.','길 모퉁이에서 오른쪽으로 도세요.','corner','A2','travel',2,'corner street turn direction'),
('w_travel_A2_28','receipt','/rɪˈsiːt/','noun','영수증','A piece of paper showing what you have bought and paid for.','Can I have a {receipt}, please?','영수증 주실 수 있나요?','receipt','A2','travel',2,'receipt payment shopping travel'),
('w_travel_A2_29','included','/ɪnˈkluːdɪd/','adjective','포함된','Forming part of a whole; counted in a total.','Is breakfast {included} in the room rate?','조식이 객실 요금에 포함되어 있나요?','included','A2','travel',1,'included breakfast hotel room rate'),
('w_travel_A2_30','direct','/dɪˈrekt/','adjective','직항의, 직통의','Going straight from one place to another with no stops.','Is there a {direct} flight to Osaka?','오사카 직항 편이 있나요?','direct','A2','travel',2,'direct flight airplane nonstop'),
('w_travel_A2_31','connection','/kəˈnekʃən/','noun','환승 연결편','A plane or train that you change to from another service.','We have a one-hour {connection} in Dubai.','두바이에서 한 시간 환승이 있어요.','connection','A2','travel',2,'connection flight airport transit'),
('w_travel_A2_32','delay','/dɪˈleɪ/','noun','지연','A period of time by which something is late.','There is a forty-minute {delay} due to heavy traffic.','교통 체증으로 40분 지연이 있어요.','delay','A2','travel',1,'delay clock airport waiting'),
('w_travel_A2_33','comfortable','/ˈkʌmftəbəl/','adjective','편안한','Making you feel relaxed and at ease.','The seats on the train were very {comfortable}.','기차 좌석이 매우 편안했어요.','comfortable','A2','travel',2,'comfortable seat train travel relax'),
('w_travel_A2_34','crowded','/ˈkraʊdɪd/','adjective','붐비는','Full of a large number of people.','The beach was too {crowded} in August.','8월에는 해변이 너무 붐볐어요.','crowded','A2','travel',2,'crowded beach summer people tourist'),
('w_travel_A2_35','local','/ˈloʊkəl/','adjective','현지의','Belonging to or relating to a particular area.','Ask a {local} person for the best restaurant tips.','최고의 식당 팁은 현지인에게 물어보세요.','local','A2','travel',1,'local market food culture travel')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_B1_01','accommodation','/əˌkɒməˈdeɪʃən/','noun','숙박 시설','A place where someone can stay, especially when travelling.','We found affordable {accommodation} near the city centre.','시내 중심가 근처에서 저렴한 숙박 시설을 찾았어요.','accommodation','B1','travel',1,'accommodation hotel room travel stay'),
('w_travel_B1_02','itinerary','/aɪˈtɪnərəri/','noun','여행 일정','A detailed plan or route for a journey.','Our travel agent prepared a detailed {itinerary} for the trip.','여행사가 여행을 위한 상세한 일정을 준비해 줬어요.','itinerary','B1','travel',1,'itinerary plan schedule travel map'),
('w_travel_B1_03','jet lag','/ˈdʒet læɡ/','noun','시차 피로','Tiredness felt after a long flight across time zones.','I always suffer from {jet lag} after flying to the US.','미국 비행 후에는 항상 시차 피로를 겪어요.','jet lag','B1','travel',2,'jet lag tired airplane sleep'),
('w_travel_B1_04','currency','/ˈkʌrənsi/','noun','통화, 화폐','The system of money used in a particular country.','What {currency} do they use in Japan?','일본에서는 어떤 화폐를 사용하나요?','currency','B1','travel',1,'currency money yen dollar exchange'),
('w_travel_B1_05','customs','/ˈkʌstəmz/','noun','세관','The government department that checks goods entering a country.','All bags are screened at {customs} on arrival.','도착 시 모든 가방은 세관에서 검사해요.','customs','B1','travel',1,'customs airport security luggage check'),
('w_travel_B1_06','boarding','/ˈbɔːrdɪŋ/','noun','탑승','The process of getting onto a plane, ship, or bus.','{Boarding} will begin thirty minutes before departure.','탑승은 출발 30분 전에 시작돼요.','boarding','B1','travel',1,'boarding gate airplane passenger queue'),
('w_travel_B1_07','excursion','/ɪkˈskɜːrʒən/','noun','소풍, 당일치기 여행','A short trip, often as part of a holiday.','We took an {excursion} to the waterfall from our resort.','리조트에서 폭포로 소풍을 다녀왔어요.','excursion','B1','travel',2,'excursion waterfall nature day trip'),
('w_travel_B1_08','backpack','/ˈbækpæk/','noun','배낭','A bag carried on your back, used especially when hiking.','She carried all her essentials in a sturdy {backpack}.','튼튼한 배낭에 필수품을 모두 담아서 다녔어요.','backpack','B1','travel',2,'backpack hiker trail mountain travel'),
('w_travel_B1_09','landmark','/ˈlændmɑːrk/','noun','명소, 랜드마크','A well-known building or place used as a reference point.','The Eiffel Tower is Paris''s most famous {landmark}.','에펠탑은 파리의 가장 유명한 랜드마크예요.','landmark','B1','travel',1,'landmark eiffel tower paris tourism'),
('w_travel_B1_10','phrase book','/ˈfreɪz bʊk/','noun','회화책','A book of common expressions in a foreign language.','I carried a Japanese {phrase book} throughout my trip.','여행 내내 일본어 회화책을 가지고 다녔어요.','phrase book','B1','travel',2,'phrase book language travel japan'),
('w_travel_B1_11','insurance','/ɪnˈʃʊərəns/','noun','보험','An arrangement that provides financial protection against risk.','Travel {insurance} is essential in case of emergencies.','비상사태에 대비해 여행 보험은 필수예요.','insurance','B1','travel',1,'insurance travel document protection'),
('w_travel_B1_12','border','/ˈbɔːrdər/','noun','국경','The line that separates two countries.','We crossed the {border} by train in the early morning.','이른 아침에 기차로 국경을 넘었어요.','border','B1','travel',1,'border crossing checkpoint passport'),
('w_travel_B1_13','permit','/ˈpɜːrmɪt/','noun','허가증','An official document giving permission to do something.','You need a special {permit} to camp in this national park.','이 국립공원에서 캠핑하려면 특별 허가증이 필요해요.','permit','B1','travel',2,'permit document park camping official'),
('w_travel_B1_14','detour','/ˈdiːtʊr/','noun','우회로, 돌아가는 길','A longer, alternative route taken to avoid something or see extra sights.','We made a {detour} through the mountain village on the way back.','돌아오는 길에 산 마을을 거쳐 돌아갔어요.','detour','B1','travel',2,'detour mountain village road scenic'),
('w_travel_B1_15','budget','/ˈbʌdʒɪt/','noun','예산','The total amount of money available for a trip.','We planned the trip on a tight {budget}.','빠듯한 예산으로 여행을 계획했어요.','budget','B1','travel',1,'budget money planning travel savings'),
('w_travel_B1_16','guidebook','/ˈɡaɪdbʊk/','noun','여행 안내서','A book of information for visitors to a place.','According to the {guidebook}, the palace closes at five.','여행 안내서에 따르면 궁전은 5시에 닫아요.','guidebook','B1','travel',2,'guidebook travel book tourism information'),
('w_travel_B1_17','embark','/ɪmˈbɑːrk/','verb','탑승하다, 출발하다','To get on a ship or plane; to begin a journey.','Passengers will {embark} from gate twelve.','승객들은 12번 게이트에서 탑승할 거예요.','embark','B1','travel',2,'embark ship cruise boarding gate'),
('w_travel_B1_18','disembark','/ˌdɪsɪmˈbɑːrk/','verb','하선하다, 내리다','To leave a ship, aircraft, or other vehicle.','Passengers should {disembark} in an orderly fashion.','승객들은 질서 있게 내려야 해요.','disembark','B1','travel',3,'disembark ship dock passengers'),
('w_travel_B1_19','baggage claim','/ˈbæɡɪdʒ kleɪm/','noun','수하물 찾는 곳','The place at an airport where you collect your bags.','Meet me at the {baggage claim} area when you land.','도착하면 수하물 찾는 곳에서 만나요.','baggage claim','B1','travel',1,'baggage claim airport carousel luggage'),
('w_travel_B1_20','check out','/tʃek aʊt/','phrasal verb','체크아웃하다','To leave a hotel and pay your bill.','We need to {check out} before noon on Saturday.','토요일 정오 전에 체크아웃해야 해요.','check out','B1','travel',1,'checkout hotel reception key payment'),
('w_travel_B1_21','layover','/ˈleɪoʊvər/','noun','경유 대기 시간','A stop between two parts of a long journey.','We had a five-hour {layover} in Singapore.','싱가포르에서 5시간 경유 대기가 있었어요.','layover','B1','travel',2,'layover airport waiting lounge transit'),
('w_travel_B1_22','domestic','/dəˈmestɪk/','adjective','국내의','Relating to a person''s own country.','I usually take {domestic} flights within Korea.','보통 국내선을 타고 국내 여행을 해요.','domestic','B1','travel',2,'domestic flight airplane korea local'),
('w_travel_B1_23','international','/ˌɪntərˈnæʃənəl/','adjective','국제적인','Involving more than one country.','The {international} terminal is in a separate building.','국제선 터미널은 별도 건물에 있어요.','international','B1','travel',1,'international terminal airport global flight'),
('w_travel_B1_24','transfer','/ˈtrænsf3ːr/','noun','환승','A change from one vehicle or service to another.','You will need to make a {transfer} in Frankfurt.','프랑크푸르트에서 환승해야 해요.','transfer','B1','travel',1,'transfer flight airport connection hub'),
('w_travel_B1_25','overbook','/ˌoʊvərˈbʊk/','verb','초과 예약하다','To accept more reservations than there are seats or rooms available.','The hotel {overbook}ed and had to find us an alternative.','호텔이 초과 예약되어 다른 곳을 찾아줘야 했어요.','overbook','B1','travel',2,'overbook hotel reception complaint'),
('w_travel_B1_26','cancellation','/ˌkænsəˈleɪʃən/','noun','취소','The act of deciding that something will not happen.','We received a full refund after the {cancellation}.','취소 후 전액 환불을 받았어요.','cancellation','B1','travel',2,'cancellation refund booking flight'),
('w_travel_B1_27','refund','/ˈriːfʌnd/','noun','환불','Money paid back to you when you return something.','They gave us a full {refund} for the cancelled tour.','취소된 투어에 대해 전액 환불해 줬어요.','refund','B1','travel',1,'refund money back travel booking'),
('w_travel_B1_28','upgrade','/ˈʌpɡreɪd/','noun','업그레이드','A move to a better class or standard.','We got a free {upgrade} to a sea-view room.','무료로 바다가 보이는 방으로 업그레이드됐어요.','upgrade','B1','travel',2,'upgrade hotel room view premium'),
('w_travel_B1_29','expedition','/ˌekspɪˈdɪʃən/','noun','탐험 여행','An organised journey for a particular purpose.','The team set off on a two-week {expedition} to the jungle.','팀은 정글로 2주간의 탐험 여행을 떠났어요.','expedition','B1','travel',3,'expedition jungle nature adventure team'),
('w_travel_B1_30','heritage','/ˈherɪtɪdʒ/','noun','문화유산','Cultural or historical traditions passed down through generations.','The old town is listed as a World {Heritage} Site.','구시가지는 세계 문화유산으로 등재되어 있어요.','heritage','B1','travel',2,'heritage site UNESCO history culture'),
('w_travel_B1_31','fare','/fer/','noun','요금','The price you pay to travel by bus, train, or other transport.','The bus {fare} into the city is only two euros.','시내까지 버스 요금은 2유로밖에 안 해요.','fare','B1','travel',1,'fare bus ticket transport price'),
('w_travel_B1_32','stopover','/ˈstɒpoʊvər/','noun','경유 체류','A short stay in a place you are passing through on a longer journey.','We had a two-day {stopover} in Dubai on our way to London.','런던 가는 길에 두바이에서 이틀간 경유했어요.','stopover','B1','travel',2,'stopover dubai airport city hotel'),
('w_travel_B1_33','complain','/kəmˈpleɪn/','verb','불평하다','To say that you are unhappy about something.','He {complained} to the hotel manager about the noisy room.','시끄러운 방에 대해 호텔 매니저에게 불평했어요.','complained','B1','travel',2,'complaint hotel manager service problem'),
('w_travel_B1_34','phrase','/freɪz/','noun','표현, 어구','A small group of words that express an idea.','Learning a few useful {phrase}s can help a lot when travelling.','몇 가지 유용한 표현을 배우면 여행할 때 많이 도움이 돼요.','phrases','B1','travel',2,'phrase language learning travel communication'),
('w_travel_B1_35','scenic','/ˈsiːnɪk/','adjective','경치 좋은','Having beautiful natural scenery.','We took the {scenic} route along the coast.','해안을 따라 경치 좋은 길로 갔어요.','scenic','B1','travel',2,'scenic route coast landscape nature')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_B2_01','nomadic','/noʊˈmædɪk/','adjective','유목적인, 떠돌이의','Moving from place to place rather than settling in one spot.','She lives a {nomadic} lifestyle, working remotely from different countries.','그녀는 여러 나라에서 원격 근무를 하며 유목적인 생활을 해요.','nomadic','B2','travel',2,'nomadic lifestyle remote work travel world'),
('w_travel_B2_02','wanderlust','/ˈwɒndərlʌst/','noun','여행 욕구, 방랑벽','A strong desire to travel and explore the world.','Her {wanderlust} led her to quit her job and travel for a year.','여행 욕구가 그녀를 일을 그만두고 1년간 여행하게 만들었어요.','wanderlust','B2','travel',1,'wanderlust travel adventure world explore'),
('w_travel_B2_03','expedition','/ˌekspɪˈdɪʃən/','noun','탐험대, 원정','An organised journey with a specific scientific or exploratory purpose.','The {expedition} team reached the summit after ten days.','탐험대는 10일 만에 정상에 도달했어요.','expedition','B2','travel',2,'expedition mountain summit team adventure'),
('w_travel_B2_04','traverse','/trəˈvɜːrs/','verb','횡단하다','To travel across or through a large area.','They {traversed} the entire length of the country by bicycle.','그들은 자전거로 나라 전체를 횡단했어요.','traversed','B2','travel',3,'traverse bicycle country landscape road'),
('w_travel_B2_05','pilgrimage','/ˈpɪlɡrɪmɪdʒ/','noun','성지 순례, 순례 여행','A journey made for a religious or deeply personal reason.','Thousands make the {pilgrimage} to Santiago de Compostela each year.','매년 수천 명이 산티아고 데 콤포스텔라 성지 순례를 해요.','pilgrimage','B2','travel',2,'pilgrimage camino santiago walk spiritual'),
('w_travel_B2_06','heritage','/ˈherɪtɪdʒ/','noun','유산','The history and traditions of a place or culture.','Visiting these sites gave me a deep appreciation of {heritage}.','이곳을 방문하면서 유산의 가치를 깊이 느꼈어요.','heritage','B2','travel',2,'heritage culture history architecture old'),
('w_travel_B2_07','immersive','/ɪˈmɜːrsɪv/','adjective','몰입적인','Providing a very deep and engaging experience.','The {immersive} cultural tour made us feel like locals.','몰입적인 문화 투어 덕분에 현지인처럼 느껴졌어요.','immersive','B2','travel',2,'immersive experience culture local travel'),
('w_travel_B2_08','spontaneous','/spɒnˈteɪniəs/','adjective','즉흥적인','Done without planning, naturally and freely.','A {spontaneous} trip to a nearby city is sometimes the best.','가까운 도시로의 즉흥 여행이 가끔은 최고예요.','spontaneous','B2','travel',2,'spontaneous trip city adventure impulsive'),
('w_travel_B2_09','off-grid','/ˌɒf ˈɡrɪd/','adjective','자연 속 격리된','Not connected to public utilities or mainstream society.','We spent a week in an {off-grid} cabin in the mountains.','산속 격리된 오두막에서 일주일을 보냈어요.','off-grid','B2','travel',3,'off-grid cabin mountain nature isolated'),
('w_travel_B2_10','authentic','/ɔːˈθentɪk/','adjective','진정성 있는','Real or genuine, not a copy or imitation.','I always look for {authentic} local experiences when I travel.','여행할 때 항상 진정성 있는 현지 경험을 찾아요.','authentic','B2','travel',1,'authentic local market food culture'),
('w_travel_B2_11','itinerant','/ɪˈtɪnərənt/','adjective','떠돌이의','Travelling from place to place for work or another purpose.','An {itinerant} musician played folk songs in the village square.','떠돌이 음악가가 마을 광장에서 민요를 연주했어요.','itinerant','B2','travel',3,'itinerant musician village square folk'),
('w_travel_B2_12','remote','/rɪˈmoʊt/','adjective','외딴, 외진','Far away from towns and other people.','The village is so {remote} that it can only be reached by boat.','그 마을은 너무 외져서 배로만 갈 수 있어요.','remote','B2','travel',2,'remote village island boat nature'),
('w_travel_B2_13','sustainable','/səˈsteɪnəbəl/','adjective','지속 가능한','Causing little or no damage to the environment.','We chose a {sustainable} travel agency that offsets carbon emissions.','탄소 배출량을 상쇄하는 지속 가능한 여행사를 선택했어요.','sustainable','B2','travel',2,'sustainable eco travel green environment'),
('w_travel_B2_14','itinerary','/aɪˈtɪnərəri/','noun','세부 여행 계획','A detailed list of places to visit and things to do.','She crafted a meticulous {itinerary} covering fifteen destinations.','15개 여행지를 포함한 꼼꼼한 여행 계획을 세웠어요.','itinerary','B2','travel',1,'itinerary destinations plan schedule map'),
('w_travel_B2_15','passport control','/ˈpæspɔːrt kənˌtroʊl/','noun','출입국 심사','The point in an airport where your passport is checked.','The queue at {passport control} took over an hour.','출입국 심사 줄이 한 시간 넘게 걸렸어요.','passport control','B2','travel',2,'passport control airport queue immigration'),
('w_travel_B2_16','overland','/ˈoʊvərlænd/','adjective','육로로','Travelling by land rather than by air or sea.','We did an {overland} journey from London to Istanbul.','런던에서 이스탄불까지 육로로 여행했어요.','overland','B2','travel',3,'overland journey train bus route map'),
('w_travel_B2_17','backpacker','/ˈbækpækər/','noun','배낭여행자','A person who travels cheaply, often staying in hostels.','As a {backpacker}, she spent three months in Southeast Asia.','배낭여행자로서 동남아시아에서 3개월을 보냈어요.','backpacker','B2','travel',2,'backpacker hostel southeast asia budget'),
('w_travel_B2_18','cultural immersion','/ˈkʌltʃərəl ɪˈmɜːrʒən/','noun','문화 몰입','The act of deeply engaging with a foreign culture.','{cultural immersion} trips are far more meaningful than typical tours.','문화 몰입 여행은 일반 투어보다 훨씬 의미 있어요.','cultural immersion','B2','travel',2,'cultural immersion language local community'),
('w_travel_B2_19','desolate','/ˈdesələt/','adjective','황량한, 인적이 드문','Empty of people; bleak and bare.','The {desolate} landscape of Iceland was breathtaking.','아이슬란드의 황량한 풍경은 숨이 멎을 정도였어요.','desolate','B2','travel',3,'desolate landscape iceland nature bleak'),
('w_travel_B2_20','altitude','/ˈæltɪtjuːd/','noun','고도','The height of a place above sea level.','The high {altitude} made breathing difficult.','높은 고도 때문에 숨쉬기가 힘들었어요.','altitude','B2','travel',2,'altitude mountain high elevation breathe'),
('w_travel_B2_21','trekking','/ˈtrekɪŋ/','noun','트레킹','The activity of walking long distances, usually in the mountains.','We went {trekking} in the Himalayas for two weeks.','히말라야에서 2주간 트레킹을 했어요.','trekking','B2','travel',2,'trekking himalaya mountain hiking trail'),
('w_travel_B2_22','shore excursion','/ʃɔːr ɪkˈskɜːrʒən/','noun','기항지 관광','A trip taken by cruise passengers when the ship is in port.','The {shore excursion} to the Roman ruins was unforgettable.','로마 유적지 기항지 관광은 잊을 수 없었어요.','shore excursion','B2','travel',3,'shore excursion cruise port ruins'),
('w_travel_B2_23','self-guided','/ˈself ˌɡaɪdɪd/','adjective','자유 여행의','Done without an official guide or organised group.','A {self-guided} walking tour lets you set your own pace.','자유 도보 여행은 자신만의 속도로 즐길 수 있어요.','self-guided','B2','travel',2,'self-guided walking tour city map freedom'),
('w_travel_B2_24','scenic route','/ˈsiːnɪk ruːt/','noun','경치 좋은 길','A road or path chosen for its beautiful views rather than speed.','We took the {scenic route} through the Alps to enjoy the views.','경치를 즐기기 위해 알프스를 통과하는 경치 좋은 길로 갔어요.','scenic route','B2','travel',2,'scenic route alps mountain drive view'),
('w_travel_B2_25','off the beaten track','/ˌɒf ðə ˌbiːtən ˈtræk/','phrase','잘 알려지지 않은 곳','In a place that is not often visited or well-known.','She prefers destinations {off the beaten track} to crowded hotspots.','그녀는 붐비는 명소보다 잘 알려지지 않은 곳을 선호해요.','off the beaten track','B2','travel',2,'off beaten track hidden village local discovery'),
('w_travel_B2_26','cosmopolitan','/ˌkɒzməˈpɒlɪtən/','adjective','국제적인','Familiar with and at ease in many different countries and cultures.','New York is one of the world''s most {cosmopolitan} cities.','뉴욕은 세계에서 가장 국제적인 도시 중 하나예요.','cosmopolitan','B2','travel',2,'cosmopolitan city new york diverse culture'),
('w_travel_B2_27','orient','/ˈɔːrient/','verb','방향을 잡다','To find out where you are and adjust to new surroundings.','It took me a day to {orient} myself in the unfamiliar city.','낯선 도시에서 방향을 잡는 데 하루가 걸렸어요.','orient','B2','travel',2,'orient map city direction unfamiliar'),
('w_travel_B2_28','voucher','/ˈvaʊtʃər/','noun','바우처, 이용권','A piece of paper that can be exchanged for goods or services.','Present this {voucher} at the hotel reception on arrival.','도착 시 호텔 프런트에서 이 바우처를 제시하세요.','voucher','B2','travel',2,'voucher hotel booking travel coupon'),
('w_travel_B2_29','embody','/ɪmˈbɒdi/','verb','구현하다','To be an expression or representation of something.','This ancient temple {embodies} centuries of tradition.','이 고대 사원은 수백 년의 전통을 구현해요.','embodies','B2','travel',3,'embody temple tradition culture history'),
('w_travel_B2_30','itinerary planning','/aɪˈtɪnərəri ˈplænɪŋ/','noun','일정 계획','The process of organising the schedule for a trip.','Good {itinerary planning} saves time and money.','좋은 일정 계획은 시간과 돈을 절약해 줘요.','itinerary planning','B2','travel',1,'itinerary planning travel schedule map'),
('w_travel_B2_31','culture shock','/ˈkʌltʃər ʃɒk/','noun','문화 충격','The feeling of disorientation when experiencing an unfamiliar culture.','{Culture shock} can hit you hard in the first week abroad.','해외 첫 주에 문화 충격이 심하게 올 수 있어요.','culture shock','B2','travel',2,'culture shock abroad different country'),
('w_travel_B2_32','time zone','/ˈtaɪm zoʊn/','noun','시간대','One of the regions of the globe that has a standard time.','Flying across many {time zone}s causes jet lag.','여러 시간대를 넘는 비행은 시차 피로를 유발해요.','time zones','B2','travel',2,'time zone clock world map travel'),
('w_travel_B2_33','round-the-world','/ˌraʊnd ðə ˈwɜːrld/','adjective','세계 일주의','Describing a journey that goes all the way around the globe.','She bought a {round-the-world} ticket and visited twelve countries.','세계 일주 티켓을 사서 12개국을 방문했어요.','round-the-world','B2','travel',3,'round the world ticket flight globe'),
('w_travel_B2_34','expedition planner','/ˌekspɪˈdɪʃən ˈplænər/','noun','탐험 기획자','A person or tool that organises a complex journey.','We hired an {expedition planner} for our Antarctic trip.','남극 여행을 위해 탐험 기획자를 고용했어요.','expedition planner','B2','travel',3,'expedition planner antarctica adventure plan'),
('w_travel_B2_35','uncharted','/ʌnˈtʃɑːrtɪd/','adjective','미지의, 지도에 없는','Not yet explored or mapped.','They ventured into {uncharted} territory deep in the rainforest.','그들은 열대우림 깊숙이 미지의 영역으로 모험을 떠났어요.','uncharted','B2','travel',3,'uncharted forest jungle explore adventure')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_C1_01','odyssey','/ˈɒdɪsi/','noun','대장정, 모험적 여행','A long and eventful journey full of adventures.','Her year-long {odyssey} through Central Asia changed her life forever.','중앙아시아를 1년간 여행한 대장정이 그녀의 인생을 바꿨어요.','odyssey','C1','travel',2,'odyssey journey adventure road landscape'),
('w_travel_C1_02','itinerant','/ɪˈtɪnərənt/','adjective','유랑하는','Travelling from place to place, especially for work.','He led the life of an {itinerant} scholar, lecturing across Europe.','그는 유럽 전역에서 강의하며 유랑하는 학자의 삶을 살았어요.','itinerant','C1','travel',3,'itinerant scholar europe lecture travel'),
('w_travel_C1_03','sojourn','/ˈsoʊdʒɜːrn/','noun','체류, 임시 거주','A temporary stay in a place.','Her three-month {sojourn} in Florence deepened her love of art.','피렌체에서의 3개월 체류가 그녀의 예술 사랑을 깊게 했어요.','sojourn','C1','travel',2,'sojourn florence italy art stay'),
('w_travel_C1_04','vagabond','/ˈvæɡəbɒnd/','noun','방랑자','A person who wanders from place to place without a fixed home.','He described himself as a happy {vagabond} with no permanent address.','그는 자신을 영구 주소가 없는 행복한 방랑자라고 표현했어요.','vagabond','C1','travel',3,'vagabond traveller backpack road freedom'),
('w_travel_C1_05','peripatetic','/ˌperɪpəˈtetɪk/','adjective','자주 이동하는, 순회하는','Going from place to place, especially while working.','Her {peripatetic} career as a consultant took her to forty countries.','컨설턴트로서의 순회 경력이 그녀를 40개국으로 데려갔어요.','peripatetic','C1','travel',3,'peripatetic consultant travel work global'),
('w_travel_C1_06','traverse','/trəˈvɜːrs/','verb','가로지르다, 횡단하다','To travel across or through a large area with purpose.','The expedition {traversed} the Antarctic plateau in brutal conditions.','탐험대는 혹독한 환경에서 남극 고원을 횡단했어요.','traversed','C1','travel',3,'traverse antarctica ice expedition extreme'),
('w_travel_C1_07','wayfarer','/ˈweɪferər/','noun','나그네, 여행자','A person who travels on foot, especially along roads.','The old inn once offered shelter to {wayfarer}s crossing the moors.','그 오래된 여관은 한때 황야를 건너는 나그네들에게 피신처를 제공했어요.','wayfarers','C1','travel',3,'wayfarer inn road moors walking traveller'),
('w_travel_C1_08','exile','/ˈeksaɪl/','noun','망명, 유배','The state of being forced to live away from one''s home country.','He wrote his greatest works during his years in {exile}.','그는 망명 시절에 가장 위대한 작품들을 썼어요.','exile','C1','travel',3,'exile country expat writing abroad'),
('w_travel_C1_09','diaspora','/daɪˈæspərə/','noun','디아스포라, 이산민','The spread of people from their original homeland to other countries.','The Irish {diaspora} is found in every corner of the world.','아일랜드 디아스포라는 세계 곳곳에 있어요.','diaspora','C1','travel',3,'diaspora community culture heritage global'),
('w_travel_C1_10','pilgrimage','/ˈpɪlɡrɪmɪdʒ/','noun','성지 순례','A journey to a place of great personal or religious significance.','He made a {pilgrimage} to his grandfather''s birthplace in County Cork.','그는 코크 카운티에 있는 할아버지의 고향으로 성지 순례를 떠났어요.','pilgrimage','C1','travel',2,'pilgrimage ireland village ancestry heritage'),
('w_travel_C1_11','perambulate','/pəˈræmbjuleɪt/','verb','거닐다, 산책하다','To walk or travel through or around a place for pleasure.','She liked to {perambulate} the old quarter at dusk.','그녀는 해질 무렵 구시가지를 거니는 것을 좋아했어요.','perambulate','C1','travel',4,'perambulate old quarter evening stroll'),
('w_travel_C1_12','circumnavigate','/ˌsɜːrkəmˈnævɪɡeɪt/','verb','세계를 일주하다','To sail or travel completely around something, especially the earth.','She became the youngest person to {circumnavigate} the globe solo.','그녀는 혼자서 지구를 일주한 최연소 인물이 됐어요.','circumnavigate','C1','travel',2,'circumnavigate globe solo sailing world'),
('w_travel_C1_13','wanderer','/ˈwɒndərər/','noun','방랑자, 유랑자','A person who moves from place to place without a fixed home.','The novel follows a young {wanderer} across three continents.','그 소설은 세 대륙을 떠도는 젊은 방랑자를 따라가요.','wanderer','C1','travel',3,'wanderer journey continent novel road'),
('w_travel_C1_14','expatriate','/ˌekspəˈtrɪeɪt/','noun','해외 거주자','A person who lives outside their native country.','The city has a thriving {expatriate} community from all over Asia.','그 도시에는 아시아 전역에서 온 활발한 해외 거주자 커뮤니티가 있어요.','expatriate','C1','travel',2,'expatriate community asia city culture'),
('w_travel_C1_15','nomadism','/ˈnoʊmədɪzəm/','noun','유목주의, 유랑 생활','The practice of moving from place to place as a way of life.','Digital {nomadism} has become mainstream with remote work.','디지털 유목주의는 원격 근무로 주류가 됐어요.','nomadism','C1','travel',2,'nomadism digital remote work travel laptop'),
('w_travel_C1_16','meander','/miˈændər/','verb','어슬렁거리다, 구불구불 가다','To walk slowly and without a particular direction.','We spent the afternoon {meander}ing through the old town.','오후를 구시가지를 어슬렁거리며 보냈어요.','meandering','C1','travel',3,'meandering old town street afternoon walk'),
('w_travel_C1_17','sojourn','/ˈsoʊdʒɜːrn/','verb','잠시 머물다','To make a temporary stay.','He {sojourn}ed in Berlin for several months studying architecture.','그는 건축을 공부하며 베를린에 몇 달간 잠시 머물었어요.','sojourned','C1','travel',3,'sojourn berlin architecture study city'),
('w_travel_C1_18','alight','/əˈlaɪt/','verb','내리다 (교통수단에서)','To get off a bus, train, or other vehicle.','Please {alight} here for the National Museum.','국립 박물관에 가시려면 여기서 내리세요.','alight','C1','travel',3,'alight bus train station stop'),
('w_travel_C1_19','embarkation','/ˌembɑːrˈkeɪʃən/','noun','탑승, 승선','The act of getting on a ship or aircraft.','{Embarkation} will take place at berth seven.','탑승은 7번 선석에서 이루어질 예정이에요.','embarkation','C1','travel',3,'embarkation ship cruise berth port'),
('w_travel_C1_20','itinerant vendor','/ɪˈtɪnərənt ˈvendər/','noun','행상','A trader who moves from place to place selling goods.','An {itinerant vendor} sold handmade crafts at every market.','행상이 모든 시장에서 수제 공예품을 팔았어요.','itinerant vendor','C1','travel',4,'itinerant vendor market craft handmade'),
('w_travel_C1_21','cosmopolite','/kɒzˈmɒpəlaɪt/','noun','세계시민','A person who feels at home in any country.','As a true {cosmopolite}, she felt comfortable living anywhere in the world.','진정한 세계시민으로서 그녀는 세계 어디에서도 편안함을 느꼈어요.','cosmopolite','C1','travel',3,'cosmopolite world citizen global travel culture'),
('w_travel_C1_22','transient','/ˈtrænziənt/','adjective','일시적인, 잠시 머무는','Staying or existing for only a short time.','The hostel catered mainly to a {transient} population of backpackers.','그 호스텔은 주로 잠시 머무는 배낭여행자들을 위한 곳이었어요.','transient','C1','travel',3,'transient hostel backpacker short stay'),
('w_travel_C1_23','heritage trail','/ˈherɪtɪdʒ treɪl/','noun','문화유산 탐방로','A marked route that passes through historically significant sites.','The {heritage trail} winds through six medieval villages.','그 문화유산 탐방로는 여섯 개의 중세 마을을 통해 구불구불 이어져요.','heritage trail','C1','travel',2,'heritage trail medieval village history path'),
('w_travel_C1_24','itinerary fatigue','/aɪˈtɪnərəri fəˈtiːɡ/','noun','과도한 일정으로 인한 피로','Exhaustion caused by a packed travel schedule.','{Itinerary fatigue} made us skip the last museum.','과도한 일정 피로 때문에 마지막 박물관을 건너뛰었어요.','itinerary fatigue','C1','travel',3,'itinerary fatigue tired overplanned travel'),
('w_travel_C1_25','xenophile','/ˈzenəfaɪl/','noun','외국 문화 애호가','A person who is attracted to foreign peoples and cultures.','A true {xenophile}, he collected art from every country he visited.','진정한 외국 문화 애호가로서 그는 방문한 모든 나라의 예술품을 수집했어요.','xenophile','C1','travel',3,'xenophile art culture collection foreign travel'),
('w_travel_C1_26','disoriented','/dɪsˈɔːrientɪd/','adjective','방향 감각을 잃은','Confused about where you are or what is happening.','I felt completely {disoriented} after landing in a new time zone.','새로운 시간대에 도착한 후 완전히 방향 감각을 잃었어요.','disoriented','C1','travel',2,'disoriented airport arrival jet lag lost'),
('w_travel_C1_27','quest','/kwest/','noun','탐구 여행','A long and difficult search for something.','The journey became a personal {quest} for identity and belonging.','그 여행은 정체성과 소속감을 위한 개인적인 탐구 여행이 됐어요.','quest','C1','travel',2,'quest journey identity personal search'),
('w_travel_C1_28','pathfinder','/ˈpɑːθfaɪndər/','noun','선구자, 길을 개척하는 사람','A person who goes ahead to find a route or discover new paths.','Early explorers were the original {pathfinder}s of unknown continents.','초기 탐험가들은 미지의 대륙을 개척한 원조 선구자들이었어요.','pathfinders','C1','travel',3,'pathfinder explorer continent discovery map'),
('w_travel_C1_29','wander','/ˈwɒndər/','verb','배회하다, 헤매다','To walk slowly without any clear direction or purpose.','She loved to {wander} through unfamiliar cities with no map.','그녀는 지도 없이 낯선 도시를 배회하는 것을 좋아했어요.','wander','C1','travel',2,'wander city street explore no map'),
('w_travel_C1_30','souvenir hunting','/ˈsuːvənɪr ˈhʌntɪŋ/','noun','기념품 쇼핑','The activity of searching for things to buy as mementos of a trip.','{Souvenir hunting} in the night market took most of the evening.','야시장에서의 기념품 쇼핑이 저녁 대부분을 차지했어요.','souvenir hunting','C1','travel',3,'souvenir hunting market night shopping'),
('w_travel_C1_31','frontier','/frʌnˈtɪər/','noun','변방, 국경 지역','A border or boundary between countries; also unexplored territory.','Crossing the mountain {frontier} felt like entering another world.','산악 국경을 넘는 것은 다른 세계에 들어가는 것 같았어요.','frontier','C1','travel',3,'frontier border mountain crossing region'),
('w_travel_C1_32','traverse','/ˈtrævɜːrs/','noun','횡단, 가로지름','The act of crossing or passing through a place.','The {traverse} of the glacier took eight gruelling hours.','빙하 횡단은 8시간이 걸리는 힘든 경험이었어요.','traverse','C1','travel',3,'traverse glacier ice mountain expedition'),
('w_travel_C1_33','immerse','/ɪˈmɜːrs/','verb','몰입하다','To involve yourself deeply in an activity or culture.','She chose to {immerse} herself in the local community rather than tour.','그녀는 관광보다 현지 커뮤니티에 몰입하는 것을 선택했어요.','immerse','C1','travel',2,'immerse local community culture language'),
('w_travel_C1_34','foray','/ˈfɔːreɪ/','noun','짧은 탐험, 시도','A short trip or attempt into unfamiliar territory.','Our {foray} into the remote highlands was unexpectedly rewarding.','외딴 고지대로의 짧은 탐험은 예상치 못하게 보람 있었어요.','foray','C1','travel',3,'foray highlands remote nature rewarding'),
('w_travel_C1_35','cartography','/kɑːrˈtɒɡrəfi/','noun','지도 제작학','The science and art of making maps.','His passion for {cartography} was born during a sailing voyage.','항해 여행 중에 지도 제작학에 대한 열정이 생겼어요.','cartography','C1','travel',3,'cartography map art sailing voyage history')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_travel_C2_01','peregrination','/ˌperɪɡrɪˈneɪʃən/','noun','긴 방랑 여행','A long journey through various places.','His {peregrination} across four continents spanned two decades.','그의 4대륙에 걸친 방랑 여행은 20년에 걸쳐 있었어요.','peregrination','C2','travel',3,'peregrination journey continent decades world'),
('w_travel_C2_02','circumnavigate','/ˌsɜːrkəmˈnævɪɡeɪt/','verb','세계를 일주하다','To travel all the way around something, especially the globe.','It took him 80 days to {circumnavigate} the earth by aeroplane.','비행기로 지구를 일주하는 데 80일이 걸렸어요.','circumnavigate','C2','travel',2,'circumnavigate earth aeroplane globe journey'),
('w_travel_C2_03','cosmopolitan','/ˌkɒzməˈpɒlɪtən/','adjective','세계주의적인, 국제적인','Having an international character, familiar with many cultures.','Singapore''s {cosmopolitan} culture reflects centuries of trade.','싱가포르의 국제적인 문화는 수백 년의 무역을 반영해요.','cosmopolitan','C2','travel',2,'cosmopolitan singapore culture trade city'),
('w_travel_C2_04','expatriate','/ˌekspəˈtrɪeɪt/','verb','국외로 추방하다, 이주시키다','To send someone to live in another country; to move abroad voluntarily.','After retiring, they chose to {expatriate} to southern Portugal.','은퇴 후 그들은 포르투갈 남부로 이주하기로 했어요.','expatriate','C2','travel',3,'expatriate portugal retire move abroad'),
('w_travel_C2_05','transhumance','/trænsˈhjuːməns/','noun','계절적 이동 방목','The seasonal movement of livestock to different regions.','The ancient practice of {transhumance} still occurs in the Alps each spring.','고대의 계절적 이동 방목 관행이 매년 봄 알프스에서 여전히 이루어져요.','transhumance','C2','travel',4,'transhumance alps livestock seasonal herding'),
('w_travel_C2_06','nomadism','/ˈnoʊmədɪzəm/','noun','유목 생활 방식','A way of life characterized by moving from place to place.','Academic interest in {nomadism} has grown with the rise of remote work.','원격 근무의 부상으로 유목 생활 방식에 대한 학문적 관심이 높아졌어요.','nomadism','C2','travel',3,'nomadism remote work digital academic study'),
('w_travel_C2_07','xenophilia','/ˌzenəˈfɪliə/','noun','외국 문화 사랑','An attraction to or fondness for foreign cultures and peoples.','Her {xenophilia} was evident in her multilingual home library.','그녀의 외국 문화 사랑은 다국어로 가득한 집 서재에서 분명하게 드러났어요.','xenophilia','C2','travel',4,'xenophilia multilingual books library culture'),
('w_travel_C2_08','wanderer','/ˈwɒndərər/','noun','영원한 방랑자','One who moves continually without a permanent base.','He defined himself as an eternal {wanderer}, belonging everywhere and nowhere.','그는 자신을 어디에나 속하고 어디에도 속하지 않는 영원한 방랑자로 규정했어요.','wanderer','C2','travel',3,'wanderer eternal journey world belonging'),
('w_travel_C2_09','odyssey','/ˈɒdɪsi/','noun','인생의 대여정','A long and transformative journey or experience.','The documentary chronicles the {odyssey} of displaced communities seeking home.','그 다큐멘터리는 집을 찾는 이주 커뮤니티의 대여정을 기록해요.','odyssey','C2','travel',2,'odyssey displaced community documentary journey'),
('w_travel_C2_10','cartography','/kɑːrˈtɒɡrəfi/','noun','지도학','The discipline of making and studying maps.','Advances in digital {cartography} have transformed how we navigate.','디지털 지도학의 발전은 우리의 항법 방식을 변화시켰어요.','cartography','C2','travel',3,'cartography digital map navigation technology'),
('w_travel_C2_11','terroir','/terˈwɑːr/','noun','테루아 (지역 특성)','The set of environmental factors, especially soil and climate, that give a place its unique character.','Travel enthusiasts speak of the {terroir} of a destination as locals do of wine.','여행 애호가들은 현지인들이 와인에 대해 말하듯 여행지의 테루아에 대해 이야기해요.','terroir','C2','travel',4,'terroir wine region landscape environment'),
('w_travel_C2_12','polyglot','/ˈpɒliɡlɒt/','noun','다국어 구사자','A person who knows and uses several languages.','As a seasoned {polyglot}, she could navigate daily life in eight countries.','숙련된 다국어 구사자로서 그녀는 8개국에서 일상생활을 영위할 수 있었어요.','polyglot','C2','travel',2,'polyglot language speaker traveller culture'),
('w_travel_C2_13','liminality','/ˌlɪmɪˈnælɪti/','noun','경계 상태','The transitional state between one condition and another.','Airports exist in a state of {liminality} between home and destination.','공항은 집과 목적지 사이의 경계 상태에 존재해요.','liminality','C2','travel',4,'liminality airport transit state between'),
('w_travel_C2_14','deterritorialise','/diːˌterɪˈtɔːrɪəlaɪz/','verb','영토성을 해체하다','To remove or undermine the attachment of a people to a specific territory.','Globalisation tends to {deterritorialise} cultural identity.','세계화는 문화적 정체성의 영토성을 해체하는 경향이 있어요.','deterritorialise','C2','travel',5,'deterritorialise globalisation culture identity'),
('w_travel_C2_15','wayfinding','/ˈweɪfaɪndɪŋ/','noun','길 찾기 (체계적)','The process of using spatial and environmental information to navigate.','Indigenous {wayfinding} techniques guided explorers before GPS.','GPS 이전에는 토착민의 길 찾기 기술이 탐험가들을 안내했어요.','wayfinding','C2','travel',3,'wayfinding indigenous navigation landscape gps'),
('w_travel_C2_16','peripatetic','/ˌperɪpəˈtetɪk/','noun','순회자','A person who travels or works in many places.','The documentary profiled {peripatetic}s who work in conflict zones.','그 다큐멘터리는 분쟁 지역에서 일하는 순회자들을 소개했어요.','peripatetics','C2','travel',3,'peripatetic conflict zone work travel'),
('w_travel_C2_17','rhizome','/ˈraɪzoʊm/','noun','리좀 (비선형적 연결)','A concept used to describe non-hierarchical, interconnected networks.','The traveller''s identity became a {rhizome} — spreading across cultures.','여행자의 정체성은 리좀처럼 문화 전체로 퍼져 나갔어요.','rhizome','C2','travel',5,'rhizome network identity culture theory'),
('w_travel_C2_18','place attachment','/pleɪs əˈtætʃmənt/','noun','장소 애착','The emotional bond a person develops with a specific location.','{Place attachment} can make leaving a long-term travel destination painful.','장소 애착은 장기 여행지를 떠나는 것을 고통스럽게 만들 수 있어요.','place attachment','C2','travel',3,'place attachment emotion bond leave destination'),
('w_travel_C2_19','ethnography','/eθˈnɒɡrəfi/','noun','민족지학','The scientific description of a culture and its customs.','Her {ethnography} of nomadic communities challenged Western assumptions.','유목 커뮤니티에 대한 그녀의 민족지학은 서구적 가정에 도전했어요.','ethnography','C2','travel',4,'ethnography nomadic community research culture'),
('w_travel_C2_20','topophilia','/ˌtɒpəˈfɪliə/','noun','장소 사랑','A strong sense of place and love of a particular environment.','The novelist''s {topophilia} for the Scottish Highlands permeates every page.','소설가의 스코틀랜드 고지대에 대한 장소 사랑이 모든 페이지에 스며들어요.','topophilia','C2','travel',4,'topophilia scotland highlands love place nature'),
('w_travel_C2_21','sublunary','/sʌbˈluːnəri/','adjective','지상의, 세속적인','Belonging to this world as opposed to a spiritual realm.','The traveller sought meaning beyond the merely {sublunary} pleasures of tourism.','여행자는 단순히 지상적인 관광 즐거움을 넘어선 의미를 찾았어요.','sublunary','C2','travel',5,'sublunary world spiritual meaning travel'),
('w_travel_C2_22','polyphonic','/ˌpɒliˈfɒnɪk/','adjective','다성적인, 다양한 목소리의','Involving many different voices or cultural perspectives.','The festival offered a {polyphonic} celebration of global travel traditions.','그 축제는 세계 여행 전통을 다성적으로 기리는 자리였어요.','polyphonic','C2','travel',5,'polyphonic festival culture global voices'),
('w_travel_C2_23','autochthonous','/ɔːˈtɒkθənəs/','adjective','토착적인, 원주민의','Indigenous to a place; formed or originating where found.','The festival celebrated {autochthonous} customs that predate colonisation.','그 축제는 식민지화 이전부터 전해온 토착 관습을 기념했어요.','autochthonous','C2','travel',4,'autochthonous indigenous customs festival precolonial'),
('w_travel_C2_24','exilic','/ˈeksɪlɪk/','adjective','망명과 관련된','Relating to or characteristic of exile.','Her {exilic} writing captured the pain of displacement beautifully.','그녀의 망명 관련 글쓰기는 이주의 고통을 아름답게 담아냈어요.','exilic','C2','travel',4,'exilic writing displacement pain culture'),
('w_travel_C2_25','heterotopia','/ˌhetərəˈtoʊpiə/','noun','헤테로토피아 (다른 공간)','A space that exists outside normal social order, like a ship or hotel.','Foucault described the cruise ship as a {heterotopia} floating between worlds.','푸코는 유람선을 세계 사이를 떠도는 헤테로토피아로 묘사했어요.','heterotopia','C2','travel',5,'heterotopia cruise ship foucault space world'),
('w_travel_C2_26','psychogeography','/ˌsaɪkoʊdʒiˈɒɡrəfi/','noun','심리지리학','The study of how environments affect human behaviour and emotions.','{Psychogeography} was central to the Situationist movement''s urban drifting.','심리지리학은 시튜에이셔니스트 운동의 도시 표류의 핵심이었어요.','psychogeography','C2','travel',5,'psychogeography urban drift city emotion'),
('w_travel_C2_27','flaneur','/flɑːˈnɜːr/','noun','플라뇌르 (도시 산책자)','A person who strolls idly through cities, observing urban life.','He embraced the role of the {flaneur}, wandering Paris without a plan.','그는 계획 없이 파리를 거닐며 플라뇌르의 역할을 받아들였어요.','flaneur','C2','travel',4,'flaneur paris stroll urban observer city'),
('w_travel_C2_28','xenophobia','/ˌzenəˈfoʊbiə/','noun','외국인 혐오','Dislike or prejudice against people from other countries.','Responsible travel can help reduce {xenophobia} through genuine cultural exchange.','책임 있는 여행은 진정한 문화 교류를 통해 외국인 혐오를 줄이는 데 도움이 돼요.','xenophobia','C2','travel',3,'xenophobia cultural exchange travel respect'),
('w_travel_C2_29','epistemic','/ˌepɪˈstiːmɪk/','adjective','인식론적인','Relating to knowledge and its methods.','Travel creates {epistemic} humility — a recognition of how little we know.','여행은 우리가 얼마나 모르는지를 인식하는 인식론적 겸손함을 만들어요.','epistemic','C2','travel',5,'epistemic knowledge humility travel learning'),
('w_travel_C2_30','apophenia','/ˌæpəˈfiːniə/','noun','연결 패턴 인식 과잉','The tendency to perceive meaningful connections between unrelated things.','Jet-lagged travellers often report moments of {apophenia} in unfamiliar cities.','시차 피로를 겪는 여행자들은 낯선 도시에서 연결 패턴 인식 과잉 순간을 경험해요.','apophenia','C2','travel',5,'apophenia traveller jet lag city pattern'),
('w_travel_C2_31','sonder','/ˈsɒndər/','noun','타인의 삶에 대한 인식','The realisation that each passerby has a life as vivid as one''s own.','Travel intensifies the feeling of {sonder} — everyone has a story.','여행은 타인의 삶에 대한 인식을 강화해요. 모든 사람에게는 이야기가 있어요.','sonder','C2','travel',3,'sonder passerby life story travel people'),
('w_travel_C2_32','numinous','/ˈnjuːmɪnəs/','adjective','신성한, 경외감을 주는','Having a strong spiritual quality; evoking a sense of awe.','Standing at the ancient ruins produced a {numinous} feeling.','고대 유적 앞에 서면 경외감을 주는 느낌이 들었어요.','numinous','C2','travel',4,'numinous ruins ancient spiritual awe'),
('w_travel_C2_33','indigeneity','/ˌɪndɪˈdʒiːnɪti/','noun','토착성','The state of being indigenous or originating in a particular place.','The tourism board balanced promotion with respect for local {indigeneity}.','관광청은 홍보와 지역 토착성에 대한 존중 사이의 균형을 유지했어요.','indigeneity','C2','travel',4,'indigeneity local respect tourism balance'),
('w_travel_C2_34','cartophilia','/kɑːrˈtɒfɪliə/','noun','지도 수집 애호','The love of collecting and studying maps.','Her {cartophilia} began with a hand-drawn map found in her grandmother''s attic.','그녀의 지도 수집 애호는 할머니 다락방에서 발견한 손으로 그린 지도에서 시작됐어요.','cartophilia','C2','travel',4,'cartophilia map collection grandmother attic history'),
('w_travel_C2_35','weltanschauung','/ˈveltɑːnˌʃaʊʊŋ/','noun','세계관','A comprehensive philosophy or world view shaping how one sees life.','Prolonged travel reshaped her {weltanschauung} fundamentally.','장기간의 여행이 그녀의 세계관을 근본적으로 바꿨어요.','weltanschauung','C2','travel',5,'weltanschauung worldview philosophy travel change')
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_A1_01','Where are you going?','어디 가세요?','Where are you going','여행 목적지를 물을 때 쓰는 가장 기본적인 표현이에요.','여행 대화','A1','travel','pattern',NULL,1),
('s_travel_A1_02','How do I get to the hotel?','호텔까지 어떻게 가요?','How do I get to','"How do I get to ~?"는 특정 장소로 가는 방법을 물을 때 쓰는 기본 표현이에요.','길 묻기','A1','travel','pattern',NULL,2),
('s_travel_A1_03','Is this the right bus?','이 버스가 맞나요?','Is this the right','탑승 전에 버스나 기차를 확인할 때 쓰는 간단한 표현이에요.','교통수단 확인','A1','travel','pattern',NULL,3),
('s_travel_A1_04','Where is the airport?','공항이 어디에 있어요?','Where is the','건물이나 장소의 위치를 물을 때 "Where is ~?" 패턴을 써요.','위치 묻기','A1','travel','pattern',NULL,4),
('s_travel_A1_05','I need a map, please.','지도 한 장 주세요.','I need','"I need ~"는 무언가가 필요할 때 쓰는 가장 간단한 표현이에요.','여행 정보 센터','A1','travel','pattern',NULL,5),
('s_travel_A1_06','What time does it open?','몇 시에 열어요?','What time does it open','박물관이나 관광지의 운영 시간을 물을 때 자주 쓰는 표현이에요.','관광지 방문','A1','travel','pattern',NULL,6),
('s_travel_A1_07','How much is the ticket?','표가 얼마예요?','How much is the','가격을 물을 때 쓰는 가장 간단하고 직접적인 표현이에요.','매표소','A1','travel','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_A2_01','I have a reservation under the name Kim.','김이라는 이름으로 예약했어요.','I have a reservation under','호텔이나 레스토랑에서 예약 확인을 할 때 쓰는 필수 표현이에요.','호텔 체크인','A2','travel','pattern',NULL,1),
('s_travel_A2_02','Could I check in now, please?','지금 체크인할 수 있나요?','Could I check in','"Could I ~?"는 부탁을 정중하게 할 때 쓰는 표현이에요.','호텔 체크인','A2','travel','pattern',NULL,2),
('s_travel_A2_03','What time is check-out?','체크아웃은 몇 시예요?','What time is check-out','숙박 시설에서 반드시 알아야 할 질문이에요.','호텔 체크아웃','A2','travel','pattern',NULL,3),
('s_travel_A2_04','I''d like to book a room for two nights.','2박짜리 방을 예약하고 싶어요.','I''d like to book','"I''d like to ~"는 무언가를 하고 싶다고 정중하게 표현할 때 써요.','호텔 예약','A2','travel','pattern',NULL,4),
('s_travel_A2_05','Is breakfast included in the price?','가격에 조식이 포함되어 있나요?','Is breakfast included','예약 시 포함 사항을 확인하는 표현이에요. "included"를 기억하세요.','예약 확인','A2','travel','pattern',NULL,5),
('s_travel_A2_06','Can I see the room first?','먼저 방을 볼 수 있을까요?','Can I see the room first','예약 전에 방 상태를 확인할 때 쓸 수 있는 표현이에요.','호텔 방문','A2','travel','pattern',NULL,6),
('s_travel_A2_07','Do you have any rooms available?','빈 방이 있나요?','any rooms available','예약 없이 숙박 시설에 방문했을 때 쓰는 표현이에요.','즉흥 숙박 예약','A2','travel','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_B1_01','Could you tell me how to get to the nearest metro station?','가장 가까운 지하철역까지 어떻게 가는지 알려주실 수 있나요?','Could you tell me how to get to','"Could you tell me how to ~?"는 정중하게 길을 물을 때 쓰는 정형 표현이에요.','길 찾기','B1','travel','pattern',NULL,1),
('s_travel_B1_02','Do I need a visa to travel to this country?','이 나라에 여행하려면 비자가 필요한가요?','Do I need a visa to','비자 요건을 확인할 때 쓰는 표현이에요. "travel to"뒤에 나라 이름을 넣어요.','비자 문의','B1','travel','pattern',NULL,2),
('s_travel_B1_03','I think I''m on the wrong train — where does this go?','잘못된 기차를 탄 것 같아요. 이 기차는 어디로 가나요?','I think I''m on the wrong','실수를 인정할 때 "I think I''m on the wrong ~"을 쓰면 부드럽게 들려요.','교통 실수','B1','travel','pattern',NULL,3),
('s_travel_B1_04','Excuse me, is this seat taken?','실례합니다, 이 자리 비어 있나요?','is this seat taken','"Is this seat taken?"은 자리를 물을 때 쓰는 세련된 표현이에요. "Is this free?"도 OK예요.','기차·버스 탑승','B1','travel','pattern',NULL,4),
('s_travel_B1_05','How long does it take to get there by taxi?','택시로 거기까지 얼마나 걸려요?','How long does it take to get there','소요 시간을 물을 때 "How long does it take to ~?" 패턴을 써요.','교통 안내','B1','travel','pattern',NULL,5),
('s_travel_B1_06','My passport expires next month — will that be a problem?','여권이 다음 달에 만료되는데 문제가 될까요?','will that be a problem','입국 시 여권 유효 기간을 걱정할 때 쓸 수 있는 표현이에요.','입국 심사','B1','travel','pattern',NULL,6),
('s_travel_B1_07','Could you recommend a good local area to stay in?','머물기에 좋은 현지 지역을 추천해 주실 수 있나요?','Could you recommend a good','추천을 정중하게 부탁할 때 "Could you recommend ~?"를 써요.','숙박 지역 조언','B1','travel','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_B2_01','Travelling solo completely changed my perspective on life.','혼자 여행하는 것이 인생에 대한 제 시각을 완전히 바꿨어요.','completely changed my perspective','여행이 가져다준 변화를 표현할 때 "changed my perspective"를 써요.','여행 경험 공유','B2','travel','pattern',NULL,1),
('s_travel_B2_02','The most memorable part of the trip was getting lost in the old quarter.','여행에서 가장 기억에 남는 부분은 구시가지에서 길을 잃은 것이었어요.','The most memorable part was','여행 하이라이트를 이야기할 때 "The most memorable part was ~" 구조를 써요.','여행담 나누기','B2','travel','pattern',NULL,2),
('s_travel_B2_03','I''d highly recommend staying off the tourist trail if you want an authentic experience.','진정성 있는 경험을 원한다면 관광객 코스를 벗어나는 것을 적극 추천해요.','I''d highly recommend staying off','추천할 때 "I''d highly recommend ~ing"을 쓰면 자신감 있게 들려요.','여행 조언','B2','travel','pattern',NULL,3),
('s_travel_B2_04','What really surprised me was how welcoming the locals were despite the language barrier.','정말 놀라웠던 것은 언어 장벽에도 불구하고 현지인들이 얼마나 따뜻하게 맞아줬는지예요.','What really surprised me was','경험의 놀라운 측면을 강조할 때 "What really surprised me was ~"를 써요.','문화 경험 공유','B2','travel','pattern',NULL,4),
('s_travel_B2_05','If I could go back, I''d spend more time in the countryside and less in the city.','다시 갈 수 있다면 도시보다 시골에서 더 많은 시간을 보낼 것 같아요.','If I could go back, I''d','가상의 재방문을 이야기할 때 "If I could go back, I''d ~" 가정법을 써요.','여행 회고','B2','travel','pattern',NULL,5),
('s_travel_B2_06','The culture shock hit me harder than I expected when I first arrived.','처음 도착했을 때 예상보다 훨씬 심한 문화 충격을 받았어요.','harder than I expected','결과가 예상을 초과했을 때 "harder than I expected"처럼 비교급을 써요.','문화 충격 경험','B2','travel','pattern',NULL,6),
('s_travel_B2_07','Immersing yourself in the local language, even just a few phrases, opens so many doors.','현지어에 몰입하는 것, 심지어 몇 가지 표현만으로도 정말 많은 문이 열려요.','Immersing yourself in','경험의 가치를 강조할 때 동명사로 시작하는 "Immersing yourself in ~" 구조를 써요.','언어와 여행','B2','travel','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_C1_01','Travel, at its best, is not a form of escape but a means of deeper self-understanding.','여행은 최선의 상태에서 도피의 형태가 아니라 더 깊은 자기 이해의 수단이에요.','at its best','"at its best"는 어떤 것의 이상적인 상태를 표현할 때 쓰는 고급 표현이에요.','여행 철학 토론','C1','travel','pattern',NULL,1),
('s_travel_C1_02','There''s something profoundly humbling about navigating a world that doesn''t speak your language.','자신의 언어를 말하지 않는 세상을 헤쳐 나가는 것에는 심오하게 겸허함을 주는 무언가가 있어요.','profoundly humbling about','"There''s something ~ about ~ing"은 미묘한 감정이나 경험의 질을 표현하는 고급 구조예요.','언어와 문화','C1','travel','pattern',NULL,2),
('s_travel_C1_03','The longer I travel, the more I realise how little I truly understand about the world.','여행할수록 세상에 대해 얼마나 적게 이해하는지 더욱 깨달아요.','The longer I travel, the more','"The + 비교급, the + 비교급" 구조는 두 가지가 함께 변화함을 표현해요.','여행 성찰','C1','travel','pattern',NULL,3),
('s_travel_C1_04','I''ve come to believe that it''s the unplanned moments that define a journey, not the itinerary.','계획되지 않은 순간들이 여행 일정이 아니라 여행을 정의한다고 생각하게 됐어요.','I''ve come to believe that','"I''ve come to ~"는 서서히 형성된 믿음이나 이해를 표현하는 세련된 패턴이에요.','여행 철학','C1','travel','pattern',NULL,4),
('s_travel_C1_05','What strikes me most about long-term travel is the way it erodes your sense of home.','장기 여행에서 가장 인상 깊은 점은 집에 대한 감각을 서서히 지운다는 거예요.','What strikes me most about','"What strikes me most about ~"은 분석적 의견을 격식 있게 도입하는 표현이에요.','여행과 정체성','C1','travel','pattern',NULL,5),
('s_travel_C1_06','Having lived as an expat for a decade, I no longer think of nationality as fixed.','10년간 해외 거주자로 살면서 더 이상 국적을 고정된 것으로 생각하지 않아요.','Having lived as an expat','완료 분사구문 "Having ~"은 과거 경험을 현재 믿음의 근거로 제시하는 C1 구조예요.','정체성 토론','C1','travel','pattern',NULL,6),
('s_travel_C1_07','The most transformative journeys are those that shatter your assumptions, not confirm them.','가장 변화를 이끄는 여행은 당신의 가정을 확인하는 것이 아니라 산산이 부수는 것이에요.','those that shatter your assumptions','"those that ~"는 관계절로 종류를 구분할 때, "not ~ but ~"는 대조를 강조할 때 써요.','여행 철학 에세이','C1','travel','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_travel_C2_01','To travel is to hold a paradox: the more borders you cross, the less certain you become of your own.','여행은 역설을 품어요. 더 많은 국경을 넘을수록 자신의 국경에 대해 덜 확신하게 돼요.','to hold a paradox','"To + 동사"로 시작하는 부정사는 철학적 진술에서 주어처럼 쓰여 격식을 높여요.','여행 철학 에세이','C2','travel','pattern',NULL,1),
('s_travel_C2_02','The notion that travel broadens the mind is complicated by the reality that it can also entrench privilege.','여행이 마음을 넓힌다는 개념은 특권을 강화할 수도 있다는 현실에 의해 복잡해져요.','is complicated by the reality that','"is complicated by the reality that ~"는 단순한 주장을 비판적으로 반박할 때 쓰는 학문적 구조예요.','여행 윤리 토론','C2','travel','pattern',NULL,2),
('s_travel_C2_03','Authentic cultural exchange demands vulnerability on both sides, not merely the observer''s curiosity.','진정한 문화 교류는 단순히 관찰자의 호기심이 아니라 양측 모두의 취약성을 요구해요.','demands vulnerability on both sides','"demands ~, not merely ~"는 조건을 명확히 하며 과도 단순화를 거부하는 C2 수준 구조예요.','문화 교류 비평','C2','travel','pattern',NULL,3),
('s_travel_C2_04','What separates tourism from travel is not the distance covered but the degree of self-interrogation involved.','관광과 여행을 구분하는 것은 이동한 거리가 아니라 관련된 자기 성찰의 정도예요.','What separates ~ from ~ is not ~ but','"What separates A from B is not X but Y"는 정의와 구분을 위한 정교한 C2 구조예요.','여행 vs 관광','C2','travel','pattern',NULL,4),
('s_travel_C2_05','There is an inherent ethical tension between the desire to witness poverty tourism and respecting local dignity.','빈곤 관광을 목격하려는 욕구와 현지인의 존엄성을 존중하는 것 사이에는 내재적 윤리적 긴장이 있어요.','inherent ethical tension between','"inherent ethical tension between A and B"는 양립하는 가치 사이의 갈등을 분석하는 학문적 표현이에요.','여행 윤리','C2','travel','pattern',NULL,5),
('s_travel_C2_06','The peripatetic intellectual tradition — from Aristotle to Ibn Battuta — equates movement with enlightenment.','아리스토텔레스부터 이븐 바투타까지의 순회 지식인 전통은 이동을 계몽과 동일시해요.','equates movement with enlightenment','대시(—)로 삽입구를 쓰고, "equates A with B"로 동치를 표현하는 C2 수사학 기법이에요.','학술 토론','C2','travel','pattern',NULL,6),
('s_travel_C2_07','To sojourn is not merely to visit; it is to suspend one''s prior self and allow a place to reconstitute you.','잠시 머무는 것은 단순히 방문하는 것이 아니에요. 이전의 자아를 정지시키고 장소가 당신을 재구성하도록 허용하는 것이에요.','to suspend one''s prior self','"not merely to ~; it is to ~"는 두 부정사를 세미콜론으로 연결해 철학적 재정의를 하는 C2 구조예요.','여행 철학 에세이','C2','travel','pattern',NULL,7)
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_A1_01','eat','/iːt/','verb','먹다','To put food in your mouth and swallow it.','Let''s {eat} together.','같이 먹어요.','eat','A1','cafe',1,'eating food restaurant meal together'),
('w_cafe_A1_02','drink','/drɪŋk/','verb','마시다','To take liquid into your mouth and swallow it.','I want to {drink} some water.','물을 마시고 싶어요.','drink','A1','cafe',1,'drinking water glass cafe'),
('w_cafe_A1_03','food','/fuːd/','noun','음식','Things that people or animals eat.','This {food} is so good.','이 음식 정말 맛있어요.','food','A1','cafe',1,'food plate restaurant delicious'),
('w_cafe_A1_04','water','/ˈwɔːtər/','noun','물','The clear liquid that comes from rain.','Can I have some {water}, please?','물 좀 주실 수 있나요?','water','A1','cafe',1,'water glass restaurant table'),
('w_cafe_A1_05','coffee','/ˈkɒfi/','noun','커피','A hot drink made from roasted coffee beans.','I''d like a {coffee}, please.','커피 한 잔 주세요.','coffee','A1','cafe',1,'coffee cup hot drink cafe'),
('w_cafe_A1_06','tea','/tiː/','noun','차','A hot drink made by soaking tea leaves in boiling water.','I prefer {tea} in the morning.','아침에는 차를 더 좋아해요.','tea','A1','cafe',1,'tea cup hot drink morning'),
('w_cafe_A1_07','menu','/ˈmenjuː/','noun','메뉴','A list of dishes available in a restaurant.','Could I see the {menu}?','메뉴판 볼 수 있을까요?','menu','A1','cafe',1,'restaurant menu book reading'),
('w_cafe_A1_08','table','/ˈteɪbl/','noun','테이블','A piece of furniture with a flat top at which people sit to eat.','Is this {table} free?','이 테이블 비어 있나요?','table','A1','cafe',1,'restaurant table chairs empty'),
('w_cafe_A1_09','hungry','/ˈhʌŋɡri/','adjective','배고픈','Feeling the need to eat food.','I''m so {hungry} right now.','지금 너무 배고파요.','hungry','A1','cafe',1,'hungry person stomach food craving'),
('w_cafe_A1_10','delicious','/dɪˈlɪʃəs/','adjective','맛있는','Having a very pleasant taste or smell.','This cake is absolutely {delicious}!','이 케이크 정말 맛있어요!','delicious','A1','cafe',1,'delicious food cake smile enjoyment'),
('w_cafe_A1_11','please','/pliːz/','adverb','부탁해요','Used to make a request more polite.','One coffee, {please}.','커피 하나 부탁해요.','please','A1','cafe',1,'polite request service staff cafe'),
('w_cafe_A1_12','hot','/hɒt/','adjective','뜨거운','Having a high temperature.','Be careful, the soup is very {hot}.','조심하세요, 수프가 매우 뜨거워요.','hot','A1','cafe',1,'hot soup steam food bowl'),
('w_cafe_A1_13','cold','/kəʊld/','adjective','차가운','Having a low temperature.','I''d like a {cold} drink.','차가운 음료를 주세요.','cold','A1','cafe',1,'cold drink ice glass refreshing'),
('w_cafe_A1_14','big','/bɪɡ/','adjective','큰','Of large size.','Can I have the {big} size?','큰 사이즈로 주세요.','big','A1','cafe',2,'large size cup coffee drink'),
('w_cafe_A1_15','small','/smɔːl/','adjective','작은','Of little size.','Just a {small} cup, thank you.','작은 컵으로 주세요.','small','A1','cafe',2,'small cup coffee size drink'),
('w_cafe_A1_16','more','/mɔːr/','adverb','더','A greater amount.','Can I have {more} bread?','빵 더 주실 수 있나요?','more','A1','cafe',1,'bread basket restaurant refill more'),
('w_cafe_A1_17','ready','/ˈredi/','adjective','준비된','Prepared to do something.','Are you {ready} to order?','주문하실 준비 됐나요?','ready','A1','cafe',1,'ready order restaurant waiter'),
('w_cafe_A1_18','good','/ɡʊd/','adjective','좋은','Of high quality or pleasant standard.','Everything here is so {good}.','여기 모든 게 다 맛있어요.','good','A1','cafe',1,'good food restaurant smile happy'),
('w_cafe_A1_19','open','/ˈəʊpən/','adjective','영업 중인','Ready to receive customers.','Is the café still {open}?','카페 아직 문 열었나요?','open','A1','cafe',2,'cafe open sign door entrance'),
('w_cafe_A1_20','close','/kləʊz/','verb','문을 닫다','To stop being available to customers.','What time do you {close}?','몇 시에 문 닫아요?','close','A1','cafe',2,'cafe closing time sign door'),
('w_cafe_A1_21','price','/praɪs/','noun','가격','The amount of money expected for something.','What''s the {price} of this?','이거 얼마예요?','price','A1','cafe',1,'price tag menu cost cafe'),
('w_cafe_A1_22','milk','/mɪlk/','noun','우유','A white liquid produced by cows.','Can I add {milk} to my coffee?','커피에 우유 넣어줄 수 있나요?','milk','A1','cafe',1,'milk pour coffee white cup'),
('w_cafe_A1_23','sugar','/ˈʃʊɡər/','noun','설탕','A sweet substance used to sweeten food or drinks.','No {sugar}, please.','설탕은 빼주세요.','sugar','A1','cafe',2,'sugar spoon coffee sweet white'),
('w_cafe_A1_24','bread','/bred/','noun','빵','A food made from flour, water, and yeast.','The {bread} here is freshly baked.','여기 빵은 막 구운 거예요.','bread','A1','cafe',1,'fresh bread bakery loaf oven'),
('w_cafe_A1_25','cake','/keɪk/','noun','케이크','A sweet food made by baking a mixture.','I''ll have a slice of {cake}.','케이크 한 조각 주세요.','cake','A1','cafe',2,'slice cake plate dessert fork'),
('w_cafe_A1_26','soup','/suːp/','noun','수프','A liquid food made by cooking vegetables or meat.','The {soup} of the day is tomato.','오늘의 수프는 토마토예요.','soup','A1','cafe',2,'soup bowl spoon hot restaurant'),
('w_cafe_A1_27','juice','/dʒuːs/','noun','주스','A drink made from the liquid of fruit or vegetables.','Can I get an orange {juice}?','오렌지 주스 주실 수 있나요?','juice','A1','cafe',1,'orange juice glass fresh fruit'),
('w_cafe_A1_28','bill','/bɪl/','noun','계산서','A document listing the price of things you have bought.','Can we get the {bill}, please?','계산서 주세요.','bill','A1','cafe',1,'restaurant bill check payment table'),
('w_cafe_A1_29','free','/friː/','adjective','무료의','Not costing any money.','Is the Wi-Fi {free} here?','여기 와이파이 무료인가요?','free','A1','cafe',2,'wifi free cafe sign internet'),
('w_cafe_A1_30','wait','/weɪt/','verb','기다리다','To stay in a place until something happens.','How long do we have to {wait}?','얼마나 기다려야 하나요?','wait','A1','cafe',2,'waiting line queue restaurant entrance'),
('w_cafe_A1_31','seat','/siːt/','noun','자리','A place where someone sits.','Is this {seat} taken?','이 자리 있나요?','seat','A1','cafe',1,'cafe seat chair empty taken'),
('w_cafe_A1_32','outside','/ˌaʊtˈsaɪd/','adverb','바깥에','In the open air, not inside a building.','Can we sit {outside}?','바깥에 앉을 수 있나요?','outside','A1','cafe',2,'outdoor seating cafe terrace sunny'),
('w_cafe_A1_33','inside','/ˌɪnˈsaɪd/','adverb','안쪽에','In the interior of a building.','I prefer to sit {inside}.','안쪽에 앉고 싶어요.','inside','A1','cafe',2,'cafe interior inside cozy warm'),
('w_cafe_A1_34','fresh','/freʃ/','adjective','신선한','Recently made or obtained.','Is this {fresh} today?','오늘 신선한 건가요?','fresh','A1','cafe',1,'fresh ingredients vegetables market morning'),
('w_cafe_A1_35','sweet','/swiːt/','adjective','단','Having the pleasant taste of sugar.','This is really {sweet}.','이게 정말 달아요.','sweet','A1','cafe',2,'sweet dessert cake sugar taste')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_A2_01','order','/ˈɔːrdər/','verb','주문하다','To ask for food or drink in a restaurant.','Are you ready to {order}?','주문하실 준비 됐나요?','order','A2','cafe',1,'waiter order restaurant customer menu'),
('w_cafe_A2_02','waiter','/ˈweɪtər/','noun','웨이터','A man who brings food and drinks to people in a restaurant.','Excuse me, {waiter}!','저기요, 웨이터!','waiter','A2','cafe',1,'waiter apron restaurant service smile'),
('w_cafe_A2_03','reservation','/ˌrezərˈveɪʃən/','noun','예약','An arrangement to have a seat kept for you.','I have a {reservation} for six o''clock.','6시로 예약했어요.','reservation','A2','cafe',1,'restaurant reservation booking table'),
('w_cafe_A2_04','takeaway','/ˈteɪkəweɪ/','noun','포장 주문','Food bought to eat somewhere other than the restaurant.','I''ll get that as a {takeaway}.','그걸 포장으로 주세요.','takeaway','A2','cafe',1,'takeaway coffee cup bag carry street'),
('w_cafe_A2_05','dessert','/dɪˈzɜːrt/','noun','디저트','The sweet food eaten at the end of a meal.','Do you have room for {dessert}?','디저트 드실 수 있어요?','dessert','A2','cafe',1,'dessert chocolate cake plate sweet'),
('w_cafe_A2_06','vegetarian','/ˌvedʒɪˈteəriən/','adjective','채식의','Not containing meat or fish.','Do you have {vegetarian} options?','채식 옵션이 있나요?','vegetarian','A2','cafe',1,'vegetarian salad green healthy food'),
('w_cafe_A2_07','spicy','/ˈspaɪsi/','adjective','매운','Having a strong, hot flavor from spices.','Is this dish very {spicy}?','이 요리 많이 매워요?','spicy','A2','cafe',1,'spicy chili food red hot pepper'),
('w_cafe_A2_08','mild','/maɪld/','adjective','순한, 맵지 않은','Not strongly flavored or spicy.','I''d prefer something {mild}.','순한 걸로 주세요.','mild','A2','cafe',1,'mild food gentle flavor soup light'),
('w_cafe_A2_09','portion','/ˈpɔːrʃən/','noun','1인분, 양','An amount of food served to one person.','The {portion} is very generous here.','여기 양이 정말 넉넉해요.','portion','A2','cafe',1,'large portion food plate generous restaurant'),
('w_cafe_A2_10','tip','/tɪp/','noun','팁','Money given to a waiter as a reward for good service.','Should we leave a {tip}?','팁을 남길까요?','tip','A2','cafe',1,'tip money restaurant table service'),
('w_cafe_A2_11','receipt','/rɪˈsiːt/','noun','영수증','A piece of paper showing money paid.','Can I have a {receipt}, please?','영수증 주실 수 있나요?','receipt','A2','cafe',1,'receipt paper payment purchase cafe'),
('w_cafe_A2_12','change','/tʃeɪndʒ/','noun','거스름돈','Money returned when you have paid more than the cost.','Keep the {change}.','잔돈은 가지세요.','change','A2','cafe',2,'change coins money cash payment'),
('w_cafe_A2_13','flavor','/ˈfleɪvər/','noun','맛, 풍미','The taste of a food or drink.','What {flavor} is this ice cream?','이 아이스크림 무슨 맛이에요?','flavor','A2','cafe',1,'ice cream flavors colors dessert shop'),
('w_cafe_A2_14','sauce','/sɔːs/','noun','소스','A liquid served with food to add flavor.','Can I get extra {sauce}?','소스 더 주실 수 있나요?','sauce','A2','cafe',2,'sauce bottle dipping food restaurant'),
('w_cafe_A2_15','side','/saɪd/','noun','사이드 메뉴','A small dish served alongside the main course.','What {side} dishes come with it?','사이드 메뉴는 뭐가 나와요?','side','A2','cafe',2,'side dish salad restaurant plate food'),
('w_cafe_A2_16','main','/meɪn/','adjective','메인의','Most important or biggest.','What''s today''s {main} course?','오늘 메인 요리는 뭔가요?','main','A2','cafe',1,'main course dish plate restaurant dinner'),
('w_cafe_A2_17','starter','/ˈstɑːrtər/','noun','전채 요리','A small dish eaten at the start of a meal.','Shall we skip the {starter}?','전채 요리는 건너뛸까요?','starter','A2','cafe',1,'starter appetizer small plate food restaurant'),
('w_cafe_A2_18','gluten','/ˈɡluːtən/','noun','글루텐','A protein found in wheat that some people cannot eat.','Is this {gluten}-free?','이거 글루텐 프리인가요?','gluten','A2','cafe',2,'gluten free label bread wheat food'),
('w_cafe_A2_19','ingredient','/ɪnˈɡriːdiənt/','noun','재료','One of the items used to make a dish.','What are the {ingredients} in this?','이 재료가 뭔가요?','ingredient','A2','cafe',1,'ingredients cooking kitchen food preparation'),
('w_cafe_A2_20','sharing','/ˈʃeərɪŋ/','adjective','공유용','Intended to be divided among people.','Is this a {sharing} platter?','이게 쉐어링 플레터인가요?','sharing','A2','cafe',2,'sharing platter food friends table together'),
('w_cafe_A2_21','dine','/daɪn/','verb','식사하다','To eat dinner, especially in a formal setting.','We''d like to {dine} here tonight.','오늘 저녁 여기서 식사하고 싶어요.','dine','A2','cafe',1,'dining restaurant elegant dinner table candle'),
('w_cafe_A2_22','takeout','/ˈteɪkaʊt/','noun','포장','Food ordered from a restaurant to eat elsewhere.','Can I place a {takeout} order?','포장 주문 할 수 있나요?','takeout','A2','cafe',1,'takeout bag food packaging restaurant counter'),
('w_cafe_A2_23','combo','/ˈkɒmbəʊ/','noun','세트','A meal that includes several items together at a discount.','I''ll have the lunch {combo}.','점심 세트로 주세요.','combo','A2','cafe',2,'combo meal set food drink fries'),
('w_cafe_A2_24','refund','/ˈriːfʌnd/','noun','환불','Money paid back to a customer.','Can I get a {refund} for this order?','이 주문 환불 받을 수 있나요?','refund','A2','cafe',2,'refund receipt return policy customer'),
('w_cafe_A2_25','napkin','/ˈnæpkɪn/','noun','냅킨','A piece of cloth or paper used when eating.','Could you bring some {napkins}?','냅킨 좀 가져다 주실 수 있나요?','napkins','A2','cafe',2,'napkin table restaurant folded cloth'),
('w_cafe_A2_26','fork','/fɔːrk/','noun','포크','A utensil with prongs used to eat food.','I need another {fork}.','포크가 하나 더 필요해요.','fork','A2','cafe',2,'fork cutlery restaurant table setting'),
('w_cafe_A2_27','straw','/strɔː/','noun','빨대','A thin tube used to suck up a drink.','Could I get a {straw}?','빨대 주실 수 있나요?','straw','A2','cafe',2,'straw drink cup cafe plastic paper'),
('w_cafe_A2_28','half','/hɑːf/','noun','절반','One of two equal parts.','Can we get a {half} portion?','반 인분으로 주실 수 있나요?','half','A2','cafe',2,'half portion food plate sharing'),
('w_cafe_A2_29','busy','/ˈbɪzi/','adjective','바쁜','Having a lot of customers or activity.','Is the restaurant very {busy} tonight?','오늘 저녁 식당 많이 바빠요?','busy','A2','cafe',2,'busy restaurant crowded evening dinner rush'),
('w_cafe_A2_30','wait time','/weɪt taɪm/','noun','대기 시간','The time spent waiting for a table or food.','What''s the {wait time} for a table?','테이블까지 대기 시간이 얼마나 돼요?','wait time','A2','cafe',1,'waiting line restaurant queue time estimate'),
('w_cafe_A2_31','wrap','/ræp/','noun','랩 샌드위치','Food wrapped in a thin piece of bread or tortilla.','I''ll have the chicken {wrap}.','치킨 랩으로 주세요.','wrap','A2','cafe',2,'wrap sandwich food lunch cafe counter'),
('w_cafe_A2_32','bowl','/bəʊl/','noun','그릇','A round dish used to serve food.','Can I get that in a {bowl}?','그걸 그릇에 담아 줄 수 있나요?','bowl','A2','cafe',2,'bowl soup rice food ceramic restaurant'),
('w_cafe_A2_33','extra','/ˈekstrə/','adjective','추가의','More than what is usual or expected.','Can I get {extra} cheese?','치즈 추가로 주실 수 있나요?','extra','A2','cafe',1,'extra cheese topping food add-on restaurant'),
('w_cafe_A2_34','cut','/kʌt/','verb','자르다','To divide food into pieces.','Can you {cut} the pizza into eight slices?','피자를 여덟 조각으로 잘라주실 수 있나요?','cut','A2','cafe',2,'cutting pizza slices board knife restaurant'),
('w_cafe_A2_35','enjoy','/ɪnˈdʒɔɪ/','verb','즐기다','To take pleasure in something.','I hope you {enjoy} your meal.','식사 맛있게 하세요.','enjoy','A2','cafe',1,'enjoying meal restaurant happy customer smile')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_B1_01','cuisine','/kwɪˈziːn/','noun','요리, 요리법','A style of cooking associated with a particular country or region.','I love Italian {cuisine}.','이탈리아 요리를 정말 좋아해요.','cuisine','B1','cafe',1,'italian cuisine food restaurant pasta'),
('w_cafe_B1_02','entrée','/ˈɒntreɪ/','noun','메인 요리','The main dish of a meal.','What {entrée} would you recommend?','메인 요리로 뭘 추천하시나요?','entrée','B1','cafe',1,'main dish entree plate restaurant dinner'),
('w_cafe_B1_03','pairing','/ˈpeərɪŋ/','noun','페어링, 조합','A combination of food and wine or other items that complement each other.','The sommelier suggested a wine {pairing}.','소믈리에가 와인 페어링을 추천해 줬어요.','pairing','B1','cafe',2,'wine pairing food restaurant glass dinner'),
('w_cafe_B1_04','ambience','/ˈæmbiəns/','noun','분위기','The character and atmosphere of a place.','The {ambience} here is perfect for a date.','여기 분위기가 데이트하기 딱 좋아요.','ambience','B1','cafe',1,'restaurant ambience lighting romantic atmosphere'),
('w_cafe_B1_05','allergies','/ˈælədʒiz/','noun','알레르기들','Medical conditions causing reactions to certain substances.','I have {allergies} to shellfish.','저는 조개류 알레르기가 있어요.','allergies','B1','cafe',1,'food allergy shellfish restriction menu'),
('w_cafe_B1_06','complimentary','/ˌkɒmplɪˈmentri/','adjective','무료 제공되는','Given free of charge as a courtesy.','The appetizers are {complimentary} today.','오늘 애피타이저는 서비스예요.','complimentary','B1','cafe',2,'complimentary service free food restaurant'),
('w_cafe_B1_07','specialty','/ˈspeʃəlti/','noun','특선 요리, 전문','The dish or item that a place is best known for.','The lamb is the house {specialty}.','양고기가 이 집 특선 요리예요.','specialty','B1','cafe',1,'chef special dish restaurant signature'),
('w_cafe_B1_08','refill','/ˈriːfɪl/','noun','리필','A fresh supply of a drink after the first is consumed.','Free {refills} on soft drinks.','탄산음료는 리필 무료예요.','refill','B1','cafe',1,'refill drink glass water restaurant free'),
('w_cafe_B1_09','seasonal','/ˈsiːzənəl/','adjective','제철의, 시즌별','Related to a particular time of year.','We use only {seasonal} produce.','저희는 제철 재료만 사용해요.','seasonal','B1','cafe',1,'seasonal vegetables fresh market produce autumn'),
('w_cafe_B1_10','authentic','/ɔːˈθentɪk/','adjective','정통의','Genuine, made in the traditional way.','This is {authentic} Korean barbecue.','이건 정통 한국식 바비큐예요.','authentic','B1','cafe',1,'authentic traditional cooking restaurant culture'),
('w_cafe_B1_11','reservation','/ˌrezərˈveɪʃən/','noun','예약','An arrangement to hold something for future use.','I''d like to make a {reservation} for Friday.','금요일로 예약하고 싶어요.','reservation','B1','cafe',1,'restaurant reservation booking table phone'),
('w_cafe_B1_12','dietary','/ˈdaɪətri/','adjective','식이의, 식단과 관련된','Relating to a person''s diet or dietary requirements.','Do you cater for {dietary} restrictions?','식이 제한이 있는 경우도 되나요?','dietary','B1','cafe',1,'dietary restriction menu special needs food'),
('w_cafe_B1_13','homemade','/ˌhəʊmˈmeɪd/','adjective','직접 만든','Made at home, not commercially produced.','The pasta here is {homemade}.','여기 파스타는 직접 만들어요.','homemade','B1','cafe',1,'homemade pasta kitchen handmade restaurant'),
('w_cafe_B1_14','tender','/ˈtendər/','adjective','연한','Easy to chew, not tough (of meat).','The steak is perfectly {tender}.','스테이크가 완벽하게 연해요.','tender','B1','cafe',1,'tender steak meat fork restaurant'),
('w_cafe_B1_15','crispy','/ˈkrɪspi/','adjective','바삭한','Pleasantly firm and making a crackling sound when bitten.','I love the {crispy} skin on this chicken.','이 치킨 껍질이 바삭해서 좋아요.','crispy','B1','cafe',1,'crispy fried chicken skin restaurant crunchy'),
('w_cafe_B1_16','savory','/ˈseɪvəri/','adjective','짭짤한, 감칠맛 나는','Having a pleasant, salty, or spicy taste.','I prefer {savory} food over sweet.','저는 단것보다 짭짤한 걸 더 좋아해요.','savory','B1','cafe',2,'savory food salty herbs bread snack'),
('w_cafe_B1_17','portion size','/ˈpɔːrʃən saɪz/','noun','1인분 크기','The amount of food given as one serving.','The {portion size} is very generous here.','여기 1인분이 정말 넉넉해요.','portion size','B1','cafe',1,'large portion food plate restaurant serving'),
('w_cafe_B1_18','atmosphere','/ˈætməsfɪər/','noun','분위기','The tone or mood of a place.','The {atmosphere} is very relaxed here.','여기 분위기가 매우 편안해요.','atmosphere','B1','cafe',1,'cafe atmosphere cozy warm lighting interior'),
('w_cafe_B1_19','overflow','/ˌəʊvərˈfləʊ/','verb','꽉 차다','To be too full or have too many customers.','The place was {overflowing} with people.','그 곳은 사람으로 가득했어요.','overflowing','B1','cafe',3,'crowded busy restaurant full people queue'),
('w_cafe_B1_20','selection','/sɪˈlekʃən/','noun','선택, 선별','A range of items to choose from.','The wine {selection} is excellent.','와인 선택지가 훌륭해요.','selection','B1','cafe',1,'wine selection bottles menu restaurant cellar'),
('w_cafe_B1_21','accompaniment','/əˈkʌmpənimənt/','noun','곁들이는 것','Something served alongside a main dish.','What {accompaniment} comes with the fish?','생선에는 어떤 게 곁들어 나와요?','accompaniment','B1','cafe',2,'side dish accompaniment food plate restaurant'),
('w_cafe_B1_22','garnish','/ˈɡɑːrnɪʃ/','noun','고명, 가니시','A decoration added to a dish or drink.','The cocktail has a lemon {garnish}.','칵테일에 레몬 가니시가 있어요.','garnish','B1','cafe',2,'garnish lemon herb cocktail decoration plate'),
('w_cafe_B1_23','well-done','/ˌwel ˈdʌn/','adjective','완전히 익힌','Cooked thoroughly, not rare.','I''d like my steak {well-done}.','스테이크는 완전히 익혀주세요.','well-done','B1','cafe',1,'well done steak meat cooked brown grill'),
('w_cafe_B1_24','medium','/ˈmiːdiəm/','adjective','미디엄으로 익힌','Cooked to an intermediate level, between rare and well-done.','Can I get the lamb {medium}?','양고기는 미디엄으로 해주세요.','medium','B1','cafe',1,'medium steak grill pink inside restaurant'),
('w_cafe_B1_25','rare','/reər/','adjective','레어로 익힌','Cooked so the outside is browned but the inside is still red.','I''ll have the steak {rare}, please.','스테이크는 레어로 주세요.','rare','B1','cafe',1,'rare steak red inside grill meat plate'),
('w_cafe_B1_26','substitute','/ˈsʌbstɪtjuːt/','verb','대체하다','To replace one thing with another.','Can I {substitute} the fries for a salad?','감자튀김 대신 샐러드로 바꿀 수 있나요?','substitute','B1','cafe',1,'substitute swap food salad fries restaurant'),
('w_cafe_B1_27','organic','/ɔːˈɡænɪk/','adjective','유기농의','Produced without artificial chemicals.','Do you use {organic} ingredients?','유기농 재료를 사용하나요?','organic','B1','cafe',1,'organic vegetables fresh market natural food'),
('w_cafe_B1_28','locally sourced','/ˈləʊkəli sɔːrst/','adjective','로컬 식재료의','Obtained from nearby farms or producers.','All our vegetables are {locally sourced}.','저희 채소는 모두 지역 농장에서 가져와요.','locally sourced','B1','cafe',2,'local farm fresh market vegetables produce'),
('w_cafe_B1_29','grilled','/ɡrɪld/','adjective','구운','Cooked on a grill using direct heat.','I''ll have the {grilled} salmon.','그릴에 구운 연어로 주세요.','grilled','B1','cafe',1,'grilled salmon fish restaurant grill marks'),
('w_cafe_B1_30','steamed','/stiːmd/','adjective','찐','Cooked using steam.','The {steamed} dumplings are delicious.','찐 만두가 맛있어요.','steamed','B1','cafe',1,'steamed dumplings dim sum restaurant chinese'),
('w_cafe_B1_31','braised','/breɪzd/','adjective','끓여 익힌','Slowly cooked in a small amount of liquid.','The {braised} short ribs melt in your mouth.','브레이즈드 갈비가 입에서 살살 녹아요.','braised','B1','cafe',2,'braised short ribs beef restaurant slow cooked'),
('w_cafe_B1_32','marinated','/ˈmærɪneɪtɪd/','adjective','양념에 재운','Soaked in a sauce or seasoning before cooking.','The {marinated} chicken is so juicy.','양념에 재운 치킨이 정말 촉촉해요.','marinated','B1','cafe',1,'marinated chicken seasoning herbs restaurant grill'),
('w_cafe_B1_33','dietary restriction','/ˈdaɪətri rɪˈstrɪkʃən/','noun','식이 제한','A limitation on what foods a person can eat.','I have a {dietary restriction} — no dairy.','저는 유제품을 먹지 못해요.','dietary restriction','B1','cafe',1,'dietary restriction dairy free menu restaurant'),
('w_cafe_B1_34','course','/kɔːrs/','noun','코스','One of several dishes that make up a meal.','This is a three-{course} meal.','이건 3코스 식사예요.','course','B1','cafe',1,'three course meal restaurant dinner elegant'),
('w_cafe_B1_35','halal','/həˈlɑːl/','adjective','할랄의','Permissible according to Muslim law.','Is there a {halal} option available?','할랄 옵션이 있나요?','halal','B1','cafe',2,'halal food certification menu restaurant mosque')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_B2_01','connoisseur','/ˌkɒnəˈsɜːr/','noun','미식가, 감별사','An expert judge in matters of taste.','He is a true wine {connoisseur}.','그는 진정한 와인 감별사예요.','connoisseur','B2','cafe',1,'wine connoisseur expert tasting glass cellar'),
('w_cafe_B2_02','sommelier','/ˌsɒməˈljeɪ/','noun','소믈리에','A trained wine steward in a restaurant.','The {sommelier} suggested a Burgundy.','소믈리에가 부르고뉴를 추천했어요.','sommelier','B2','cafe',1,'sommelier wine restaurant bottle recommend'),
('w_cafe_B2_03','palate','/ˈpælɪt/','noun','미각, 입맛','A person''s ability to appreciate fine food and drink.','This wine suits my {palate} perfectly.','이 와인이 제 입맛에 딱 맞아요.','palate','B2','cafe',1,'palate wine tasting taste flavor sensory'),
('w_cafe_B2_04','gastronomy','/ɡæˈstrɒnəmi/','noun','미식학, 요리의 예술','The practice of choosing, cooking, and eating good food.','The city is known for its fine {gastronomy}.','그 도시는 훌륭한 미식 문화로 유명해요.','gastronomy','B2','cafe',1,'gastronomy fine dining restaurant elegant food'),
('w_cafe_B2_05','gourmet','/ˈɡɔːrmeɪ/','adjective','고급 미식의','Of very high quality and usually expensive.','This is a {gourmet} burger restaurant.','이건 고급 버거 레스토랑이에요.','gourmet','B2','cafe',1,'gourmet burger food upscale restaurant quality'),
('w_cafe_B2_06','fermentation','/ˌfɜːrmenˈteɪʃən/','noun','발효','The process by which microorganisms convert sugars into acids or alcohol.','The bread benefits from long {fermentation}.','긴 발효 과정이 빵을 더 맛있게 해요.','fermentation','B2','cafe',1,'fermentation bread sourdough jar kitchen process'),
('w_cafe_B2_07','artisanal','/ɑːrˈtɪzənəl/','adjective','장인이 만든','Made in a traditional or non-mechanized way using skilled craftsmanship.','We only serve {artisanal} cheeses.','저희는 장인이 만든 치즈만 제공해요.','artisanal','B2','cafe',1,'artisanal cheese handmade craft market food'),
('w_cafe_B2_08','decant','/dɪˈkænt/','verb','(와인을) 디캔팅하다','To pour wine into a decanter to allow it to breathe.','The sommelier offered to {decant} the red wine.','소믈리에가 레드 와인을 디캔팅해 주겠다고 했어요.','decant','B2','cafe',2,'decant wine pour decanter glass restaurant'),
('w_cafe_B2_09','curation','/kjʊˈreɪʃən/','noun','큐레이션','The process of selecting and organizing items from a large range.','Their menu is a careful {curation} of seasonal dishes.','메뉴는 제철 요리들을 세심하게 선별한 것이에요.','curation','B2','cafe',2,'menu curation selection restaurant chef seasonal'),
('w_cafe_B2_10','fusion','/ˈfjuːʒən/','noun','퓨전','A combination of two or more distinct culinary styles.','This restaurant serves Korean-Mexican {fusion}.','이 식당은 한국-멕시코 퓨전 요리를 제공해요.','fusion','B2','cafe',1,'fusion food restaurant korean mexican creative'),
('w_cafe_B2_11','infuse','/ɪnˈfjuːz/','verb','우려내다, 불어넣다','To soak something in liquid to extract flavor.','The tea is {infused} with jasmine.','차에 재스민 향이 우려져 있어요.','infused','B2','cafe',1,'infuse tea jasmine herbs pot flavor'),
('w_cafe_B2_12','umami','/uːˈmɑːmi/','noun','감칠맛','A savory taste that is one of the five basic tastes.','This broth has a deep {umami} flavor.','이 육수에는 깊은 감칠맛이 있어요.','umami','B2','cafe',1,'umami flavor broth soup savory depth'),
('w_cafe_B2_13','emulsify','/ɪˈmʌlsɪfaɪ/','verb','유화시키다','To combine two immiscible liquids into a stable mixture.','Whisk vigorously to {emulsify} the dressing.','드레싱을 유화시키려면 힘차게 휘저으세요.','emulsify','B2','cafe',2,'emulsify dressing salad oil vinegar whisk kitchen'),
('w_cafe_B2_14','reduction','/rɪˈdʌkʃən/','noun','리덕션 소스','A sauce made by boiling liquid until it becomes concentrated.','The dish is topped with a balsamic {reduction}.','요리 위에 발사믹 리덕션이 올려져 있어요.','reduction','B2','cafe',1,'balsamic reduction sauce plate gourmet restaurant'),
('w_cafe_B2_15','deglaze','/diːˈɡleɪz/','verb','데글레이즈하다','To loosen browned bits from a pan using liquid.','The chef used wine to {deglaze} the pan.','셰프가 와인으로 팬을 데글레이즈했어요.','deglaze','B2','cafe',2,'deglaze pan wine cooking kitchen chef'),
('w_cafe_B2_16','provenance','/ˈprɒvənəns/','noun','산지, 출처','The place of origin or earliest known history of something.','We proudly display the {provenance} of all our ingredients.','저희는 모든 재료의 산지를 자랑스럽게 표시해요.','provenance','B2','cafe',1,'provenance ingredients origin farm food label'),
('w_cafe_B2_17','infusion','/ɪnˈfjuːʒən/','noun','우린 것, 인퓨전','A liquid obtained by soaking herbs or other substances.','Try our seasonal herbal {infusion}.','시즌별 허브 인퓨전을 드셔보세요.','infusion','B2','cafe',2,'herbal infusion tea herbs cup warm'),
('w_cafe_B2_18','macerate','/ˈmæsəreɪt/','verb','(과일 등을) 재우다','To soften food by soaking it in liquid.','{Macerate} the strawberries in sugar overnight.','딸기를 설탕에 하룻밤 재워두세요.','macerate','B2','cafe',2,'macerate strawberries sugar fruit soaking'),
('w_cafe_B2_19','rendered','/ˈrendərd/','adjective','지방이 녹아 바삭한','Cooked so that the fat melts out.','The duck skin is perfectly {rendered}.','오리 껍질이 완벽하게 바삭하게 구워졌어요.','rendered','B2','cafe',2,'rendered duck skin crispy fat restaurant'),
('w_cafe_B2_20','char','/tʃɑːr/','verb','살짝 태우다','To partially burn or blacken the surface of food.','We lightly {char} the vegetables over an open flame.','채소를 직화로 살짝 태워요.','char','B2','cafe',1,'char grilled vegetables fire flame restaurant'),
('w_cafe_B2_21','brine','/braɪn/','noun','소금물','A highly concentrated salt solution used to preserve food.','The chicken is soaked in {brine} for 24 hours.','치킨을 24시간 소금물에 담가요.','brine','B2','cafe',2,'brine salt water chicken preservation jar'),
('w_cafe_B2_22','cure','/kjʊər/','verb','절이다, 염장하다','To preserve food by salting, smoking, or drying.','This salmon is {cured} with dill and salt.','이 연어는 딜과 소금으로 절여요.','cured','B2','cafe',1,'cured salmon dill salt lox restaurant'),
('w_cafe_B2_23','forage','/ˈfɒrɪdʒ/','verb','채집하다','To search for and collect wild food from natural environments.','The chef {forages} for mushrooms every morning.','셰프가 매일 아침 버섯을 채집해요.','forages','B2','cafe',2,'foraging mushrooms forest chef wild food'),
('w_cafe_B2_24','drizzle','/ˈdrɪzl/','verb','살짝 뿌리다','To pour a thin stream of liquid over food.','{Drizzle} the olive oil over the salad.','샐러드 위에 올리브 오일을 살짝 뿌려요.','drizzle','B2','cafe',1,'drizzle oil dressing salad plate restaurant'),
('w_cafe_B2_25','caramelized','/ˈkærəməlaɪzd/','adjective','카라멜화된','Cooked until the natural sugars turn brown.','The onions are slowly {caramelized}.','양파가 천천히 카라멜화돼요.','caramelized','B2','cafe',1,'caramelized onions brown sweet pan cooking'),
('w_cafe_B2_26','mouthfeel','/ˈmaʊθfiːl/','noun','입안의 식감','The physical sensations in the mouth caused by food.','The sauce has a lovely creamy {mouthfeel}.','소스의 크리미한 식감이 정말 좋아요.','mouthfeel','B2','cafe',2,'texture creamy sauce food mouth sensation'),
('w_cafe_B2_27','sear','/sɪər/','verb','(고온에) 겉을 굽다','To cook the surface of food quickly at high heat.','{Sear} the tuna for just thirty seconds each side.','참치를 각 면마다 30초씩 세어링하세요.','sear','B2','cafe',1,'sear tuna steak high heat pan restaurant'),
('w_cafe_B2_28','blanch','/blɑːntʃ/','verb','살짝 데치다','To briefly boil food and then cool it immediately in cold water.','{Blanch} the broccoli before sautéing.','볶기 전에 브로콜리를 살짝 데쳐요.','blanch','B2','cafe',2,'blanch vegetables boiling water broccoli kitchen'),
('w_cafe_B2_29','glaze','/ɡleɪz/','noun','글레이즈, 윤기 나는 소스','A glossy coating applied to food.','The ham is finished with a honey {glaze}.','햄 위에 꿀 글레이즈를 발라 마무리해요.','glaze','B2','cafe',1,'glaze honey ham shiny coating oven baked'),
('w_cafe_B2_30','al dente','/æl ˈdenti/','adjective','알 덴테 (약간 씹히게)','Cooked to be firm to the bite.','I like my pasta {al dente}.','파스타는 알 덴테로 좋아해요.','al dente','B2','cafe',1,'pasta al dente fork plate italian restaurant'),
('w_cafe_B2_31','pairing','/ˈpeərɪŋ/','noun','마리아주, 페어링','A combination of food and drink that complement each other.','The cheese {pairing} was thoughtfully selected.','치즈 페어링이 세심하게 선정됐어요.','pairing','B2','cafe',1,'cheese wine pairing selection restaurant board'),
('w_cafe_B2_32','tartness','/ˈtɑːrtnəs/','noun','새콤함','The quality of having a sharp, acidic taste.','The lemon curd has a pleasant {tartness}.','레몬 커드에 기분 좋은 새콤함이 있어요.','tartness','B2','cafe',2,'lemon curd tart sharp sour taste citrus'),
('w_cafe_B2_33','acidity','/əˈsɪdɪti/','noun','산도','The level of acid in food or wine.','The wine has a high {acidity} that cuts through the fat.','이 와인의 높은 산도가 기름기를 잡아줘요.','acidity','B2','cafe',1,'wine acidity glass tasting flavor profile'),
('w_cafe_B2_34','texture','/ˈtekstʃər/','noun','식감','The feel of a food in the mouth.','The {texture} of the mousse is incredibly smooth.','무스의 식감이 믿을 수 없을 만큼 부드러워요.','texture','B2','cafe',1,'mousse smooth texture spoon plate dessert'),
('w_cafe_B2_35','flambé','/flæmˈbeɪ/','verb','플람베하다','To pour alcohol over food and set it alight briefly.','The waiter {flambéed} the crêpes at the table.','웨이터가 테이블 옆에서 크레이프를 플람베했어요.','flambéed','B2','cafe',2,'flambe crepe fire alcohol tableside restaurant')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_C1_01','terroir','/tɛˈrwɑːr/','noun','테루아','The environmental conditions, especially soil and climate, in which grapes are grown.','This wine reflects the {terroir} of the Burgundy region.','이 와인은 부르고뉴 지역의 테루아를 반영해요.','terroir','C1','cafe',1,'terroir vineyard grapes soil climate wine'),
('w_cafe_C1_02','umami','/uːˈmɑːmi/','noun','감칠맛 (제5미각)','A category of taste in food corresponding to a savory, meaty flavor.','The miso adds an intense {umami} depth.','된장이 깊은 감칠맛을 더해줘요.','umami','C1','cafe',1,'umami miso broth savory depth flavor'),
('w_cafe_C1_03','molecular gastronomy','/məˈlekjʊlər ɡæˈstrɒnəmi/','noun','분자 요리학','A scientific approach to cooking that examines physical and chemical processes.','The chef trained in {molecular gastronomy} in Catalonia.','셰프는 카탈로니아에서 분자 요리학을 배웠어요.','molecular gastronomy','C1','cafe',1,'molecular gastronomy chef science food lab'),
('w_cafe_C1_04','foraging','/ˈfɒrɪdʒɪŋ/','noun','채집','The practice of searching for and collecting wild food from natural environments.','{Foraging} for wild herbs defines this restaurant''s ethos.','야생 허브를 채집하는 것이 이 레스토랑의 철학이에요.','foraging','C1','cafe',1,'foraging wild herbs forest chef nature food'),
('w_cafe_C1_05','provenance','/ˈprɒvənəns/','noun','(식재료의) 산지와 이력','The origin and history of ingredients.','Every dish on the menu lists the {provenance} of its ingredients.','메뉴의 모든 요리에 재료의 산지가 적혀 있어요.','provenance','C1','cafe',1,'provenance farm ingredient origin label traceability'),
('w_cafe_C1_06','Michelin star','/ˈmɪʃəlɪn stɑːr/','noun','미슐랭 스타','A prestigious award given by the Michelin Guide to exceptional restaurants.','This is the chef''s first {Michelin star} restaurant.','이 레스토랑은 셰프의 첫 미슐랭 스타 식당이에요.','Michelin star','C1','cafe',1,'michelin star restaurant chef award fine dining'),
('w_cafe_C1_07','tasting menu','/ˈteɪstɪŋ ˈmenjuː/','noun','테이스팅 메뉴','A series of small dishes showcasing a chef''s range of cooking.','The {tasting menu} consists of twelve courses.','테이스팅 메뉴는 12코스로 구성돼 있어요.','tasting menu','C1','cafe',1,'tasting menu small plates restaurant fine dining'),
('w_cafe_C1_08','mise en place','/ˌmiːz ɒn ˈplɑːs/','noun','미장 플라스 (사전 준비)','The practice of preparing and organizing all ingredients before cooking.','Good {mise en place} is the foundation of professional cooking.','좋은 미장 플라스는 전문 요리의 기본이에요.','mise en place','C1','cafe',1,'mise en place prep kitchen chef organized'),
('w_cafe_C1_09','charcuterie','/ʃɑːrˈkuːtəri/','noun','샤르퀴트리','A branch of cooking involving dressed meats, especially pork.','The {charcuterie} board comes with three house-cured meats.','샤르퀴트리 보드에는 직접 염장한 고기 3종이 나와요.','charcuterie','C1','cafe',1,'charcuterie board meat cheese wine restaurant'),
('w_cafe_C1_10','reduction','/rɪˈdʌkʃən/','noun','리덕션 (농축 소스)','A sauce made by simmering liquid until it is concentrated and thickened.','The dish is plated with a port wine {reduction}.','요리에 포트 와인 리덕션이 곁들여져요.','reduction','C1','cafe',1,'reduction sauce wine plate fine dining gourmet'),
('w_cafe_C1_11','consommé','/ˈkɒnsəmeɪ/','noun','콩소메','A clear soup made from rich stock clarified by egg whites.','The meal begins with a delicate chicken {consommé}.','식사는 섬세한 치킨 콩소메로 시작돼요.','consommé','C1','cafe',1,'consomme clear soup elegant restaurant fine dining'),
('w_cafe_C1_12','velouté','/vəˈluːteɪ/','noun','벨루테 소스','A smooth white sauce made from stock thickened with a roux.','The fish is served in a saffron {velouté}.','생선은 사프란 벨루테에 담겨 나와요.','velouté','C1','cafe',2,'veloute sauce white fish saffron fine dining'),
('w_cafe_C1_13','coulis','/ˈkuːli/','noun','쿨리 (체로 거른 소스)','A thin sauce made from puréed and strained fruit or vegetables.','The plate is decorated with a raspberry {coulis}.','접시에 라즈베리 쿨리가 장식돼 있어요.','coulis','C1','cafe',2,'coulis raspberry sauce dessert plate decoration'),
('w_cafe_C1_14','sous vide','/suː ˈviːd/','noun','수비드 조리법','A method of cooking food sealed in bags submerged in a water bath.','The egg is prepared using {sous vide} at sixty-three degrees.','달걀은 63도에서 수비드 방식으로 조리돼요.','sous vide','C1','cafe',1,'sous vide cooking bag water bath precision'),
('w_cafe_C1_15','emulsion','/ɪˈmʌlʃən/','noun','에멀션, 유화액','A mixture of two liquids normally impossible to combine.','The dressing is a light oil-and-vinegar {emulsion}.','드레싱은 오일과 식초의 가벼운 에멀션이에요.','emulsion','C1','cafe',2,'emulsion oil vinegar dressing salad kitchen'),
('w_cafe_C1_16','deconstructed','/ˌdiːkənˈstrʌktɪd/','adjective','해체된, 재해석된','Presented in a way that breaks down a traditional dish into its components.','The {deconstructed} tiramisu is a work of art.','해체된 티라미수는 예술 작품 같아요.','deconstructed','C1','cafe',1,'deconstructed dessert modern restaurant artistic plate'),
('w_cafe_C1_17','amuse-bouche','/əˌmjuːz ˈbuːʃ/','noun','아뮤즈 부슈','A single bite-sized hors d''œuvre served before the meal.','We received a truffle {amuse-bouche} to start.','트러플 아뮤즈 부슈로 시작했어요.','amuse-bouche','C1','cafe',2,'amuse bouche truffle bite restaurant fine dining'),
('w_cafe_C1_18','intermezzo','/ˌɪntərˈmetsəʊ/','noun','인터메조 (코스 사이의 셔벗)','A small dish served between courses to cleanse the palate.','A lemon sorbet {intermezzo} was served between courses.','코스 사이에 레몬 셔벗 인터메조가 나왔어요.','intermezzo','C1','cafe',2,'intermezzo sorbet lemon course palate cleanser'),
('w_cafe_C1_19','foie gras','/ˌfwɑː ˈɡrɑː/','noun','푸아그라','A luxury food product made from the liver of a specially fattened duck or goose.','The {foie gras} terrine is the signature starter.','푸아그라 테린이 대표 전채 요리예요.','foie gras','C1','cafe',2,'foie gras liver duck luxury restaurant starter'),
('w_cafe_C1_20','tartare','/ˈtɑːrtɑːr/','noun','타르타르','A dish of raw chopped meat or fish mixed with seasonings.','I''d like the beef {tartare} with quail egg.','메추리알을 얹은 비프 타르타르를 주세요.','tartare','C1','cafe',2,'tartare beef raw chopped egg fine dining'),
('w_cafe_C1_21','quenelle','/kəˈnel/','noun','크넬 (달걀형 가니시)','An oval-shaped portion of mousse, cream, or ice cream formed between two spoons.','The ice cream was served as a {quenelle}.','아이스크림이 크넬 모양으로 제공됐어요.','quenelle','C1','cafe',3,'quenelle ice cream mousse oval spoon plate'),
('w_cafe_C1_22','brunoise','/ˈbruːnwɑːz/','noun','브루누아즈 (깍뚝썰기)','Vegetables diced into very small uniform cubes.','The soup is garnished with a carrot {brunoise}.','수프는 당근 브루누아즈로 장식돼요.','brunoise','C1','cafe',2,'brunoise dice vegetables carrot kitchen knife'),
('w_cafe_C1_23','julienne','/dʒuːliˈen/','noun','줄리엔 (채 썰기)','Vegetables cut into long thin matchstick-shaped strips.','The salad features {julienned} daikon.','샐러드에 채 썬 무가 들어가요.','julienned','C1','cafe',2,'julienne daikon vegetable strips salad knife'),
('w_cafe_C1_24','nappe','/næp/','verb','소스를 고르게 입히다','To coat food with a sauce of the right consistency.','The sauce should {nappe} the spoon.','소스는 숟가락을 고르게 입혀야 해요.','nappe','C1','cafe',3,'nappe sauce spoon coating consistency kitchen'),
('w_cafe_C1_25','fond','/fɒnd/','noun','퐁 (팬에 눌은 육즙)','The browned bits that stick to the bottom of a pan after searing.','Deglaze the pan to lift the {fond}.','팬의 퐁을 데글레이즈로 들어올리세요.','fond','C1','cafe',2,'fond pan brown bits deglaze cooking chef'),
('w_cafe_C1_26','temper','/ˈtempər/','verb','템퍼링하다 (초콜릿 등)','To bring chocolate to a specific temperature sequence for the right texture.','The chef {tempered} the chocolate to achieve a glossy finish.','셰프가 윤기 있는 마감을 위해 초콜릿을 템퍼링했어요.','tempered','C1','cafe',2,'tempering chocolate glossy finish kitchen pastry'),
('w_cafe_C1_27','ganache','/ɡəˈnæʃ/','noun','가나슈','A smooth, rich chocolate mixture made from chocolate and cream.','The tart is filled with dark chocolate {ganache}.','타르트에 다크 초콜릿 가나슈가 채워져 있어요.','ganache','C1','cafe',2,'ganache chocolate tart dark pastry rich'),
('w_cafe_C1_28','jus','/dʒuː/','noun','주 (고기 육즙 소스)','The natural juices from meat or the sauce made from them.','The lamb comes with a rosemary {jus}.','양고기에 로즈메리 주가 곁들여져요.','jus','C1','cafe',1,'jus sauce meat lamb rosemary restaurant plate'),
('w_cafe_C1_29','roulade','/ruːˈlɑːd/','noun','루라드 (돌돌 만 요리)','A dish made from a flat piece of food that is rolled around a filling.','The pork {roulade} is stuffed with herbs and garlic.','돼지고기 루라드에는 허브와 마늘이 채워져 있어요.','roulade','C1','cafe',2,'roulade pork rolled stuffed herbs restaurant'),
('w_cafe_C1_30','galette','/ɡæˈlet/','noun','갈레트','A flat, round cake or pastry, often savory.','We started with a buckwheat {galette}.','메밀 갈레트로 시작했어요.','galette','C1','cafe',2,'galette buckwheat crepe savory restaurant french'),
('w_cafe_C1_31','verrines','/verˈiːn/','noun','버린 (유리컵 요리)','A dish served in a small glass jar or cup, showing layers of ingredients.','The amuse-bouche was served as {verrines}.','아뮤즈 부슈가 버린으로 제공됐어요.','verrines','C1','cafe',3,'verrines glass jar layers food restaurant'),
('w_cafe_C1_32','praline','/ˈprɑːliːn/','noun','프랄린','A sweet candy made from nuts and caramelized sugar.','The dessert is topped with hazelnut {praline}.','디저트 위에 헤이즐넛 프랄린이 얹혀 있어요.','praline','C1','cafe',2,'praline hazelnut caramel sweet dessert'),
('w_cafe_C1_33','beurre blanc','/ˌbɜːr ˈblɒŋk/','noun','뵈르 블랑 소스','A classic French white butter sauce made with wine and shallots.','The halibut rests in a delicate {beurre blanc}.','광어가 섬세한 뵈르 블랑에 담겨 나와요.','beurre blanc','C1','cafe',2,'beurre blanc sauce butter fish restaurant french'),
('w_cafe_C1_34','confit','/ˈkɒnfi/','noun','콩피 (저온에 기름에 익힌)','Food slowly cooked in its own fat at a low temperature.','The duck leg {confit} is fall-off-the-bone tender.','오리 다리 콩피가 뼈에서 살이 쉽게 떨어질 만큼 연해요.','confit','C1','cafe',1,'duck confit leg fat slow cooked restaurant'),
('w_cafe_C1_35','crémeux','/kreɪˈmø/','noun','크레뫼 (크리미 가나슈)','A very smooth, creamy ganache-based dessert component.','The plate features a dark chocolate {crémeux}.','접시에 다크 초콜릿 크레뫼가 올려져 있어요.','crémeux','C1','cafe',2,'cremeux chocolate creamy smooth dessert pastry')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_cafe_C2_01','oenology','/iːˈnɒlədʒi/','noun','포도주학, 와인학','The study of wines and winemaking.','She has a degree in {oenology} from Bordeaux.','그녀는 보르도에서 포도주학 학위를 받았어요.','oenology','C2','cafe',1,'oenology wine study bordeaux laboratory'),
('w_cafe_C2_02','viticulture','/ˈvɪtɪkʌltʃər/','noun','포도 재배학','The cultivation and harvesting of grapes.','Advances in {viticulture} have transformed the region''s wines.','포도 재배학의 발전이 그 지역의 와인을 완전히 바꿔 놓았어요.','viticulture','C2','cafe',1,'viticulture vineyard grapes cultivation harvest'),
('w_cafe_C2_03','organoleptic','/ˌɔːrɡənəˈleptɪk/','adjective','관능적인 (맛·향·외관)','Relating to properties of food perceived by the senses.','The panel assessed the {organoleptic} qualities of each sample.','패널이 각 샘플의 관능 품질을 평가했어요.','organoleptic','C2','cafe',2,'organoleptic tasting panel sensory evaluation food'),
('w_cafe_C2_04','appellation','/ˌæpəˈleɪʃən/','noun','원산지 명칭 보호','A legally defined geographical indication used to identify wine.','This wine carries the Châteauneuf-du-Pape {appellation}.','이 와인에는 샤토뇌프뒤파프 원산지 명칭이 붙어 있어요.','appellation','C2','cafe',1,'appellation wine label region france origin'),
('w_cafe_C2_05','maceration','/ˌmæsəˈreɪʃən/','noun','침용, 마세라시옹','The process of soaking grape skins in the juice to extract color and tannins.','Extended {maceration} gives this red wine its depth of color.','장시간 침용이 이 레드 와인에 깊은 색을 부여해요.','maceration','C2','cafe',1,'maceration red wine grapes skins tannin'),
('w_cafe_C2_06','Maillard reaction','/maɪˈɑːr riˈækʃən/','noun','마이야르 반응','A chemical reaction between amino acids and sugars that produces browning.','The golden crust is created by the {Maillard reaction}.','황금빛 껍질은 마이야르 반응으로 만들어져요.','Maillard reaction','C2','cafe',1,'maillard reaction browning crust bread chemistry cooking'),
('w_cafe_C2_07','emulsification','/ɪˌmʌlsɪfɪˈkeɪʃən/','noun','유화 과정','The process of combining two immiscible liquids into a stable mixture.','Lecithin aids in the {emulsification} of the sauce.','레시틴이 소스의 유화를 도와줘요.','emulsification','C2','cafe',2,'emulsification lecithin sauce oil water kitchen'),
('w_cafe_C2_08','deglazing','/diːˈɡleɪzɪŋ/','noun','데글레이징','Adding liquid to a hot pan to loosen and dissolve browned food bits.','{Deglazing} with cognac adds complexity to the sauce.','코냑으로 데글레이징하면 소스에 복잡한 깊이가 생겨요.','deglazing','C2','cafe',1,'deglazing pan cognac sauce cooking restaurant'),
('w_cafe_C2_09','transglutaminase','/ˌtrænsˈɡluːtəmɪneɪz/','noun','트랜스글루타미나아제 (고기 접착 효소)','An enzyme used in molecular gastronomy to bind proteins together.','The chef used {transglutaminase} to form a scallop noodle.','셰프가 가리비 국수를 만들기 위해 트랜스글루타미나아제를 사용했어요.','transglutaminase','C2','cafe',2,'transglutaminase enzyme molecular gastronomy chef lab'),
('w_cafe_C2_10','spherification','/ˌsfɪərɪfɪˈkeɪʃən/','noun','구형화 (분자요리 기법)','A culinary technique that creates liquid-filled spheres resembling caviar.','The cocktail is served with elderflower {spherification}.','칵테일에 엘더플라워 구형화 알갱이가 곁들여져요.','spherification','C2','cafe',1,'spherification molecular gastronomy caviar cocktail restaurant'),
('w_cafe_C2_11','phenolic compounds','/fɪˈnɒlɪk ˈkɒmpaʊndz/','noun','페놀 화합물','Naturally occurring compounds in plants that contribute to taste and health benefits.','Red wine is rich in {phenolic compounds} such as resveratrol.','레드 와인에는 레스베라트롤 등 페놀 화합물이 풍부해요.','phenolic compounds','C2','cafe',2,'phenolic compounds wine grape antioxidant health'),
('w_cafe_C2_12','tannins','/ˈtænɪnz/','noun','타닌','Bitter plant compounds that create a drying sensation in wine.','The {tannins} in this Cabernet are still quite gripping.','이 카베르네의 타닌이 아직 상당히 강렬해요.','tannins','C2','cafe',1,'tannins wine cabernet red astringent grape'),
('w_cafe_C2_13','malolactic fermentation','/ˌmæləˌlæktɪk fɜːrmenˈteɪʃən/','noun','유산 발효','A winemaking process that converts tart malic acid into softer lactic acid.','{Malolactic fermentation} gives the Chardonnay its buttery character.','유산 발효가 샤르도네에 버터 같은 풍미를 부여해요.','malolactic fermentation','C2','cafe',2,'malolactic fermentation chardonnay wine buttery process'),
('w_cafe_C2_14','lees','/liːz/','noun','효모 찌꺼기','The sediment of yeast and other particles that settle in wine after fermentation.','Aging on the {lees} adds richness and complexity.','효모 찌꺼기 위에서의 숙성이 풍부함과 복잡성을 더해줘요.','lees','C2','cafe',2,'lees yeast sediment wine barrel aging'),
('w_cafe_C2_15','brix','/brɪks/','noun','브릭스 (당도 측정 단위)','A unit measuring the sugar content in grapes or other food liquids.','The grapes were harvested at twenty-four {brix}.','포도는 24 브릭스에서 수확했어요.','brix','C2','cafe',2,'brix sugar content grapes harvest measurement'),
('w_cafe_C2_16','volatile acidity','/ˈvɒlətaɪl əˈsɪdɪti/','noun','휘발성 산도','Gaseous acids in wine, primarily acetic acid, that can produce a vinegar aroma.','High {volatile acidity} is considered a wine fault.','높은 휘발성 산도는 와인의 결점으로 여겨져요.','volatile acidity','C2','cafe',2,'volatile acidity wine flaw vinegar aroma'),
('w_cafe_C2_17','biodynamic','/ˌbaɪəʊdaɪˈnæmɪk/','adjective','생명역동적인','Relating to a holistic approach to farming that treats the farm as a living system.','The estate farms using strict {biodynamic} principles.','그 와이너리는 엄격한 생명역동 원칙에 따라 농사를 짓고 있어요.','biodynamic','C2','cafe',2,'biodynamic farming vineyard natural organic wine'),
('w_cafe_C2_18','remuage','/rəˈmjuːɑːʒ/','noun','르뮈아주 (샴페인 숙성 공정)','The process of gradually turning Champagne bottles to consolidate the sediment.','The cellar master oversees the daily {remuage}.','셀러 마스터가 매일 르뮈아주를 관리해요.','remuage','C2','cafe',3,'remuage champagne riddling bottles cellar'),
('w_cafe_C2_19','disgorgement','/dɪsˈɡɔːrdʒmənt/','noun','데고르주망 (침전물 제거)','The removal of the yeast sediment plug from Champagne bottles.','The vintage date marks the time of {disgorgement}.','빈티지 날짜는 데고르주망 시점을 나타내요.','disgorgement','C2','cafe',3,'disgorgement champagne sediment removal bottle process'),
('w_cafe_C2_20','micro-oxygenation','/ˌmaɪkrəʊ ˌɒksɪdʒəˈneɪʃən/','noun','마이크로산소 주입법','A technique that exposes wine to controlled quantities of oxygen.','{Micro-oxygenation} softens the tannins and stabilizes the color.','마이크로산소 주입법이 타닌을 부드럽게 하고 색을 안정시켜요.','micro-oxygenation','C2','cafe',2,'micro oxygenation wine technique barrel tannin'),
('w_cafe_C2_21','élevage','/ˌeleɪˈvɑːʒ/','noun','엘르바주 (와인 육성)','The stage of winemaking after fermentation, where wine is nurtured to maturity.','The {élevage} in French oak lasts eighteen months.','프렌치 오크에서의 엘르바주는 18개월간 지속돼요.','élevage','C2','cafe',2,'elevage wine barrel french oak aging cellar'),
('w_cafe_C2_22','mouthfeel','/ˈmaʊθfiːl/','noun','마우스필 (입안의 촉감)','The tactile sensations experienced in the mouth when drinking wine.','The wine has a plush, velvety {mouthfeel}.','와인이 풍부하고 벨벳 같은 마우스필을 가지고 있어요.','mouthfeel','C2','cafe',1,'mouthfeel wine velvet texture tasting sensation'),
('w_cafe_C2_23','phenolics','/fɪˈnɒlɪks/','noun','페놀류 (와인 구성 성분)','A group of chemical compounds found in wine that influence color, taste, and stability.','The {phenolics} in this wine need more time to integrate.','이 와인의 페놀류는 융합되려면 더 많은 시간이 필요해요.','phenolics','C2','cafe',2,'phenolics wine chemical color taste stability'),
('w_cafe_C2_24','polyphenols','/ˌpɒliˈfiːnɒlz/','noun','폴리페놀','Compounds with antioxidant properties found abundantly in red wine.','Red wine is praised for its {polyphenols}.','레드 와인은 폴리페놀로 칭찬받아요.','polyphenols','C2','cafe',1,'polyphenols red wine antioxidant health grapes'),
('w_cafe_C2_25','extraction','/ɪkˈstrækʃən/','noun','추출 (와인 양조)','The process of drawing color, tannin, and flavor from grape skins into wine.','Gentle {extraction} preserves the wine''s elegance.','부드러운 추출이 와인의 우아함을 보존해요.','extraction','C2','cafe',2,'extraction wine grapes skins tannin color process'),
('w_cafe_C2_26','terpenes','/ˈtɜːrpiːnz/','noun','테르펜 (향기 성분)','Aromatic compounds in grapes that contribute floral and fruity aromas to wine.','The {terpenes} in Gewürztraminer produce its distinctive rose aroma.','게뷔르츠트라미너의 테르펜이 독특한 장미 향을 만들어요.','terpenes','C2','cafe',2,'terpenes gewurztraminer aroma rose wine floral'),
('w_cafe_C2_27','oxidative aging','/ˈɒksɪdeɪtɪv ˈeɪdʒɪŋ/','noun','산화 숙성','Wine aging that allows contact with oxygen, developing nutty, complex flavors.','Sherry undergoes {oxidative aging} in open barrels.','셰리는 열린 배럴에서 산화 숙성을 거쳐요.','oxidative aging','C2','cafe',2,'oxidative aging sherry barrel nutty complex wine'),
('w_cafe_C2_28','encépagement','/ɒnˌsepɑːʒˈmɒn/','noun','포도 품종 비율','The proportion of different grape varieties used in a wine blend.','The {encépagement} is dominated by Cabernet Sauvignon.','카베르네 소비뇽이 포도 품종 비율을 지배해요.','encépagement','C2','cafe',3,'encepagement grape variety blend proportion bordeaux'),
('w_cafe_C2_29','autolysis','/ɔːˈtɒlɪsɪs/','noun','자가 분해 (샴페인 숙성)','The breakdown of yeast cells that contributes to a wine''s bready, creamy character.','Long {autolysis} gives this champagne a brioche-like quality.','오랜 자가 분해가 이 샴페인에 브리오슈 같은 품질을 부여해요.','autolysis','C2','cafe',2,'autolysis champagne yeast bready creamy aging'),
('w_cafe_C2_30','assemblage','/əˈsɒmbliːdʒ/','noun','아상블라주 (혼합)','The art of blending different wines or grape varieties to create the final cuvée.','The winemaker''s skill is revealed in the {assemblage}.','와인 메이커의 기술이 아상블라주에서 드러나요.','assemblage','C2','cafe',1,'assemblage blending wine varieties cellar winemaker'),
('w_cafe_C2_31','volatile esters','/ˈvɒlətaɪl ˈestərz/','noun','휘발성 에스테르','Compounds that contribute fruity and floral aromas to wine.','The {volatile esters} in this Riesling are brilliantly expressive.','이 리슬링의 휘발성 에스테르가 눈부시게 표현적이에요.','volatile esters','C2','cafe',2,'volatile esters riesling aroma fruity floral wine'),
('w_cafe_C2_32','cru','/kruː/','noun','크뤼 (특정 포도밭)','A term for a vineyard or group of vineyards recognized for producing superior wine.','This is a Grand {Cru} Burgundy.','이것은 그랑 크뤼 부르고뉴예요.','cru','C2','cafe',1,'grand cru burgundy vineyard classified wine superior'),
('w_cafe_C2_33','négociant','/neɪˈɡɒʃɪənt/','noun','네고시앙 (와인 중개상)','A wine merchant who buys grapes or wine from growers to blend and bottle.','The {négociant} purchased juice from several domaines.','네고시앙이 여러 도멘에서 와인 원액을 구입했어요.','négociant','C2','cafe',2,'negociant merchant wine buyer burgundy bottle'),
('w_cafe_C2_34','bâtonnage','/bɑːtɒˈnɑːʒ/','noun','바토나주 (효모 찌꺼기 젓기)','The process of stirring wine lees to add richness and texture.','Weekly {bâtonnage} enriches the texture of this Chardonnay.','주 1회 바토나주가 이 샤르도네의 질감을 풍부하게 해줘요.','bâtonnage','C2','cafe',2,'batonnage stirring lees chardonnay texture barrel'),
('w_cafe_C2_35','microbiome','/ˈmaɪkrəʊbaɪəʊm/','noun','미생물군 (발효 환경)','The community of microorganisms present in a fermentation environment.','Each winery''s {microbiome} is unique and shapes its wines.','각 와이너리의 미생물군은 고유하며 와인의 특성을 형성해요.','microbiome','C2','cafe',2,'microbiome winery fermentation unique bacteria yeast')
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_A1_01','A table for two, please.','두 명이에요.','A table for two','식당에 들어갈 때 인원수를 말하는 가장 자연스러운 표현이에요.','자리 안내','A1','cafe','pattern',NULL,1),
('s_cafe_A1_02','Can I see the menu, please?','메뉴판 볼 수 있을까요?','Can I see','레스토랑에서 주문 전에 메뉴를 요청하는 가장 기본적인 표현이에요.','메뉴 요청','A1','cafe','pattern',NULL,2),
('s_cafe_A1_03','I''ll have this one, please.','이걸로 주세요.','I''ll have','메뉴를 손으로 가리키며 주문할 때 쓰는 가장 간단한 표현이에요.','주문','A1','cafe','pattern',NULL,3),
('s_cafe_A1_04','Is this seat taken?','이 자리 비어 있나요?','Is this seat taken','카페나 식당에서 빈자리를 확인할 때 쓰는 기본 표현이에요.','자리 확인','A1','cafe','pattern',NULL,4),
('s_cafe_A1_05','How much is this?','이거 얼마예요?','How much is','가격을 물어볼 때 쓰는 가장 기본적인 표현이에요.','가격 문의','A1','cafe','pattern',NULL,5),
('s_cafe_A1_06','The bill, please.','계산서 주세요.','The bill, please','식사 후 계산을 요청하는 가장 간결한 표현이에요.','계산 요청','A1','cafe','pattern',NULL,6),
('s_cafe_A1_07','This is delicious!','정말 맛있어요!','This is delicious','음식이 맛있을 때 바로 칭찬할 수 있는 가장 자연스러운 표현이에요.','음식 칭찬','A1','cafe','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_A2_01','What do you recommend?','무엇을 추천하시나요?','What do you recommend','웨이터에게 추천 메뉴를 물어볼 때 쓰는 가장 자연스러운 표현이에요.','메뉴 추천 문의','A2','cafe','pattern',NULL,1),
('s_cafe_A2_02','Can I get this to go, please?','포장으로 주실 수 있나요?','to go','"to go"는 포장을 의미하는 미국식 표현이에요. 영국에서는 "takeaway"를 써요.','포장 요청','A2','cafe','pattern',NULL,2),
('s_cafe_A2_03','Is there anything without meat?','고기가 안 들어간 메뉴가 있나요?','without meat','식이 제한이 있을 때 특정 재료를 제외한 메뉴를 물어보는 표현이에요.','채식 문의','A2','cafe','pattern',NULL,3),
('s_cafe_A2_04','Could we split the bill?','계산을 따로 할 수 있나요?','split the bill','여러 명이 함께 식사 후 각자 계산하고 싶을 때 쓰는 표현이에요.','계산 분리','A2','cafe','pattern',NULL,4),
('s_cafe_A2_05','Can I have a refill, please?','리필 해주실 수 있나요?','a refill','음료나 물이 비었을 때 다시 채워달라고 요청하는 표현이에요.','리필 요청','A2','cafe','pattern',NULL,5),
('s_cafe_A2_06','How long is the wait?','얼마나 기다려야 하나요?','How long is the wait','식당이 꽉 찼을 때 대기 시간을 묻는 표현이에요.','대기 시간 문의','A2','cafe','pattern',NULL,6),
('s_cafe_A2_07','Do you have a vegetarian option?','채식 메뉴가 있나요?','a vegetarian option','채식주의자이거나 고기를 먹지 않을 때 메뉴를 확인하는 표현이에요.','채식 메뉴 확인','A2','cafe','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_B1_01','What do you recommend for someone who doesn''t eat meat?','고기를 먹지 않는 사람에게는 무엇을 추천하시나요?','recommend for someone who','"recommend for someone who ~"는 조건에 맞는 추천을 구할 때 쓰는 표현이에요.','맞춤 추천 요청','B1','cafe','pattern',NULL,1),
('s_cafe_B1_02','I have a nut allergy — could you check the ingredients?','견과류 알레르기가 있어서 재료를 확인해 주실 수 있나요?','I have a nut allergy','알레르기를 직접적으로 알려주는 것이 안전을 위해 중요해요. 이 표현을 기억해 두세요.','알레르기 고지','B1','cafe','pattern',NULL,2),
('s_cafe_B1_03','Could you make it without onions, please?','양파 없이 만들어 주실 수 있나요?','make it without','특정 재료를 빼달라고 할 때 "make it without ~" 패턴이 유용해요.','재료 제외 요청','B1','cafe','pattern',NULL,3),
('s_cafe_B1_04','Is the kitchen able to accommodate dietary restrictions?','식이 제한에 맞춰 조리가 가능한가요?','accommodate dietary restrictions','"accommodate"는 요구를 수용한다는 뜻으로 레스토랑 맥락에서 자연스러운 표현이에요.','식이 제한 문의','B1','cafe','pattern',NULL,4),
('s_cafe_B1_05','Could I substitute the fries for a salad?','감자튀김 대신 샐러드로 바꿀 수 있나요?','substitute the fries for','"substitute A for B"는 A를 B로 교체한다는 표현이에요. 메뉴 커스터마이즈에 유용해요.','메뉴 변경 요청','B1','cafe','pattern',NULL,5),
('s_cafe_B1_06','I think there''s a mistake in the bill.','계산서에 실수가 있는 것 같아요.','I think there''s a mistake','"I think"를 앞에 붙이면 직접적인 항의보다 훨씬 예의 바르게 들려요.','계산서 오류 지적','B1','cafe','pattern',NULL,6),
('s_cafe_B1_07','What''s the house specialty today?','오늘의 특선 요리는 무엇인가요?','the house specialty','레스토랑에서 셰프가 자신 있는 요리를 물어볼 때 쓰는 표현이에요.','특선 요리 문의','B1','cafe','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_B2_01','The dish has a beautiful balance of acidity and richness.','이 요리는 산미와 풍미의 균형이 아름다워요.','balance of acidity and richness','음식의 맛의 균형을 묘사할 때 "balance of"를 활용하면 세련되게 들려요.','요리 묘사','B2','cafe','pattern',NULL,1),
('s_cafe_B2_02','Would you be able to suggest a wine pairing for this dish?','이 요리에 어울리는 와인 페어링을 추천해 주실 수 있나요?','suggest a wine pairing','"Would you be able to..."는 정중한 요청의 표현이에요. 고급 레스토랑에서 유용해요.','와인 페어링 요청','B2','cafe','pattern',NULL,2),
('s_cafe_B2_03','The sauce has a lovely depth of flavor with just a hint of smokiness.','소스에 훈연향이 살짝 감도는 깊은 풍미가 있어요.','depth of flavor with a hint of','"a hint of"는 풍미가 약간 느껴진다는 뜻의 세련된 표현이에요.','요리 평가','B2','cafe','pattern',NULL,3),
('s_cafe_B2_04','I noticed the menu focuses heavily on locally sourced, seasonal produce.','메뉴가 로컬 식재료와 제철 재료를 중심으로 구성된 것 같아요.','locally sourced, seasonal produce','레스토랑의 철학을 인식하고 표현할 줄 아는 것은 미식가의 언어예요.','레스토랑 철학 언급','B2','cafe','pattern',NULL,4),
('s_cafe_B2_05','The texture of the mousse is incredibly light — it almost dissolves on the palate.','무스의 식감이 믿을 수 없을 만큼 가벼워요. 입안에서 녹아버리는 것 같아요.','dissolves on the palate','"on the palate"은 "입안에서"라는 뜻으로 음식 리뷰에서 자주 쓰는 표현이에요.','디저트 묘사','B2','cafe','pattern',NULL,5),
('s_cafe_B2_06','Could you tell me more about the provenance of the ingredients?','재료의 산지에 대해 더 알려주실 수 있나요?','provenance of the ingredients','좋은 레스토랑에서는 재료의 출처를 자랑스럽게 이야기해요. 이 질문으로 대화를 유도하세요.','재료 출처 문의','B2','cafe','pattern',NULL,6),
('s_cafe_B2_07','I think the fermentation adds a wonderful complexity to the bread.','발효 과정이 빵에 훌륭한 복잡성을 더해주는 것 같아요.','fermentation adds a wonderful complexity','음식 제조 과정을 이해하고 표현하는 것은 B2 수준의 핵심 역량이에요.','요리 과정 언급','B2','cafe','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_C1_01','The mise en place here is impeccable — every element of the dish arrives perfectly timed.','여기의 미장 플라스는 완벽해요. 요리의 모든 요소가 정확한 타이밍에 나와요.','mise en place is impeccable','미장 플라스는 요리 전 준비를 뜻해요. 레스토랑의 전문성을 높이 평가할 때 쓰는 표현이에요.','레스토랑 평론','C1','cafe','pattern',NULL,1),
('s_cafe_C1_02','The tasting menu does a remarkable job of showcasing the terroir of this region.','테이스팅 메뉴가 이 지역의 테루아를 탁월하게 보여주고 있어요.','showcasing the terroir','"terroir"는 원래 와인 용어지만 요리에서도 지역의 환경과 특색을 표현할 때 써요.','테이스팅 메뉴 평가','C1','cafe','pattern',NULL,2),
('s_cafe_C1_03','The charcuterie board is a study in contrast — the saltiness of the cured meats beautifully offsets the sweetness of the compote.','샤르퀴트리 보드는 대비의 예술이에요. 염장 고기의 짠맛이 콩포트의 단맛을 아름답게 상쇄해요.','a study in contrast','"a study in ~"은 어떤 특성의 완벽한 예시를 뜻하는 표현이에요.','음식 묘사','C1','cafe','pattern',NULL,3),
('s_cafe_C1_04','I appreciate how the reduction ties all the elements of the dish together.','리덕션이 요리의 모든 요소를 하나로 묶어주는 방식이 마음에 들어요.','the reduction ties all the elements together','"ties together"는 요소들을 통합한다는 뜻으로 요리 평론에서 유용한 표현이에요.','요리 기법 평론','C1','cafe','pattern',NULL,4),
('s_cafe_C1_05','Could you walk me through the foraging philosophy behind this seasonal menu?','이 시즌 메뉴의 채집 철학에 대해 설명해 주실 수 있나요?','walk me through the foraging philosophy','"walk me through"는 단계별로 설명해 달라는 뜻이에요. 지적 호기심을 표현하는 세련된 표현이에요.','레스토랑 철학 탐구','C1','cafe','pattern',NULL,5),
('s_cafe_C1_06','The Michelin inspector would certainly appreciate the restraint shown in the plating.','미슐랭 심사위원이라면 플레이팅의 절제미를 분명히 높이 평가할 거예요.','restraint shown in the plating','"restraint in plating"은 과하지 않은 절제된 플레이팅을 뜻해요. 파인 다이닝의 핵심 미학이에요.','파인 다이닝 평론','C1','cafe','pattern',NULL,6),
('s_cafe_C1_07','The sous vide preparation ensures a consistency that would be impossible to achieve with traditional methods.','수비드 조리법으로 전통 방식으로는 불가능한 일관성을 달성해요.','ensures a consistency that would be impossible','"ensures a consistency"는 균일한 품질을 보장한다는 뜻이에요.','조리 기법 설명','C1','cafe','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_cafe_C2_01','The malolactic fermentation gives this Chardonnay a buttery, almost creamy quality that beautifully complements the lobster bisque.','유산 발효가 이 샤르도네에 버터 같은 크리미한 품질을 부여해서 바닷가재 비스크와 완벽하게 어울려요.','malolactic fermentation gives a buttery quality','유산 발효는 사과산을 젖산으로 전환하는 과정이에요. 샤르도네의 크리미한 특성의 원인이 돼요.','와인 페어링 설명','C2','cafe','pattern',NULL,1),
('s_cafe_C2_02','The high tannin structure of this Barolo demands either a fatty red meat or a good decade of cellaring to soften its edges.','이 바롤로의 강한 타닌 구조는 기름진 적색육이나 10년의 셀러링을 필요로 해요.','high tannin structure demands','타닌은 와인의 수렴성을 만드는 폴리페놀 화합물이에요. 음식 페어링의 핵심 요소예요.','와인 전문 평론','C2','cafe','pattern',NULL,2),
('s_cafe_C2_03','The organoleptic assessment reveals a wine of extraordinary complexity — layers of terroir expressing themselves with each successive sip.','관능 평가에서 놀라운 복잡성을 가진 와인이 드러나요. 한 모금씩 마실 때마다 테루아의 층위가 표현돼요.','organoleptic assessment reveals','관능 평가(organoleptic assessment)는 시각, 후각, 미각을 통한 종합적 와인 평가예요.','와인 관능 평가','C2','cafe','pattern',NULL,3),
('s_cafe_C2_04','The appellation laws in Champagne strictly regulate the permitted varieties, yield per hectare, and minimum aging on lees.','샴페인의 원산지 명칭 법률은 허용 품종, 헥타르당 수확량, 효모 찌꺼기 위 최소 숙성 기간을 엄격히 규제해요.','appellation laws strictly regulate','원산지 명칭(appellation) 법률은 와인의 품질과 정체성을 보호하기 위한 법적 장치예요.','와인 원산지 명칭 설명','C2','cafe','pattern',NULL,4),
('s_cafe_C2_05','The chef''s application of spherification transforms a classic ponzu into tiny caviar pearls that burst with umami on the palate.','셰프의 구형화 기법이 클래식 폰즈를 입안에서 감칠맛이 터지는 작은 캐비어 구슬로 변환시켜요.','spherification transforms into caviar pearls','구형화는 분자 요리의 대표 기법으로 액체를 얇은 막으로 감싸 캐비어 형태로 만들어요.','분자 요리 묘사','C2','cafe','pattern',NULL,5),
('s_cafe_C2_06','What distinguishes a Grand Cru from a Premier Cru in Burgundy is ultimately a question of terroir specificity and the geological composition of the soil.','부르고뉴에서 그랑 크뤼와 프리미에 크뤼를 구별하는 것은 결국 테루아의 특수성과 토양의 지질학적 구성의 문제예요.','distinguishes Grand Cru from Premier Cru','그랑 크뤼와 프리미에 크뤼는 부르고뉴의 포도밭 등급 체계예요. 토양과 위치가 핵심이에요.','와인 등급 설명','C2','cafe','pattern',NULL,6),
('s_cafe_C2_07','The biodynamic viticulture practiced here treats the entire estate as a self-sustaining organism, eschewing synthetic inputs in favor of astronomical planting calendars and herbal preparations.','여기서 시행하는 생명역동 포도 재배는 합성 투입물 대신 천문학적 식재 달력과 허브 제제를 선호하며 전체 부동산을 자급자족하는 유기체로 취급해요.','biodynamic viticulture treats the entire estate as a self-sustaining organism','생명역동 농업은 루돌프 슈타이너의 철학에 기반한 총체적 유기 농업 접근법이에요.','생명역동 농업 설명','C2','cafe','pattern',NULL,7)
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_A1_01','sunny','/ˈsʌni/','adjective','화창한','Bright with sunlight and clear skies.','It''s a {sunny} day today.','오늘은 화창한 날이에요.','sunny','A1','weather',1,'sunny day blue sky bright'),
('w_weather_A1_02','rainy','/ˈreɪni/','adjective','비가 오는','Having a lot of rain.','I don''t like {rainy} weather.','저는 비 오는 날씨를 별로 좋아하지 않아요.','rainy','A1','weather',1,'rainy day puddles umbrella'),
('w_weather_A1_03','hot','/hɒt/','adjective','더운, 뜨거운','Having a high temperature.','It is very {hot} outside today.','오늘 밖이 정말 더워요.','hot','A1','weather',1,'hot summer sun heat'),
('w_weather_A1_04','cold','/koʊld/','adjective','추운, 차가운','Having a low temperature.','The weather is {cold} in January.','1월에는 날씨가 추워요.','cold','A1','weather',1,'cold winter snow frost'),
('w_weather_A1_05','windy','/ˈwɪndi/','adjective','바람이 부는','With a lot of wind.','It is very {windy} today.','오늘 바람이 많이 불어요.','windy','A1','weather',1,'windy trees blowing leaves'),
('w_weather_A1_06','cloudy','/ˈklaʊdi/','adjective','흐린','Covered with clouds.','The sky is {cloudy} this morning.','오늘 아침 하늘이 흐려요.','cloudy','A1','weather',1,'cloudy sky grey overcast'),
('w_weather_A1_07','snow','/snoʊ/','noun','눈','Frozen water that falls from the sky as soft white flakes.','The children love to play in the {snow}.','아이들은 눈 속에서 노는 걸 좋아해요.','snow','A1','weather',1,'snow white winter landscape'),
('w_weather_A1_08','warm','/wɔːrm/','adjective','따뜻한','At a comfortably high temperature.','Spring weather is usually {warm}.','봄 날씨는 보통 따뜻해요.','warm','A1','weather',1,'warm sunshine spring flowers'),
('w_weather_A1_09','cool','/kuːl/','adjective','선선한, 시원한','Pleasantly low in temperature.','The evening air feels {cool}.','저녁 공기가 선선하게 느껴져요.','cool','A1','weather',1,'cool breeze evening nature'),
('w_weather_A1_10','weather','/ˈweðər/','noun','날씨','The state of the atmosphere at a place and time.','What is the {weather} like today?','오늘 날씨가 어때요?','weather','A1','weather',1,'weather sky clouds sun'),
('w_weather_A1_11','rain','/reɪn/','noun','비','Water that falls from clouds as drops.','There will be {rain} this afternoon.','오늘 오후에 비가 올 거예요.','rain','A1','weather',1,'rain drops falling puddle'),
('w_weather_A1_12','sun','/sʌn/','noun','태양, 햇빛','The star that gives light and heat to the Earth.','The {sun} is very bright today.','오늘 햇빛이 정말 밝아요.','sun','A1','weather',1,'sun bright sky yellow'),
('w_weather_A1_13','wind','/wɪnd/','noun','바람','Air moving from one place to another.','The {wind} is blowing hard tonight.','오늘 밤 바람이 세게 불고 있어요.','wind','A1','weather',1,'wind trees branches blowing'),
('w_weather_A1_14','cloud','/klaʊd/','noun','구름','A white or grey mass in the sky made of water drops.','There are big {cloud}s in the sky.','하늘에 커다란 구름이 있어요.','cloud','A1','weather',2,'cloud white sky fluffy'),
('w_weather_A1_15','ice','/aɪs/','noun','얼음, 빙판','Frozen water.','Be careful — there is {ice} on the road.','조심하세요. 도로에 빙판이 있어요.','ice','A1','weather',2,'ice frozen road winter'),
('w_weather_A1_16','wet','/wet/','adjective','젖은, 비 오는','Covered with water or another liquid.','My shoes got {wet} in the rain.','빗속에서 신발이 젖었어요.','wet','A1','weather',2,'wet rain shoes puddle'),
('w_weather_A1_17','dry','/draɪ/','adjective','건조한','Free from moisture or liquid.','This summer has been very {dry}.','이번 여름은 정말 건조했어요.','dry','A1','weather',2,'dry cracked earth desert'),
('w_weather_A1_18','storm','/stɔːrm/','noun','폭풍','A period of bad weather with strong winds and rain.','A big {storm} hit the coast last night.','어젯밤 해안에 큰 폭풍이 왔어요.','storm','A1','weather',2,'storm dark clouds lightning'),
('w_weather_A1_19','umbrella','/ʌmˈbrelə/','noun','우산','A device for keeping off rain.','Don''t forget to bring your {umbrella}.','우산 가져가는 거 잊지 마세요.','umbrella','A1','weather',2,'umbrella rain protection'),
('w_weather_A1_20','coat','/koʊt/','noun','코트, 외투','A long outer garment worn to stay warm.','You should wear a {coat} today.','오늘은 코트를 입는 게 좋겠어요.','coat','A1','weather',2,'coat winter warm clothing'),
('w_weather_A1_21','season','/ˈsiːzən/','noun','계절','One of the four parts of the year: spring, summer, autumn, winter.','Summer is my favourite {season}.','여름이 제가 가장 좋아하는 계절이에요.','season','A1','weather',2,'season four spring summer autumn winter'),
('w_weather_A1_22','spring','/sprɪŋ/','noun','봄','The season between winter and summer.','The flowers bloom in {spring}.','봄에 꽃이 피어요.','spring','A1','weather',2,'spring flowers blossoms green'),
('w_weather_A1_23','summer','/ˈsʌmər/','noun','여름','The warmest season of the year.','It is very hot in {summer}.','여름에는 정말 더워요.','summer','A1','weather',2,'summer beach hot sunny'),
('w_weather_A1_24','winter','/ˈwɪntər/','noun','겨울','The coldest season of the year.','I love drinking hot cocoa in {winter}.','저는 겨울에 핫초코 마시는 걸 좋아해요.','winter','A1','weather',2,'winter snow cold cosy'),
('w_weather_A1_25','outside','/ˌaʊtˈsaɪd/','adverb','밖에, 야외에','In or to the open air.','It is raining {outside}.','밖에 비가 오고 있어요.','outside','A1','weather',3,'outside rain street'),
('w_weather_A1_26','sky','/skaɪ/','noun','하늘','The region of the atmosphere seen from Earth.','The {sky} is blue and clear today.','오늘 하늘이 파랗고 맑아요.','sky','A1','weather',3,'sky blue clear horizon'),
('w_weather_A1_27','temperature','/ˈtemprɪtʃər/','noun','기온, 온도','The degree of heat or cold measured on a scale.','The {temperature} will drop tonight.','오늘 밤 기온이 떨어질 거예요.','temperature','A1','weather',3,'temperature thermometer weather'),
('w_weather_A1_28','fog','/fɒɡ/','noun','안개','A thick cloud of water droplets near the ground.','Drive slowly because of the {fog}.','안개 때문에 천천히 운전하세요.','fog','A1','weather',3,'fog misty morning road'),
('w_weather_A1_29','sunshine','/ˈsʌnʃaɪn/','noun','햇살','Direct light from the sun.','We had lovely {sunshine} all weekend.','주말 내내 멋진 햇살이 가득했어요.','sunshine','A1','weather',3,'sunshine bright warm light'),
('w_weather_A1_30','rainbow','/ˈreɪnboʊ/','noun','무지개','An arch of colours in the sky after rain.','Look at that beautiful {rainbow}!','저 예쁜 무지개 좀 봐요!','rainbow','A1','weather',3,'rainbow colourful sky after rain'),
('w_weather_A1_31','hail','/heɪl/','noun','우박','Pellets of frozen rain that fall from the sky.','The {hail} damaged many car rooftops.','우박이 많은 차 지붕을 망가뜨렸어요.','hail','A1','weather',3,'hail ice pellets storm'),
('w_weather_A1_32','thunder','/ˈθʌndər/','noun','천둥','The loud noise heard during a storm.','The {thunder} woke me up last night.','어젯밤에 천둥 소리에 잠이 깼어요.','thunder','A1','weather',3,'thunder storm lightning'),
('w_weather_A1_33','lightning','/ˈlaɪtnɪŋ/','noun','번개','A flash of bright light in the sky during a storm.','We saw {lightning} in the distance.','멀리서 번개가 보였어요.','lightning','A1','weather',3,'lightning flash storm night'),
('w_weather_A1_34','flood','/flʌd/','noun','홍수','An overflow of water over normally dry land.','Heavy rain caused a {flood} in the town.','폭우로 마을에 홍수가 났어요.','flood','A1','weather',3,'flood water street submerged'),
('w_weather_A1_35','autumn','/ˈɔːtəm/','noun','가을','The season between summer and winter.','The leaves turn red in {autumn}.','가을에 나뭇잎이 빨갛게 물들어요.','autumn','A1','weather',3,'autumn leaves red orange fall')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_A2_01','forecast','/ˈfɔːrkæst/','noun','일기 예보','A statement about what the weather will be like in the future.','The {forecast} says it will snow tomorrow.','예보에서 내일 눈이 온다고 해요.','forecast','A2','weather',1,'forecast weather map prediction'),
('w_weather_A2_02','temperature','/ˈtemprɪtʃər/','noun','기온','The degree of heat or coldness measured on a specific scale.','The {temperature} reached 35 degrees today.','오늘 기온이 35도까지 올랐어요.','temperature','A2','weather',1,'temperature thermometer heat'),
('w_weather_A2_03','humid','/ˈhjuːmɪd/','adjective','습한','Having a lot of water vapour in the air.','Seoul is very {humid} in August.','서울은 8월에 정말 습해요.','humid','A2','weather',1,'humid sticky air tropics'),
('w_weather_A2_04','thunder','/ˈθʌndər/','noun','천둥','The loud rumbling sound that follows lightning.','There was a big {thunder} storm overnight.','밤새 엄청난 천둥 번개가 쳤어요.','thunder','A2','weather',1,'thunder storm dark sky'),
('w_weather_A2_05','lightning','/ˈlaɪtnɪŋ/','noun','번개','A flash of light caused by electricity in the atmosphere.','The {lightning} lit up the whole sky.','번개가 하늘 전체를 밝혔어요.','lightning','A2','weather',1,'lightning bolt night sky'),
('w_weather_A2_06','fog','/fɒɡ/','noun','안개','A dense cloud of tiny water droplets near the ground.','The airport was closed because of thick {fog}.','짙은 안개로 공항이 폐쇄됐어요.','fog','A2','weather',1,'fog thick misty road'),
('w_weather_A2_07','frost','/frɒst/','noun','서리','A thin layer of ice that forms on surfaces when temperatures drop below freezing.','There was {frost} on the grass this morning.','오늘 아침 풀잎에 서리가 내렸어요.','frost','A2','weather',1,'frost ice grass morning'),
('w_weather_A2_08','drizzle','/ˈdrɪzəl/','noun','이슬비, 부슬비','Light rain falling in very small drops.','It''s just a light {drizzle} — you don''t need an umbrella.','가벼운 이슬비라 우산은 필요 없어요.','drizzle','A2','weather',1,'drizzle light rain mist'),
('w_weather_A2_09','breeze','/briːz/','noun','산들바람','A gentle, light wind.','A cool {breeze} came in through the window.','시원한 산들바람이 창문으로 들어왔어요.','breeze','A2','weather',1,'breeze gentle wind leaves'),
('w_weather_A2_10','shower','/ˈʃaʊər/','noun','소나기','A brief fall of rain.','There will be afternoon {shower}s today.','오늘 오후에 소나기가 내릴 거예요.','shower','A2','weather',2,'shower rain afternoon brief'),
('w_weather_A2_11','overcast','/ˌoʊvərˈkæst/','adjective','잔뜩 흐린','(Of the sky) covered with cloud.','The sky is completely {overcast} today.','오늘 하늘이 완전히 흐려요.','overcast','A2','weather',2,'overcast grey sky clouds'),
('w_weather_A2_12','blizzard','/ˈblɪzərd/','noun','눈보라','A severe snowstorm with strong winds.','The {blizzard} shut down the whole city.','눈보라로 도시 전체가 마비됐어요.','blizzard','A2','weather',2,'blizzard snowstorm winter'),
('w_weather_A2_13','heatwave','/ˈhiːtweɪv/','noun','폭염, 열파','A prolonged period of abnormally hot weather.','Many elderly people suffer during a {heatwave}.','폭염 중에 노인분들이 많이 힘들어하세요.','heatwave','A2','weather',2,'heatwave hot sun dry'),
('w_weather_A2_14','slippery','/ˈslɪpəri/','adjective','미끄러운','Difficult to stand on or hold because of a smooth or wet surface.','The roads are {slippery} after the snow.','눈이 온 후 도로가 미끄러워요.','slippery','A2','weather',2,'slippery road ice winter'),
('w_weather_A2_15','humid','/ˈhjuːmɪd/','adjective','습한, 눅눅한','(Already listed at A2_03 — variant entry for classroom use) Feeling damp and warm.','The air is so {humid} that my hair is frizzy.','공기가 너무 습해서 머리가 부풀었어요.','humid','A2','weather',2,'humid air sticky tropical'),
('w_weather_A2_16','chilly','/ˈtʃɪli/','adjective','쌀쌀한','Unpleasantly cold.','It gets {chilly} in the evening here.','이곳은 저녁에 쌀쌀해져요.','chilly','A2','weather',2,'chilly cold evening autumn'),
('w_weather_A2_17','mild','/maɪld/','adjective','온화한','(Of weather) not extreme; gently warm.','We had a {mild} winter this year.','올해는 겨울이 온화했어요.','mild','A2','weather',2,'mild weather pleasant green'),
('w_weather_A2_18','pour','/pɔːr/','verb','쏟아지다 (비)','(Of rain) to fall heavily.','It is {pour}ing outside right now.','지금 밖에 비가 쏟아지고 있어요.','pouring','A2','weather',2,'pouring rain heavy downpour'),
('w_weather_A2_19','snowfall','/ˈsnoʊfɔːl/','noun','강설, 눈이 내림','Snow falling or the amount of snow that falls.','We had the heaviest {snowfall} in ten years.','10년 만에 가장 많은 눈이 내렸어요.','snowfall','A2','weather',2,'snowfall winter white landscape'),
('w_weather_A2_20','freezing','/ˈfriːzɪŋ/','adjective','얼어붙을 듯이 추운','Extremely cold.','It''s absolutely {freezing} outside today.','오늘 밖이 정말 얼어붙을 듯이 추워요.','freezing','A2','weather',2,'freezing cold ice winter'),
('w_weather_A2_21','humid','/ˈhjuːmɪd/','adjective','습기 많은','Moist and warm, making one feel uncomfortable.','The {humid} heat is very tiring.','습한 더위는 정말 지치게 해요.','humid','A2','weather',3,'humid tropical air green'),
('w_weather_A2_22','gust','/ɡʌst/','noun','돌풍','A sudden strong blast of wind.','A sudden {gust} blew my hat off.','갑자기 불어온 돌풍이 모자를 날려버렸어요.','gust','A2','weather',3,'gust wind strong sudden'),
('w_weather_A2_23','damp','/dæmp/','adjective','축축한','Slightly wet in an unpleasant way.','The ground is still {damp} from last night''s rain.','어젯밤 비로 땅이 아직 축축해요.','damp','A2','weather',3,'damp wet ground rain'),
('w_weather_A2_24','muggy','/ˈmʌɡi/','adjective','무더운, 후덥지근한','Unpleasantly warm and humid.','The weather is so {muggy} today.','오늘 날씨가 너무 무더워요.','muggy','A2','weather',3,'muggy hot humid summer'),
('w_weather_A2_25','clear','/klɪər/','adjective','맑은 (날씨)','(Of the sky or weather) free from cloud or rain.','The weather looks {clear} this afternoon.','오늘 오후에는 날씨가 맑겠어요.','clear','A2','weather',3,'clear sky blue sunny'),
('w_weather_A2_26','sunny spell','/ˈsʌni spel/','noun phrase','맑음 구간','A short period of sunshine.','There will be a {sunny spell} in the morning.','오전에 잠깐 맑겠어요.','sunny spell','A2','weather',3,'sunny spell bright morning'),
('w_weather_A2_27','wind chill','/wɪnd tʃɪl/','noun','체감 온도 (바람으로 낮아진)','The cooling effect of wind on the temperature felt on skin.','The {wind chill} makes it feel like minus fifteen.','체감 온도는 영하 15도예요.','wind chill','A2','weather',3,'wind chill cold winter'),
('w_weather_A2_28','rainfall','/ˈreɪnfɔːl/','noun','강우량','The amount of rain that falls in an area.','This month''s {rainfall} has been above average.','이달 강우량이 평균보다 높아요.','rainfall','A2','weather',3,'rainfall rain gauge measurement'),
('w_weather_A2_29','thunder cloud','/ˈθʌndər klaʊd/','noun','먹구름, 뇌운','A large dark cloud associated with thunder and lightning.','A huge {thunder cloud} is forming in the west.','서쪽에 큰 먹구름이 형성되고 있어요.','thunder cloud','A2','weather',3,'thunder cloud dark storm'),
('w_weather_A2_30','icy','/ˈaɪsi/','adjective','빙판인, 얼음처럼 차가운','Covered with ice or extremely cold.','Watch out — the pavement is {icy}.','조심하세요. 인도가 빙판이에요.','icy','A2','weather',3,'icy pavement winter slippery'),
('w_weather_A2_31','downpour','/ˈdaʊnpɔːr/','noun','폭우','A heavy fall of rain.','We were caught in a sudden {downpour}.','갑자기 쏟아지는 폭우를 맞았어요.','downpour','A2','weather',3,'downpour heavy rain street'),
('w_weather_A2_32','cloudburst','/ˈklaʊdbɜːrst/','noun','집중 호우','A sudden, very heavy shower.','A {cloudburst} flooded the underpass.','집중 호우로 지하차도가 침수됐어요.','cloudburst','A2','weather',3,'cloudburst flash flood rain'),
('w_weather_A2_33','mist','/mɪst/','noun','엷은 안개, 박무','A thin layer of cloud low over land.','The valley was covered in morning {mist}.','계곡이 아침 안개에 덮였어요.','mist','A2','weather',3,'mist morning valley soft'),
('w_weather_A2_34','sleet','/sliːt/','noun','진눈깨비','A mixture of rain and snow.','It''s not quite snow — it''s {sleet}.','완전한 눈은 아니고 진눈깨비예요.','sleet','A2','weather',3,'sleet rain snow mix winter'),
('w_weather_A2_35','hazy','/ˈheɪzi/','adjective','뿌연, 안개 낀','Covered by a thin mist or haze.','The mountains look {hazy} in the distance.','산이 멀리서 뿌옇게 보여요.','hazy','A2','weather',3,'hazy sky mountains distance mist')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_B1_01','humidity','/hjuːˈmɪdɪti/','noun','습도','The amount of water vapour in the air.','The {humidity} today makes it feel hotter than it is.','오늘 습도 때문에 실제보다 더 덥게 느껴져요.','humidity','B1','weather',1,'humidity sticky tropical air'),
('w_weather_B1_02','precipitation','/prɪˌsɪpɪˈteɪʃən/','noun','강수량, 강수','Water that falls from the sky as rain, snow, sleet, or hail.','Monthly {precipitation} levels have been unusually high.','월 강수량이 예년에 비해 유독 높아요.','precipitation','B1','weather',1,'precipitation rain snow measurement'),
('w_weather_B1_03','visibility','/ˌvɪzɪˈbɪlɪti/','noun','가시거리, 시정','The distance at which objects can be clearly seen.','Poor {visibility} is making driving dangerous.','낮은 가시거리로 운전이 위험해요.','visibility','B1','weather',1,'visibility fog road distance'),
('w_weather_B1_04','heatwave','/ˈhiːtweɪv/','noun','폭염','A prolonged period of abnormally hot weather.','The {heatwave} broke records across the country.','폭염이 전국적으로 기록을 깨뜨렸어요.','heatwave','B1','weather',1,'heatwave extreme heat dry summer'),
('w_weather_B1_05','drought','/draʊt/','noun','가뭄','A long period of very little or no rain.','Farmers are struggling because of the {drought}.','농부들이 가뭄 때문에 힘들어하고 있어요.','drought','B1','weather',1,'drought dry cracked earth'),
('w_weather_B1_06','blizzard','/ˈblɪzərd/','noun','눈보라','A severe snowstorm with strong, blinding winds.','Flights were cancelled due to the {blizzard}.','눈보라로 항공편이 취소됐어요.','blizzard','B1','weather',1,'blizzard snowstorm white out'),
('w_weather_B1_07','overcast','/ˌoʊvərˈkæst/','adjective','잔뜩 흐린','(Of the sky) covered with a thick layer of grey cloud.','It''s {overcast} today, so bring a jacket.','오늘 날씨가 흐리니까 재킷을 챙기세요.','overcast','B1','weather',1,'overcast grey sky heavy clouds'),
('w_weather_B1_08','mild','/maɪld/','adjective','온화한','Pleasantly warm and without extreme cold or heat.','The climate here is {mild} all year round.','이곳 기후는 연중 온화해요.','mild','B1','weather',1,'mild weather pleasant countryside'),
('w_weather_B1_09','chilly','/ˈtʃɪli/','adjective','쌀쌀한','Noticeably cold, causing discomfort.','It''s quite {chilly} in the shade.','그늘에는 꽤 쌀쌀해요.','chilly','B1','weather',1,'chilly autumn cold evening'),
('w_weather_B1_10','tropical','/ˈtrɒpɪkəl/','adjective','열대의','Relating to the tropics; very hot and humid.','Seoul summers feel almost {tropical} these days.','요즘 서울 여름은 거의 열대처럼 느껴져요.','tropical','B1','weather',1,'tropical hot humid lush green'),
('w_weather_B1_11','pressure','/ˈpreʃər/','noun','기압','The force exerted by the weight of air.','Low {pressure} systems often bring bad weather.','저기압 시스템은 주로 나쁜 날씨를 가져와요.','pressure','B1','weather',2,'pressure barometer atmosphere'),
('w_weather_B1_12','front','/frʌnt/','noun','전선 (기상)','A boundary between two different air masses.','A cold {front} is moving in from the north.','북쪽에서 한랭 전선이 이동하고 있어요.','front','B1','weather',2,'weather front map cold warm'),
('w_weather_B1_13','gale','/ɡeɪl/','noun','강풍, 돌풍','A very strong wind.','The {gale} blew tiles off the roof.','강풍이 지붕의 기와를 날려버렸어요.','gale','B1','weather',2,'gale strong wind damage'),
('w_weather_B1_14','thunder storm','/ˈθʌndər stɔːrm/','noun','뇌우','A storm with thunder and lightning.','The {thunder storm} last night was terrifying.','어젯밤 뇌우는 정말 무서웠어요.','thunderstorm','B1','weather',2,'thunderstorm lightning dark sky'),
('w_weather_B1_15','scorching','/ˈskɔːrtʃɪŋ/','adjective','작열하는, 몹시 더운','Very hot; burning hot.','The {scorching} sun drove everyone indoors.','작열하는 태양에 모두 실내로 들어갔어요.','scorching','B1','weather',2,'scorching sun hot desert'),
('w_weather_B1_16','breezy','/ˈbriːzi/','adjective','바람이 솔솔 부는','Pleasantly windy.','It''s sunny and {breezy} — perfect for a picnic.','햇살이 나고 바람이 솔솔 불어요. 소풍하기 딱 좋아요.','breezy','B1','weather',2,'breezy wind sunny outdoor'),
('w_weather_B1_17','humid subtropical','/hjuːˈmɪd ˌsʌbˈtrɒpɪkəl/','adjective phrase','고온 다습한 아열대의','Describing a climate type with hot, humid summers and mild winters.','Korea has a {humid subtropical} summer.','한국의 여름은 고온 다습한 아열대성이에요.','humid subtropical','B1','weather',3,'humid subtropical summer green'),
('w_weather_B1_18','slippery road','/ˈslɪpəri roʊd/','noun phrase','미끄러운 도로','A road surface made dangerous by rain or ice.','Slow down — there are {slippery road}s ahead.','속도를 줄이세요. 앞에 미끄러운 도로가 있어요.','slippery road','B1','weather',3,'slippery road rain ice winter'),
('w_weather_B1_19','pollen count','/ˈpɒlən kaʊnt/','noun','꽃가루 농도','A measure of the amount of pollen in the air.','The {pollen count} is very high today.','오늘 꽃가루 농도가 매우 높아요.','pollen count','B1','weather',3,'pollen flowers spring allergy'),
('w_weather_B1_20','heat index','/hiːt ˈɪndeks/','noun','체감 온도 (습도 반영)','A measure of how hot it feels when humidity is combined with temperature.','The {heat index} is 42 degrees today.','오늘 체감 온도가 42도예요.','heat index','B1','weather',3,'heat index summer humidity'),
('w_weather_B1_21','wind speed','/wɪnd spiːd/','noun','풍속','The rate at which air is moving.','The {wind speed} reached 80 km/h during the storm.','폭풍 동안 풍속이 80km/h에 달했어요.','wind speed','B1','weather',3,'wind speed meter anemometer'),
('w_weather_B1_22','barometer','/bəˈrɒmɪtər/','noun','기압계','An instrument for measuring atmospheric pressure.','The {barometer} is falling — bad weather is coming.','기압계가 내려가고 있어요. 날씨가 나빠질 거예요.','barometer','B1','weather',3,'barometer instrument pressure'),
('w_weather_B1_23','UV index','/juː viː ˈɪndeks/','noun','자외선 지수','A measure of the ultraviolet radiation reaching Earth''s surface.','The {UV index} is very high — use sunscreen.','자외선 지수가 매우 높아요. 선크림을 바르세요.','UV index','B1','weather',3,'UV index sun protection summer'),
('w_weather_B1_24','flood warning','/flʌd ˈwɔːrnɪŋ/','noun','홍수 경보','An official alert that flooding is expected.','The government issued a {flood warning} for the region.','정부가 해당 지역에 홍수 경보를 발령했어요.','flood warning','B1','weather',3,'flood warning alert rain'),
('w_weather_B1_25','air quality','/eər ˈkwɒlɪti/','noun','공기질','The degree to which the air is clean or polluted.','The {air quality} index is poor today.','오늘 공기질 지수가 나쁘네요.','air quality','B1','weather',3,'air quality pollution sky'),
('w_weather_B1_26','smog','/smɒɡ/','noun','스모그','A mixture of smoke and fog causing poor air quality.','The city was covered in thick {smog}.','도시 전체가 짙은 스모그에 덮였어요.','smog','B1','weather',3,'smog pollution city haze'),
('w_weather_B1_27','dew point','/djuː pɔɪnt/','noun','이슬점','The temperature at which air becomes saturated with moisture.','When the {dew point} is high, the air feels sticky.','이슬점이 높으면 공기가 끈적하게 느껴져요.','dew point','B1','weather',3,'dew point morning grass droplet'),
('w_weather_B1_28','wind direction','/wɪnd dɪˈrekʃən/','noun','풍향','The direction from which the wind is blowing.','The {wind direction} has shifted to the north.','풍향이 북쪽으로 바뀌었어요.','wind direction','B1','weather',3,'wind direction compass vane'),
('w_weather_B1_29','severe weather','/sɪˈvɪər ˈweðər/','noun phrase','악천후','Dangerous or extreme weather conditions.','Schools closed due to {severe weather}.','악천후로 학교들이 문을 닫았어요.','severe weather','B1','weather',3,'severe weather alert storm damage'),
('w_weather_B1_30','shelter','/ˈʃeltər/','noun','피난처, 대피소','A place giving protection from bad weather.','Everyone ran to {shelter} when the storm hit.','폭풍이 오자 모두 대피소로 달려갔어요.','shelter','B1','weather',3,'shelter protection storm rain'),
('w_weather_B1_31','frost warning','/frɒst ˈwɔːrnɪŋ/','noun','서리 주의보','An advisory that frost may form overnight.','Farmers covered their crops after the {frost warning}.','서리 주의보 후 농부들이 작물을 덮었어요.','frost warning','B1','weather',3,'frost warning cold night crops'),
('w_weather_B1_32','advisory','/ədˈvaɪzəri/','noun','기상 주의보','An official warning about potential weather hazards.','A travel {advisory} was issued for the mountain roads.','산악 도로에 대한 여행 주의보가 발령됐어요.','advisory','B1','weather',3,'advisory warning weather official'),
('w_weather_B1_33','trough','/trɒf/','noun','기압골','An elongated region of low atmospheric pressure.','A weather {trough} is bringing rain to the west.','기압골이 서쪽 지역에 비를 가져오고 있어요.','trough','B1','weather',3,'trough pressure weather map'),
('w_weather_B1_34','ridge','/rɪdʒ/','noun','고기압 마루, 능선','An elongated region of high atmospheric pressure.','A high pressure {ridge} will keep the weather fine.','고기압 마루가 날씨를 좋게 유지해줄 거예요.','ridge','B1','weather',3,'ridge high pressure map clear'),
('w_weather_B1_35','seasonal','/ˈsiːzənəl/','adjective','계절적인, 계절에 따른','Related to or varying with the seasons.','The {seasonal} rains usually begin in June.','계절성 우기는 보통 6월에 시작해요.','seasonal','B1','weather',3,'seasonal rain monsoon cycle')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_B2_01','meteorology','/ˌmiːtiəˈrɒlədʒi/','noun','기상학','The scientific study of the atmosphere and weather.','She studied {meteorology} at university.','그녀는 대학에서 기상학을 공부했어요.','meteorology','B2','weather',1,'meteorology science atmosphere'),
('w_weather_B2_02','atmospheric','/ˌætməsˈferɪk/','adjective','대기의','Relating to the atmosphere of the Earth.','{Atmospheric} pressure affects how we feel.','대기압은 우리의 기분에 영향을 미쳐요.','atmospheric','B2','weather',1,'atmospheric pressure sky science'),
('w_weather_B2_03','cyclone','/ˈsaɪkloʊn/','noun','사이클론, 열대 저기압','A system of winds rotating inward to an area of low pressure.','The {cyclone} caused widespread flooding.','사이클론이 광범위한 홍수를 일으켰어요.','cyclone','B2','weather',1,'cyclone storm tropical spinning'),
('w_weather_B2_04','monsoon','/ˌmɒnˈsuːn/','noun','몬순, 우기','A seasonal wind bringing heavy rain to South and Southeast Asia.','The {monsoon} season in India lasts from June to September.','인도의 몬순 시즌은 6월부터 9월까지예요.','monsoon','B2','weather',1,'monsoon rain India tropical'),
('w_weather_B2_05','arid','/ˈærɪd/','adjective','건조한, 불모의','Having very little or no rain; very dry.','Parts of central Australia are extremely {arid}.','호주 중부 일부는 매우 건조해요.','arid','B2','weather',1,'arid desert dry cracked'),
('w_weather_B2_06','subtropical','/ˌsʌbˈtrɒpɪkəl/','adjective','아열대의','Relating to regions adjacent to the tropics.','The island has a {subtropical} climate.','그 섬은 아열대 기후예요.','subtropical','B2','weather',1,'subtropical warm humid island'),
('w_weather_B2_07','barometric','/ˌbærəˈmetrɪk/','adjective','기압의','Relating to barometric (atmospheric) pressure.','A drop in {barometric} pressure usually means rain is coming.','기압이 떨어지면 보통 비가 올 신호예요.','barometric','B2','weather',1,'barometric pressure instrument science'),
('w_weather_B2_08','gradient','/ˈɡreɪdiənt/','noun','기압 경도','A difference in atmospheric pressure over distance.','A steep pressure {gradient} produces stronger winds.','가파른 기압 경도는 더 강한 바람을 만들어요.','gradient','B2','weather',2,'gradient pressure wind map'),
('w_weather_B2_09','phenomenon','/fəˈnɒmɪnən/','noun','현상','An observable event or occurrence in the natural world.','The aurora is a fascinating weather {phenomenon}.','오로라는 매혹적인 기상 현상이에요.','phenomenon','B2','weather',2,'phenomenon aurora natural event'),
('w_weather_B2_10','climate','/ˈklaɪmɪt/','noun','기후','The long-term pattern of weather in a particular area.','The {climate} of the Mediterranean is warm and dry.','지중해의 기후는 따뜻하고 건조해요.','climate','B2','weather',2,'climate map zone Mediterranean'),
('w_weather_B2_11','precipitation pattern','/prɪˌsɪpɪˈteɪʃən ˈpætərn/','noun','강수 패턴','The regular distribution of rainfall across time and space.','Climate change is altering {precipitation pattern}s worldwide.','기후 변화가 전 세계 강수 패턴을 바꾸고 있어요.','precipitation patterns','B2','weather',2,'precipitation pattern rainfall map'),
('w_weather_B2_12','high pressure system','/haɪ ˈpreʃər ˈsɪstəm/','noun','고기압','An area of atmospheric pressure higher than its surroundings, typically bringing fine weather.','A {high pressure system} is keeping the skies clear.','고기압이 하늘을 맑게 유지하고 있어요.','high pressure system','B2','weather',2,'high pressure system clear sky map'),
('w_weather_B2_13','low pressure system','/loʊ ˈpreʃər ˈsɪstəm/','noun','저기압','An area of atmospheric pressure lower than its surroundings, often bringing clouds and rain.','The {low pressure system} brought three days of rain.','저기압이 3일 동안 비를 가져왔어요.','low pressure system','B2','weather',2,'low pressure system clouds rain map'),
('w_weather_B2_14','typhoon','/taɪˈfuːn/','noun','태풍','A tropical cyclone occurring in the western Pacific Ocean.','The {typhoon} made landfall on Friday evening.','태풍이 금요일 저녁에 상륙했어요.','typhoon','B2','weather',2,'typhoon storm Pacific coast'),
('w_weather_B2_15','intertropical convergence zone','/ˌɪntərˌtrɒpɪkəl kənˈvɜːrdʒəns zoʊn/','noun','열대 수렴대','A belt near the equator where northeast and southeast trade winds meet.','The {intertropical convergence zone} shifts seasonally.','열대 수렴대는 계절에 따라 이동해요.','ITCZ','B2','weather',3,'ITCZ equator tropical clouds'),
('w_weather_B2_16','convection','/kənˈvekʃən/','noun','대류','The transfer of heat through the movement of fluids or gases.','Afternoon thunderstorms are caused by {convection}.','오후 뇌우는 대류 현상으로 발생해요.','convection','B2','weather',2,'convection heat rising air'),
('w_weather_B2_17','jet stream','/dʒet striːm/','noun','제트 기류','A fast-flowing, narrow air current in the upper atmosphere.','The {jet stream} guides storm tracks across continents.','제트 기류가 대륙을 가로지르는 폭풍 경로를 안내해요.','jet stream','B2','weather',2,'jet stream atmosphere map wind'),
('w_weather_B2_18','trade winds','/treɪd wɪndz/','noun','무역풍','Steady winds blowing toward the equator from the northeast or southeast.','Sailors relied on the {trade winds} for ocean crossings.','선원들은 대양 횡단에 무역풍을 이용했어요.','trade winds','B2','weather',2,'trade winds map ocean sailing'),
('w_weather_B2_19','humidity index','/hjuːˈmɪdɪti ˈɪndeks/','noun','습도 지수','A combined measure of temperature and humidity.','The {humidity index} today feels oppressive.','오늘 습도 지수가 매우 불쾌하게 느껴져요.','humidity index','B2','weather',3,'humidity index summer measurement'),
('w_weather_B2_20','polar vortex','/ˈpoʊlər ˈvɔːrteks/','noun','극 소용돌이','A large area of low pressure and cold air surrounding the Earth''s poles.','The {polar vortex} brought extreme cold to the Midwest.','극 소용돌이가 중서부에 극심한 추위를 가져왔어요.','polar vortex','B2','weather',2,'polar vortex cold winter Arctic'),
('w_weather_B2_21','heat dome','/hiːt doʊm/','noun','열돔','A region of high atmospheric pressure that traps hot air below.','The {heat dome} pushed temperatures above 40°C.','열돔이 기온을 40도 이상으로 끌어올렸어요.','heat dome','B2','weather',2,'heat dome high pressure extreme heat'),
('w_weather_B2_22','wind shear','/wɪnd ʃɪər/','noun','윈드 시어, 바람 전단','A variation in wind speed or direction over a short distance.','{Wind shear} can be dangerous for aircraft on approach.','바람 전단은 착륙 중인 항공기에 위험할 수 있어요.','wind shear','B2','weather',3,'wind shear aviation danger'),
('w_weather_B2_23','evapotranspiration','/ɪˌvæpəʊˌtrænsˌpɪˈreɪʃən/','noun','증발산','The combined process of evaporation from soil and transpiration from plants.','High {evapotranspiration} dries out the soil quickly.','높은 증발산은 토양을 빠르게 건조시켜요.','evapotranspiration','B2','weather',3,'evapotranspiration plants soil dry'),
('w_weather_B2_24','air mass','/eər mæs/','noun','기단','A large body of air with uniform temperature and humidity.','A cold {air mass} is moving in from Siberia.','시베리아에서 차가운 기단이 이동하고 있어요.','air mass','B2','weather',2,'air mass cold warm map'),
('w_weather_B2_25','squall','/skwɔːl/','noun','스콜, 돌발성 강풍','A sudden, violent gust of wind often with rain or snow.','A {squall} swept across the harbour.','항구를 가로질러 스콜이 몰아쳤어요.','squall','B2','weather',3,'squall sudden storm sea'),
('w_weather_B2_26','microclimate','/ˈmaɪkrəʊˌklaɪmɪt/','noun','미기후','The climate of a small, specific area differing from the surrounding region.','The valley has its own {microclimate} due to the hills.','그 계곡은 언덕 때문에 자체적인 미기후를 가지고 있어요.','microclimate','B2','weather',3,'microclimate valley urban local'),
('w_weather_B2_27','atmosphere','/ˈætməsfɪər/','noun','대기, 대기권','The layer of gases surrounding the Earth.','Human activity is altering the {atmosphere}.','인간 활동이 대기를 변화시키고 있어요.','atmosphere','B2','weather',2,'atmosphere Earth layers science'),
('w_weather_B2_28','temperature anomaly','/ˈtemprɪtʃər əˈnɒməli/','noun','기온 편차','A deviation of temperature from a long-term average.','Scientists recorded a 1.5°C global {temperature anomaly}.','과학자들이 전 세계적으로 1.5도의 기온 편차를 기록했어요.','temperature anomaly','B2','weather',2,'temperature anomaly global warming chart'),
('w_weather_B2_29','condensation','/ˌkɒndənˈseɪʃən/','noun','응결','The process by which water vapour becomes liquid water.','{Condensation} on windows is caused by indoor humidity.','창문의 물방울은 실내 습기로 인한 응결이에요.','condensation','B2','weather',3,'condensation water drops window'),
('w_weather_B2_30','evaporation','/ɪˌvæpəˈreɪʃən/','noun','증발','The process of liquid water turning into water vapour.','{Evaporation} from the lake cools the surrounding air.','호수에서의 증발이 주변 공기를 식혀요.','evaporation','B2','weather',3,'evaporation lake water vapour'),
('w_weather_B2_31','cloud seeding','/klaʊd ˈsiːdɪŋ/','noun','인공 강우','A weather modification technique to induce precipitation.','Dubai uses {cloud seeding} to increase rainfall.','두바이는 강수량을 늘리기 위해 인공 강우를 사용해요.','cloud seeding','B2','weather',3,'cloud seeding aircraft rain artificial'),
('w_weather_B2_32','isobar','/ˈaɪsəʊbɑːr/','noun','등압선','A line on a weather map connecting places of equal atmospheric pressure.','The closely packed {isobar}s indicate strong winds.','촘촘히 모인 등압선은 강한 바람을 나타내요.','isobars','B2','weather',3,'isobar weather map lines pressure'),
('w_weather_B2_33','isotherm','/ˈaɪsəʊθɜːrm/','noun','등온선','A line on a map connecting places of equal temperature.','The {isotherm}s show the north-south temperature gradient.','등온선은 남북 기온 경도를 보여줘요.','isotherms','B2','weather',3,'isotherm temperature map gradient'),
('w_weather_B2_34','anticyclone','/ˌæntiˈsaɪkloʊn/','noun','고기압','A system of winds that spiral outward from a high-pressure centre.','The {anticyclone} over Siberia brings dry, cold air.','시베리아의 고기압이 건조하고 차가운 공기를 가져와요.','anticyclone','B2','weather',2,'anticyclone high pressure map'),
('w_weather_B2_35','ocean current','/ˈoʊʃən ˈkʌrənt/','noun','해류','A continuous, directed movement of seawater.','{Ocean current}s redistribute heat around the globe.','해류는 지구 전체에 열을 재분배해요.','ocean currents','B2','weather',2,'ocean current map sea temperature')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_C1_01','climatology','/ˌklaɪməˈtɒlədʒi/','noun','기후학','The scientific study of climate.','{Climatology} provides the data needed for climate policy.','기후학은 기후 정책에 필요한 데이터를 제공해요.','climatology','C1','weather',1,'climatology science data research'),
('w_weather_C1_02','microclimate','/ˈmaɪkrəʊˌklaɪmɪt/','noun','미기후','The climate of a very small or restricted area, often different from the surrounding region.','Urban parks can create their own {microclimate}.','도시 공원은 자체적인 미기후를 만들 수 있어요.','microclimate','C1','weather',1,'microclimate urban park local climate'),
('w_weather_C1_03','inversion','/ɪnˈvɜːrʒən/','noun','기온 역전','A reversal of the normal decrease in temperature with altitude.','A temperature {inversion} trapped pollutants near the ground.','기온 역전이 오염 물질을 지표 근처에 가두었어요.','inversion','C1','weather',1,'temperature inversion smog valley'),
('w_weather_C1_04','stratosphere','/ˈstrætəsfɪər/','noun','성층권','The layer of Earth''s atmosphere above the troposphere, extending to about 50 km.','Volcanic ash can reach the {stratosphere}.','화산재가 성층권에 도달할 수 있어요.','stratosphere','C1','weather',1,'stratosphere atmosphere layers'),
('w_weather_C1_05','El Niño','/el ˈniːnjəʊ/','noun','엘니뇨','A periodic warming of ocean surface temperatures in the central and eastern Pacific.','{El Niño} causes droughts in some regions and floods in others.','엘니뇨는 일부 지역에 가뭄을, 다른 지역에 홍수를 가져와요.','El Niño','C1','weather',1,'El Nino Pacific ocean warming'),
('w_weather_C1_06','anomaly','/əˈnɒməli/','noun','편차, 이상','A deviation from the expected or typical pattern.','Scientists recorded a record temperature {anomaly} last year.','과학자들이 지난해 기록적인 기온 편차를 기록했어요.','anomaly','C1','weather',1,'anomaly temperature record data'),
('w_weather_C1_07','deviation','/ˌdiːviˈeɪʃən/','noun','편차','The amount by which a value differs from a standard or average.','A {deviation} of just 2°C can significantly impact ecosystems.','단 2도의 편차도 생태계에 상당한 영향을 미칠 수 있어요.','deviation','C1','weather',1,'deviation chart statistics climate'),
('w_weather_C1_08','temperate','/ˈtempərɪt/','adjective','온대의, 온화한','Having mild temperatures; moderate in terms of climate.','Korea lies within the {temperate} climate zone.','한국은 온대 기후대에 위치해 있어요.','temperate','C1','weather',1,'temperate zone map climate forest'),
('w_weather_C1_09','oceanic','/ˌoʊʃiˈænɪk/','adjective','해양성의','Relating to or influenced by the ocean.','The UK has an {oceanic} climate with mild, wet winters.','영국은 온화하고 습한 겨울의 해양성 기후예요.','oceanic','C1','weather',1,'oceanic climate UK coast mild'),
('w_weather_C1_10','continental','/ˌkɒntɪˈnentəl/','adjective','대륙성의','Relating to inland areas with extreme temperature variations.','Moscow has a {continental} climate with severe winters.','모스크바는 혹독한 겨울의 대륙성 기후예요.','continental','C1','weather',1,'continental climate map extreme'),
('w_weather_C1_11','thermohaline circulation','/ˌθɜːrməʊˈheɪlaɪn ˌsɜːrkjʊˈleɪʃən/','noun','열염 순환','The global ocean circulation driven by temperature and salinity differences.','The {thermohaline circulation} regulates Europe''s climate.','열염 순환은 유럽의 기후를 조절해요.','thermohaline circulation','C1','weather',2,'thermohaline circulation ocean map'),
('w_weather_C1_12','albedo','/ælˈbiːdəʊ/','noun','알베도 (반사율)','The proportion of light reflected by a surface.','Snow has a high {albedo}, reflecting most sunlight back.','눈은 알베도가 높아 햇빛 대부분을 반사해요.','albedo','C1','weather',2,'albedo snow ice reflection'),
('w_weather_C1_13','radiative forcing','/ˈreɪdiətɪv ˈfɔːrsɪŋ/','noun','복사 강제력','The change in energy flux in the atmosphere caused by natural or anthropogenic factors.','CO₂ increases {radiative forcing}, warming the planet.','CO₂ 증가는 복사 강제력을 높여 지구를 온난화해요.','radiative forcing','C1','weather',2,'radiative forcing CO2 energy atmosphere'),
('w_weather_C1_14','permafrost','/ˈpɜːrməfrɒst/','noun','영구 동토층','Ground that remains frozen for at least two consecutive years.','Melting {permafrost} releases methane into the atmosphere.','녹는 영구 동토층은 대기 중으로 메탄을 방출해요.','permafrost','C1','weather',2,'permafrost frozen ground Arctic tundra'),
('w_weather_C1_15','tipping point','/ˈtɪpɪŋ pɔɪnt/','noun','임계점','The critical threshold at which a small change causes a major system shift.','Many scientists warn we are near a climate {tipping point}.','많은 과학자들이 우리가 기후 임계점에 가까워지고 있다고 경고해요.','tipping point','C1','weather',2,'tipping point climate threshold'),
('w_weather_C1_16','aerosol','/ˈeərəsɒl/','noun','에어로졸 (대기 입자)','Tiny particles suspended in the atmosphere that affect climate and visibility.','Volcanic {aerosol}s can cool the planet temporarily.','화산 에어로졸은 일시적으로 지구를 냉각시킬 수 있어요.','aerosols','C1','weather',3,'aerosol particles atmosphere volcano'),
('w_weather_C1_17','meridional flow','/məˈrɪdiənəl fləʊ/','noun','경도 방향 흐름','Large-scale atmospheric circulation moving north or south.','Strong {meridional flow} brings Arctic air to mid-latitudes.','강한 경도 방향 흐름은 북극 공기를 중위도로 가져와요.','meridional flow','C1','weather',3,'meridional flow atmosphere circulation'),
('w_weather_C1_18','zonal flow','/ˈzoʊnəl fləʊ/','noun','대상 흐름','Large-scale atmospheric circulation moving east or west.','Dominant {zonal flow} keeps weather systems moving quickly.','지배적인 대상 흐름은 기상 시스템을 빠르게 이동시켜요.','zonal flow','C1','weather',3,'zonal flow west east wind pattern'),
('w_weather_C1_19','feedback loop','/ˈfiːdbæk luːp/','noun','피드백 루프','A process where an initial change triggers further changes that amplify or reduce the original effect.','Ice melt creates a warming {feedback loop}.','빙하 녹음은 온난화 피드백 루프를 만들어요.','feedback loop','C1','weather',2,'feedback loop ice melt climate'),
('w_weather_C1_20','stratospheric ozone','/ˌstrætəˈsferɪk ˈoʊzoʊn/','noun','성층권 오존','Ozone found in the stratosphere that shields Earth from UV radiation.','Protecting {stratospheric ozone} is critical for life on Earth.','성층권 오존을 보호하는 것은 지구 생명체에 매우 중요해요.','stratospheric ozone','C1','weather',2,'ozone layer stratosphere UV protection'),
('w_weather_C1_21','teleconnection','/ˈteliːkəˌnekʃən/','noun','원격 상관','A statistical relationship between weather patterns in distant regions.','El Niño is the most studied {teleconnection} on Earth.','엘니뇨는 지구에서 가장 많이 연구된 원격 상관이에요.','teleconnection','C1','weather',3,'teleconnection El Nino global pattern'),
('w_weather_C1_22','runoff','/ˈrʌnɒf/','noun','유출수','Water that flows off land into streams or rivers, especially after rain.','Heavy rainfall increases surface {runoff} and flood risk.','폭우는 지표 유출수와 홍수 위험을 높여요.','runoff','C1','weather',3,'runoff rain river flood surface'),
('w_weather_C1_23','glacier retreat','/ˈɡlæsiər rɪˈtriːt/','noun phrase','빙하 후퇴','The shrinking of a glacier due to melting exceeding snowfall accumulation.','Scientists are documenting {glacier retreat} worldwide.','과학자들이 전 세계 빙하 후퇴를 기록하고 있어요.','glacier retreat','C1','weather',2,'glacier retreat melting ice mountain'),
('w_weather_C1_24','sea level rise','/siː ˈlevəl raɪz/','noun phrase','해수면 상승','The increase in the average level of the world''s oceans.','{Sea level rise} threatens low-lying coastal cities.','해수면 상승은 저지대 해안 도시들을 위협해요.','sea level rise','C1','weather',2,'sea level rise coastal flood city'),
('w_weather_C1_25','carbon cycle','/ˈkɑːrbən ˈsaɪkəl/','noun','탄소 순환','The biogeochemical cycle by which carbon is exchanged among Earth''s spheres.','Forests play a key role in the {carbon cycle}.','숲은 탄소 순환에서 핵심적인 역할을 해요.','carbon cycle','C1','weather',2,'carbon cycle forest atmosphere CO2'),
('w_weather_C1_26','greenhouse effect','/ˈɡriːnhaʊs ɪˈfekt/','noun','온실 효과','The process by which greenhouse gases trap heat in the atmosphere.','The natural {greenhouse effect} makes Earth habitable.','자연적인 온실 효과는 지구를 살기 좋게 만들어요.','greenhouse effect','C1','weather',2,'greenhouse effect atmosphere heat trap'),
('w_weather_C1_27','ENSO','/ˈensoʊ/','noun','엔소 (엘니뇨 남방진동)','El Niño-Southern Oscillation; a recurring climate pattern across the Pacific.','Scientists monitor {ENSO} to predict seasonal weather.','과학자들은 계절 날씨 예측을 위해 엔소를 모니터링해요.','ENSO','C1','weather',3,'ENSO El Nino La Nina Pacific'),
('w_weather_C1_28','La Niña','/lɑː ˈniːnjə/','noun','라니냐','The cool phase of ENSO, causing cooler-than-average ocean temperatures in the Pacific.','{La Niña} often brings drought to South America.','라니냐는 종종 남미에 가뭄을 가져와요.','La Niña','C1','weather',2,'La Nina Pacific ocean cooling map'),
('w_weather_C1_29','storm surge','/stɔːrm sɜːrdʒ/','noun','폭풍 해일','An abnormal rise in sea level caused by a storm.','The {storm surge} inundated coastal communities.','폭풍 해일이 해안 마을을 침수시켰어요.','storm surge','C1','weather',2,'storm surge coastal flood hurricane'),
('w_weather_C1_30','deep convection','/diːp kənˈvekʃən/','noun','심층 대류','Vigorous upward movement of air extending to great heights, driving intense storms.','{Deep convection} in the tropics generates most of the world''s rainfall.','열대 지역의 심층 대류가 전 세계 강수량의 대부분을 만들어요.','deep convection','C1','weather',3,'deep convection tropical clouds thunderstorm'),
('w_weather_C1_31','geostrophic wind','/ˌdʒiːəˈstrɒfɪk wɪnd/','noun','지균풍','A wind blowing parallel to isobars, resulting from balance between pressure gradient and Coriolis forces.','The {geostrophic wind} approximates winds above the boundary layer.','지균풍은 경계층 위쪽의 바람을 근사치로 나타내요.','geostrophic wind','C1','weather',3,'geostrophic wind map isobar'),
('w_weather_C1_32','coriolis effect','/ˌkɒriˈoʊlɪs ɪˈfekt/','noun','코리올리 효과','The deflection of moving air or water due to Earth''s rotation.','The {Coriolis effect} causes storms to spin.','코리올리 효과는 폭풍을 회전하게 만들어요.','Coriolis effect','C1','weather',2,'Coriolis effect rotation earth wind'),
('w_weather_C1_33','orographic lift','/ˌɒrəˈɡræfɪk lɪft/','noun','지형성 상승','The forced ascent of air over a mountain range, often causing precipitation.','{Orographic lift} makes the windward side of mountains much wetter.','지형성 상승이 산의 바람받이 쪽을 훨씬 습하게 만들어요.','orographic lift','C1','weather',3,'orographic lift mountain rain windward'),
('w_weather_C1_34','atmospheric river','/ˌætməsˈferɪk ˈrɪvər/','noun','대기천','A narrow band of concentrated moisture transport in the atmosphere.','An {atmospheric river} caused catastrophic flooding.','대기천이 대규모 홍수를 일으켰어요.','atmospheric river','C1','weather',2,'atmospheric river moisture flood map'),
('w_weather_C1_35','climate sensitivity','/ˈklaɪmɪt senˈsɪtɪvɪti/','noun','기후 민감도','The expected rise in global temperature caused by a doubling of atmospheric CO₂.','Estimating {climate sensitivity} is a key challenge in research.','기후 민감도 추정은 연구의 핵심 과제예요.','climate sensitivity','C1','weather',2,'climate sensitivity CO2 temperature rise')
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_weather_C2_01','paleoclimatology','/ˌpeɪliəʊˌklaɪməˈtɒlədʒi/','noun','고기후학','The study of past climates through geological, biological, and chemical evidence.','{Paleoclimatology} reveals how Earth''s climate has changed over millennia.','고기후학은 수천 년에 걸친 지구 기후 변화를 밝혀줘요.','paleoclimatology','C2','weather',1,'paleoclimatology ice core fossil climate'),
('w_weather_C2_02','anthropogenic','/ˌænθrəpəˈdʒenɪk/','adjective','인위적인, 인간 활동에 의한','Originating in human activity.','Most of today''s climate change is {anthropogenic}.','오늘날 기후 변화의 대부분은 인위적인 것이에요.','anthropogenic','C2','weather',1,'anthropogenic pollution industry CO2'),
('w_weather_C2_03','biogeochemical','/ˌbaɪəʊˌdʒiːəʊˈkemɪkəl/','adjective','생물 지구 화학적','Relating to the chemical, biological, and geological cycles of the Earth.','{Biogeochemical} cycles control how nutrients move through ecosystems.','생물 지구 화학적 순환은 생태계의 영양소 이동을 조절해요.','biogeochemical','C2','weather',1,'biogeochemical cycle carbon nitrogen'),
('w_weather_C2_04','teleconnection','/ˈteliːkəˌnekʃən/','noun','원격 상관','A correlation between weather or climate anomalies separated by large distances.','{Teleconnection}s help forecast droughts months in advance.','원격 상관은 몇 달 전에 가뭄을 예측하는 데 도움을 줘요.','teleconnections','C2','weather',1,'teleconnection global climate pattern map'),
('w_weather_C2_05','thermohaline','/ˌθɜːrməʊˈheɪlaɪn/','adjective','열염 (온도와 염도에 의한)','Relating to ocean circulation driven by temperature and salinity differences.','The {thermohaline} conveyor belt could weaken with freshwater influx.','담수 유입으로 열염 컨베이어 벨트가 약해질 수 있어요.','thermohaline','C2','weather',1,'thermohaline ocean circulation belt'),
('w_weather_C2_06','albedo','/ælˈbiːdəʊ/','noun','알베도','The fraction of solar energy reflected from the Earth back into space.','Reduced {albedo} from melting ice accelerates warming.','빙하 녹음으로 인한 알베도 감소가 온난화를 가속해요.','albedo','C2','weather',1,'albedo reflection ice surface'),
('w_weather_C2_07','radiative forcing','/ˈreɪdiətɪv ˈfɔːrsɪŋ/','noun','복사 강제력','The imbalance in Earth''s energy budget caused by changes in greenhouse gas concentrations.','Increased {radiative forcing} is the primary driver of climate change.','증가된 복사 강제력이 기후 변화의 주요 원인이에요.','radiative forcing','C2','weather',1,'radiative forcing greenhouse energy'),
('w_weather_C2_08','permafrost','/ˈpɜːrməfrɒst/','noun','영구 동토층','Ground in polar regions that remains continuously frozen for two or more years.','The thawing of {permafrost} releases ancient carbon stores.','영구 동토층의 해빙은 오래된 탄소 저장량을 방출해요.','permafrost','C2','weather',1,'permafrost thaw Arctic tundra methane'),
('w_weather_C2_09','dendroclimatology','/ˌdendrəʊˌklaɪməˈtɒlədʒi/','noun','수목 연륜 기후학','The study of past climates by analysing the annual growth rings of trees.','{Dendroclimatology} can reconstruct 500 years of climate data.','수목 연륜 기후학은 500년간의 기후 데이터를 재구성할 수 있어요.','dendroclimatology','C2','weather',1,'dendroclimatology tree rings climate'),
('w_weather_C2_10','proxy','/ˈprɒksi/','noun','대리 지표','Indirect evidence used to reconstruct past climate conditions.','Ice cores are the most valuable climate {proxy}.','빙하 코어는 가장 귀중한 기후 대리 지표예요.','proxy','C2','weather',1,'proxy ice core climate data'),
('w_weather_C2_11','insolation','/ˌɪnsəˈleɪʃən/','noun','일사량','The amount of solar radiation reaching a surface.','Seasonal changes in {insolation} drive the annual temperature cycle.','일사량의 계절적 변화가 연간 기온 순환을 이끌어요.','insolation','C2','weather',2,'insolation solar radiation surface earth'),
('w_weather_C2_12','Milankovitch cycles','/mɪˈlæŋkəvɪtʃ ˈsaɪkəlz/','noun','밀란코비치 주기','Long-term variations in Earth''s orbital parameters that affect climate.','{Milankovitch cycles} explain the timing of ice ages.','밀란코비치 주기는 빙하기 시기를 설명해요.','Milankovitch cycles','C2','weather',2,'Milankovitch cycles orbit earth ice age'),
('w_weather_C2_13','cryosphere','/ˈkraɪəsfɪər/','noun','빙권','The frozen water parts of Earth, including glaciers, ice sheets, and sea ice.','The {cryosphere} is shrinking at an unprecedented rate.','빙권이 전례 없는 속도로 축소되고 있어요.','cryosphere','C2','weather',2,'cryosphere ice glacier Arctic Antarctic'),
('w_weather_C2_14','hydrological cycle','/ˌhaɪdrəˈlɒdʒɪkəl ˈsaɪkəl/','noun','물 순환 (수문 순환)','The continuous movement of water through Earth''s systems.','Climate change is intensifying the {hydrological cycle}.','기후 변화가 물 순환을 강화하고 있어요.','hydrological cycle','C2','weather',2,'hydrological cycle water rain evaporation'),
('w_weather_C2_15','stratospheric warming','/ˌstrætəˈsferɪk ˈwɔːrmɪŋ/','noun','성층권 온난화','A sudden increase in stratospheric temperature that can disrupt polar vortex.','Sudden {stratospheric warming} events weaken the polar vortex.','갑작스러운 성층권 온난화 사건이 극 소용돌이를 약화시켜요.','stratospheric warming','C2','weather',3,'stratospheric warming polar vortex'),
('w_weather_C2_16','carbon sequestration','/ˈkɑːrbən ˌsiːkwɪˈstreɪʃən/','noun','탄소 격리','The long-term storage of carbon dioxide to reduce greenhouse gas concentrations.','Reforestation is a key strategy for {carbon sequestration}.','산림 복원은 탄소 격리의 핵심 전략이에요.','carbon sequestration','C2','weather',2,'carbon sequestration forest trees soil'),
('w_weather_C2_17','cloud albedo effect','/klaʊd ælˈbiːdəʊ ɪˈfekt/','noun','구름 알베도 효과','The cooling influence of clouds reflecting solar radiation back into space.','The {cloud albedo effect} is a major source of uncertainty in climate models.','구름 알베도 효과는 기후 모델의 주요 불확실성 원인이에요.','cloud albedo effect','C2','weather',3,'cloud albedo reflection climate model'),
('w_weather_C2_18','isotope analysis','/ˈaɪsətəʊp əˈnæləsɪs/','noun','동위원소 분석','The use of stable isotope ratios in ice or sediment cores to reconstruct past climates.','{Isotope analysis} revealed a sudden cooling 12,000 years ago.','동위원소 분석으로 12,000년 전의 갑작스러운 냉각이 밝혀졌어요.','isotope analysis','C2','weather',3,'isotope analysis ice core paleoclimate'),
('w_weather_C2_19','biogenic volatile organic compound','/baɪəˈdʒenɪk vəˈlætaɪl ɔːrˈɡænɪk ˈkɒmpaʊnd/','noun','생물 기원 휘발성 유기화합물','Organic chemicals emitted by vegetation that affect air chemistry and cloud formation.','Forests emit {biogenic volatile organic compound}s that influence regional climate.','숲은 지역 기후에 영향을 미치는 생물 기원 휘발성 유기화합물을 방출해요.','BVOCs','C2','weather',3,'BVOC forest emission aerosol'),
('w_weather_C2_20','abrupt climate change','/əˈbrʌpt ˈklaɪmɪt tʃeɪndʒ/','noun','급격한 기후 변화','A large-scale change in the climate system that takes place over a few decades or less.','Evidence shows {abrupt climate change} has occurred many times in Earth''s history.','지구 역사에서 급격한 기후 변화가 여러 번 발생했다는 증거가 있어요.','abrupt climate change','C2','weather',2,'abrupt climate change sudden shift data'),
('w_weather_C2_21','solar irradiance','/ˈsoʊlər ɪˈreɪdiəns/','noun','태양 복사량','The total power of solar energy received per unit area.','Variations in {solar irradiance} are a natural climate driver.','태양 복사량의 변화는 자연적인 기후 요인이에요.','solar irradiance','C2','weather',2,'solar irradiance sun energy measurement'),
('w_weather_C2_22','feedback mechanism','/ˈfiːdbæk ˈmekənɪzəm/','noun','피드백 메커니즘','A process in which the output of a system influences that system''s future behaviour.','Water vapour is a powerful positive {feedback mechanism} in the climate system.','수증기는 기후 시스템에서 강력한 양의 피드백 메커니즘이에요.','feedback mechanism','C2','weather',2,'feedback mechanism climate water vapour'),
('w_weather_C2_23','global mean surface temperature','/ˈɡloʊbəl miːn ˈsɜːrfɪs ˈtemprɪtʃər/','noun','전 지구 평균 지표 기온','The globally averaged temperature of Earth''s surface.','The {global mean surface temperature} has risen by 1.2°C since pre-industrial times.','전 지구 평균 지표 기온은 산업화 이전보다 1.2도 상승했어요.','GMST','C2','weather',2,'global mean temperature chart rise'),
('w_weather_C2_24','forcing agent','/ˈfɔːrsɪŋ ˈeɪdʒənt/','noun','복사 강제 인자','A factor that causes a change in Earth''s energy balance.','Methane is a potent {forcing agent} in climate change.','메탄은 기후 변화에서 강력한 복사 강제 인자예요.','forcing agent','C2','weather',3,'forcing agent methane CO2 climate'),
('w_weather_C2_25','sea ice extent','/siː aɪs ɪkˈstent/','noun','해빙 면적','The total area of the ocean surface covered by sea ice.','Arctic {sea ice extent} is declining faster than predicted.','북극 해빙 면적이 예측보다 빠르게 줄어들고 있어요.','sea ice extent','C2','weather',2,'sea ice Arctic extent satellite'),
('w_weather_C2_26','ice age','/aɪs eɪdʒ/','noun','빙하기','A period of long-term reduction in global temperature resulting in glaciation.','We are currently in an interglacial period of the current {ice age}.','우리는 현재 빙하기의 간빙기에 살고 있어요.','ice age','C2','weather',2,'ice age glacial period Earth'),
('w_weather_C2_27','water vapour feedback','/ˈwɔːtər ˈveɪpər ˈfiːdbæk/','noun','수증기 피드백','The amplification of warming caused by increased water vapour in the atmosphere.','{Water vapour feedback} more than doubles initial warming from CO₂.','수증기 피드백은 CO₂로 인한 초기 온난화를 두 배 이상으로 증폭시켜요.','water vapour feedback','C2','weather',3,'water vapour feedback climate warming'),
('w_weather_C2_28','palaeotemperature','/ˌpeɪliəʊˈtemprɪtʃər/','noun','고대 기온','A reconstructed temperature of a past period inferred from proxy data.','{Palaeotemperature} records from ice cores show rapid swings.','빙하 코어의 고대 기온 기록은 급격한 변동을 보여줘요.','palaeotemperature','C2','weather',3,'palaeotemperature ice core proxy data'),
('w_weather_C2_29','heterogeneous nucleation','/ˌhetərəˈdʒiːniəs ˌnjuːkliˈeɪʃən/','noun','불균일 핵 생성','The formation of ice crystals or water droplets on aerosol particles.','{Heterogeneous nucleation} is the main process forming cloud droplets.','불균일 핵 생성이 구름 물방울 형성의 주요 과정이에요.','heterogeneous nucleation','C2','weather',3,'nucleation cloud droplets aerosol'),
('w_weather_C2_30','integrated assessment model','/ˈɪntɪɡreɪtɪd əˈsesmənt ˈmɒdəl/','noun','통합 평가 모델','A computer model combining climate science and socioeconomic analysis.','{Integrated assessment model}s project warming under different emission pathways.','통합 평가 모델들은 다양한 배출 경로에서의 온난화를 전망해요.','IAM','C2','weather',3,'integrated assessment model climate projection'),
('w_weather_C2_31','carbon budget','/ˈkɑːrbən ˈbʌdʒɪt/','noun','탄소 예산','The maximum amount of CO₂ that can be emitted to stay within a temperature limit.','The world has used most of its 1.5°C {carbon budget}.','세계는 1.5도 탄소 예산의 대부분을 이미 사용했어요.','carbon budget','C2','weather',2,'carbon budget CO2 budget emissions'),
('w_weather_C2_32','emission pathway','/ɪˈmɪʃən ˈpɑːθweɪ/','noun','배출 경로','A trajectory describing future greenhouse gas emissions over time.','Choosing a steep {emission pathway} reduction is critical.','가파른 배출 경로 감소를 선택하는 것이 매우 중요해요.','emission pathway','C2','weather',2,'emission pathway CO2 reduction graph'),
('w_weather_C2_33','net zero','/net ˈzɪərəʊ/','noun','탄소 중립, 넷 제로','A state in which the greenhouse gases emitted are balanced by those removed from the atmosphere.','Many countries have pledged to achieve {net zero} by 2050.','많은 나라들이 2050년까지 탄소 중립 달성을 약속했어요.','net zero','C2','weather',2,'net zero carbon neutral target'),
('w_weather_C2_34','tectonic influence','/tekˈtɒnɪk ˈɪnfluəns/','noun','지각 변동의 영향','The effect of plate movement on long-term climate by reshaping landmasses and sea levels.','{Tectonic influence} shaped Earth''s climate over geological time.','지각 변동의 영향이 지질학적 시간에 걸쳐 지구 기후를 형성했어요.','tectonic influence','C2','weather',3,'tectonic plates climate geology'),
('w_weather_C2_35','deep time climate','/diːp taɪm ˈklaɪmɪt/','noun phrase','심층 시간 기후 (지질학적 기후)','Climate conditions of geological eons, studied through rock and fossil records.','Understanding {deep time climate} helps contextualise modern warming.','심층 시간 기후를 이해하면 현대 온난화를 더 잘 이해할 수 있어요.','deep time climate','C2','weather',3,'deep time climate fossil geology record')
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_A1_01','What''s the weather like today?','오늘 날씨 어때요?','What''s the weather like','"What''s the weather like?"는 날씨를 물을 때 가장 자연스러운 원어민 표현이에요. "How is the weather?"보다 훨씬 자주 쓰여요.','날씨 묻기','A1','weather','pattern',NULL,1),
('s_weather_A1_02','Is it hot or cold outside?','밖에 덥나요, 추운가요?','hot or cold outside','"or"를 사용해 두 가지 선택지를 제시하면 상대방이 대답하기 쉬워요. 날씨를 처음 묻는 기초 표현이에요.','날씨 묻기','A1','weather','pattern',NULL,2),
('s_weather_A1_03','It''s sunny today.','오늘은 화창해요.','It''s sunny','날씨를 말할 때 "It''s + 날씨 형용사" 패턴이 가장 기본이에요. "It"은 특별한 의미 없이 날씨 문장에서 주어로 써요.','날씨 묘사','A1','weather','pattern',NULL,3),
('s_weather_A1_04','It''s raining outside.','밖에 비가 오고 있어요.','It''s raining','동작이 지금 일어나고 있을 때는 "-ing" 형태를 써요. "It rains"보다 "It''s raining"이 지금 이 순간의 날씨를 묘사해요.','날씨 묘사','A1','weather','pattern',NULL,4),
('s_weather_A1_05','Don''t forget your umbrella!','우산 가져가는 거 잊지 마세요!','Don''t forget your umbrella','"Don''t forget your ~!"는 상대방을 걱정해 챙겨주는 표현이에요. 날씨 대화에서 자연스럽게 쓸 수 있어요.','날씨 조언','A1','weather','pattern',NULL,5),
('s_weather_A1_06','What is the weather like in winter?','겨울 날씨는 어때요?','weather like in winter','계절을 붙여 물으면 특정 계절의 날씨 특징을 알 수 있어요. "in + 계절" 조합을 꼭 기억하세요.','계절 날씨 묻기','A1','weather','pattern',NULL,6),
('s_weather_A1_07','It is very cold today, isn''t it?','오늘 정말 춥죠, 그렇지 않나요?','isn''t it','문장 끝에 "isn''t it?"를 붙이면 상대방의 동의를 구하는 부가의문문이 돼요. 영국 영어에서 특히 자주 써요.','날씨 공감 구하기','A1','weather','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_A2_01','The weather is really nice today, don''t you think?','오늘 날씨가 정말 좋죠, 그렇지 않나요?','don''t you think','"don''t you think?"는 상대방의 의견을 자연스럽게 구하는 표현이에요. 날씨 소재로 대화를 시작할 때 유용해요.','날씨 묘사·공감','A2','weather','pattern',NULL,1),
('s_weather_A2_02','It''s getting colder these days.','요즘 점점 추워지고 있어요.','It''s getting colder','"It''s getting + 비교급"은 날씨 변화를 표현하는 핵심 패턴이에요. "warmer", "cloudier", "wetter" 등 다양한 형용사와 함께 써요.','날씨 변화 묘사','A2','weather','pattern',NULL,2),
('s_weather_A2_03','It looks like it''s going to rain.','비가 올 것 같아요.','It looks like it''s going to','"It looks like + 주어 + be going to + 동사"는 눈에 보이는 단서를 바탕으로 날씨를 예측할 때 써요.','날씨 예측','A2','weather','pattern',NULL,3),
('s_weather_A2_04','The forecast says it will be cloudy all day.','예보에서 하루 종일 흐릴 거라고 해요.','The forecast says it will be','"The forecast says ~"는 일기 예보 내용을 전달할 때 쓰는 패턴이에요. 뉴스나 앱 정보를 공유할 때 자연스러워요.','예보 전달','A2','weather','pattern',NULL,4),
('s_weather_A2_05','It was so foggy this morning that I could barely see.','오늘 아침에 너무 안개가 끼어서 잘 보이지 않았어요.','so foggy that I could barely see','"so + 형용사 + that ~" 패턴은 결과를 강조해요. "barely"는 "거의 ~않다"는 뜻으로 부정적 상황을 강조할 때 써요.','날씨 상황 묘사','A2','weather','pattern',NULL,5),
('s_weather_A2_06','The temperature dropped suddenly overnight.','밤 사이에 기온이 갑자기 떨어졌어요.','temperature dropped suddenly overnight','"overnight"는 "밤 사이에"라는 뜻으로, 날씨가 빠르게 변한 상황을 표현할 때 자주 써요.','기온 변화 묘사','A2','weather','pattern',NULL,6),
('s_weather_A2_07','I prefer sunny weather to rainy weather.','저는 비 오는 날보다 화창한 날을 더 좋아해요.','prefer A to B','"prefer A to B"는 "B보다 A를 더 좋아한다"는 표현이에요. 날씨 취향을 말할 때 자연스럽게 쓸 수 있어요.','날씨 선호 표현','A2','weather','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_B1_01','According to the forecast, there''s a high chance of thunderstorms this evening.','예보에 따르면 오늘 저녁 뇌우가 올 확률이 높아요.','According to the forecast','뉴스나 날씨 앱의 정보를 인용할 때 "According to the forecast"를 쓰면 격식 있고 정확하게 들려요.','날씨 예보 전달','B1','weather','pattern',NULL,1),
('s_weather_B1_02','You should layer up — the temperature is expected to drop significantly later.','껴입는 게 좋겠어요. 나중에 기온이 많이 떨어질 거예요.','layer up, expected to drop significantly','"layer up"는 옷을 겹쳐 입으라는 실용적 조언이에요. "expected to"는 예측을 표현하는 격식체 표현이에요.','옷차림 조언','B1','weather','pattern',NULL,2),
('s_weather_B1_03','The humidity is making it feel much hotter than it actually is.','습도 때문에 실제보다 훨씬 더 덥게 느껴져요.','humidity is making it feel','습도가 체감 온도에 영향을 주는 현상을 설명할 때 쓰는 표현이에요. "make + 목적어 + 동사원형" 구조를 활용해요.','날씨 체감 묘사','B1','weather','pattern',NULL,3),
('s_weather_B1_04','I would recommend bringing a light jacket in case the weather changes.','날씨가 변할 경우를 대비해 얇은 재킷을 챙기길 권해요.','in case the weather changes','"in case"는 "~에 대비해서"라는 뜻으로, 예방적 조언을 줄 때 꼭 쓰는 표현이에요.','옷차림 조언','B1','weather','pattern',NULL,4),
('s_weather_B1_05','The weather has been unusually warm for this time of year.','이맘때치고는 날씨가 유난히 따뜻해요.','unusually warm for this time of year','계절 평균과 비교해 현재 날씨가 특이하다고 말할 때 쓰는 표현이에요. "for this time of year"를 꼭 익혀두세요.','날씨 비교 묘사','B1','weather','pattern',NULL,5),
('s_weather_B1_06','There''s a severe weather warning in place for the northern regions.','북부 지역에 악천후 경보가 발령되어 있어요.','severe weather warning in place','"There''s a ~ warning in place"는 공식 기상 경보를 전달하는 뉴스식 표현이에요.','기상 경보 전달','B1','weather','pattern',NULL,6),
('s_weather_B1_07','With the heat index above 40 degrees, outdoor activities are not advisable.','체감 온도가 40도를 넘으니 야외 활동은 권장하지 않아요.','heat index above, not advisable','체감 온도와 건강 권고를 연결하는 실용적 표현이에요. "not advisable"은 공식 권고문에서 자주 등장해요.','폭염 안전 조언','B1','weather','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_B2_01','Climate change is intensifying the frequency and severity of extreme weather events.','기후 변화가 극한 기상 현상의 빈도와 심각성을 증가시키고 있어요.','intensifying the frequency and severity','학술 및 뉴스 토론에서 자주 등장하는 문장 구조예요. "intensify"는 단순히 "심해지다"보다 더 정확하고 강한 표현이에요.','기후 토론','B2','weather','pattern',NULL,1),
('s_weather_B2_02','The monsoon season has become increasingly unpredictable due to shifting weather patterns.','변화하는 기상 패턴으로 인해 몬순 시즌이 점점 더 예측하기 어려워지고 있어요.','increasingly unpredictable due to','"increasingly + 형용사"는 변화의 추세를 강조해요. "due to"는 원인을 격식 있게 표현하는 방법이에요.','기후 변화 토론','B2','weather','pattern',NULL,2),
('s_weather_B2_03','There is growing scientific consensus that anthropogenic emissions are driving global warming.','인간 활동으로 인한 배출이 지구 온난화를 촉진하고 있다는 과학적 공감대가 커지고 있어요.','growing scientific consensus','영어 토론에서 "growing consensus"는 "다수의 의견이 모이고 있다"는 뉘앙스예요. "anthropogenic"은 반드시 알아야 할 기후 관련 단어예요.','기후 과학 토론','B2','weather','pattern',NULL,3),
('s_weather_B2_04','The correlation between rising CO₂ levels and global average temperatures is well established.','CO₂ 수준 상승과 전 지구 평균 기온 사이의 상관관계는 잘 확립되어 있어요.','correlation is well established','"well established"는 과학적으로 검증된 사실을 언급할 때 쓰는 표현이에요. 토론에서 근거를 제시할 때 유용해요.','기후 과학 토론','B2','weather','pattern',NULL,4),
('s_weather_B2_05','Prolonged droughts in sub-Saharan Africa are threatening food security for millions.','사하라 이남 아프리카의 장기 가뭄이 수백만 명의 식량 안보를 위협하고 있어요.','Prolonged droughts threatening food security','사회적 영향을 설명하는 데 쓰는 구조로, "threaten + 명사"는 심각한 위협을 표현해요.','기후·사회 영향 토론','B2','weather','pattern',NULL,5),
('s_weather_B2_06','Rising sea levels pose an existential threat to low-lying island nations.','해수면 상승은 저지대 섬나라들에 실존적 위협을 가하고 있어요.','pose an existential threat','"pose a threat"은 "위협을 제기하다"라는 관용 표현이에요. "existential"은 생존 자체를 위협하는 수준의 위기를 나타내요.','기후·지정학 토론','B2','weather','pattern',NULL,6),
('s_weather_B2_07','Governments must implement ambitious policies to transition to a low-carbon economy.','정부는 저탄소 경제로 전환하기 위한 야심찬 정책을 시행해야 해요.','implement ambitious policies to transition','기후 정책 토론의 핵심 표현이에요. "transition to"는 변화의 방향을 나타내며, 기후 관련 논문·보고서에서 자주 등장해요.','기후 정책 토론','B2','weather','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_C1_01','The stratospheric ozone depletion and its recovery illustrate how policy intervention can reverse environmental damage.','성층권 오존 감소와 회복은 정책적 개입이 환경 피해를 되돌릴 수 있다는 것을 보여줘요.','illustrate how policy intervention can reverse','과학적 사례를 들어 정책의 효과를 논증하는 고급 학술 표현이에요. "illustrate"는 구체적 예시로 설명하다는 의미예요.','기후 정책 논의','C1','weather','pattern',NULL,1),
('s_weather_C1_02','The amplification of Arctic warming relative to the global average — often termed Arctic amplification — is accelerating permafrost thaw.','전 지구 평균 대비 북극 온난화 증폭, 즉 북극 증폭 현상이 영구 동토층 해빙을 가속하고 있어요.','Arctic amplification accelerating permafrost thaw','대시(—)로 전문 용어를 삽입하는 학술 문체예요. "relative to"는 "~에 비해"라는 비교 표현으로 논문에서 자주 쓰여요.','기후 과학 심화 논의','C1','weather','pattern',NULL,2),
('s_weather_C1_03','Teleconnections such as El Niño have profound implications for agricultural planning across the globe.','엘니뇨와 같은 원격 상관은 전 세계 농업 계획에 심대한 영향을 미쳐요.','Teleconnections have profound implications for','"have profound implications for"는 중대한 영향을 언급하는 학술 토론의 핵심 표현이에요.','기후·농업 연계 논의','C1','weather','pattern',NULL,3),
('s_weather_C1_04','Without significant reductions in radiative forcing, crossing multiple tipping points becomes increasingly probable.','복사 강제력을 크게 줄이지 않으면 여러 임계점을 넘을 가능성이 점점 높아져요.','Without significant reductions... becomes increasingly probable','조건절로 위험 시나리오를 논증하는 학술 표현이에요. "increasingly probable"은 확률의 점진적 증가를 표현해요.','기후 위험 논의','C1','weather','pattern',NULL,4),
('s_weather_C1_05','The thermohaline circulation is sensitive to freshwater input from melting ice sheets, which could disrupt heat distribution across the North Atlantic.','열염 순환은 빙상 녹음으로 인한 담수 유입에 민감하며, 이는 북대서양 전반의 열 분배를 교란할 수 있어요.','sensitive to freshwater input, could disrupt','"sensitive to"는 특정 요인에 민감하게 반응한다는 표현이에요. 관계절(which)로 결과를 이어 설명하는 학술 문장 구조예요.','해양 기후 논의','C1','weather','pattern',NULL,5),
('s_weather_C1_06','Climate models project a poleward shift of storm tracks, altering precipitation patterns in mid-latitudes.','기후 모델은 폭풍 경로의 극 방향 이동을 예측하며, 이는 중위도 강수 패턴을 변화시킬 거예요.','project a poleward shift, altering precipitation patterns','"project"가 명사가 아닌 동사로 "예측하다"를 뜻하는 학술적 용법이에요. 분사구문(altering)으로 결과를 우아하게 연결해요.','기후 모델 논의','C1','weather','pattern',NULL,6),
('s_weather_C1_07','Robust attribution studies have established that the 2021 Pacific Northwest heat dome was virtually impossible without anthropogenic climate forcing.','강력한 귀인 연구들은 2021년 태평양 연안 북서부의 열돔이 인위적 기후 강제력 없이는 사실상 불가능했음을 규명했어요.','attribution studies, virtually impossible without anthropogenic','기후 귀인 과학(attribution science)의 핵심 표현이에요. "virtually impossible without"은 특정 원인의 결정적 역할을 논증할 때 써요.','기후 귀인 연구 토론','C1','weather','pattern',NULL,7)
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_weather_C2_01','Paleoclimatological proxies, including ice cores and dendrochronological records, reveal that current warming rates are anomalous relative to any comparable interval in the Holocene.','빙하 코어와 수목 연륜 연대학 기록을 포함한 고기후학적 대리 지표들은 현재의 온난화 속도가 홀로세의 어떤 유사 구간과 비교해도 이례적임을 보여줘요.','Paleoclimatological proxies reveal anomalous relative to','최고급 학술 작문의 전형으로, 복잡한 명사구를 명사로 쌓는 방식이에요. "anomalous relative to"는 비교 기준을 제시하는 정교한 표현이에요.','고기후학 학술 토론','C2','weather','pattern',NULL,1),
('s_weather_C2_02','The biogeochemical feedbacks triggered by permafrost degradation — notably the release of previously sequestered methane and CO₂ — could render current emission reduction targets insufficient.','영구 동토층 분해로 촉발된 생물 지구 화학적 피드백, 특히 과거에 격리된 메탄과 CO₂의 방출은 현재의 배출 감소 목표를 불충분하게 만들 수 있어요.','biogeochemical feedbacks, render targets insufficient','복잡한 삽입절(—notably~—)과 "render + 목적어 + 형용사" 사역 구조를 활용한 최고급 표현이에요.','기후 과학 최고급 논의','C2','weather','pattern',NULL,2),
('s_weather_C2_03','Disentangling natural climate variability from anthropogenic forcing requires sophisticated attribution methodologies that account for the full breadth of internal climate oscillations.','자연적 기후 변동성과 인위적 강제력을 분리하려면 내부 기후 진동의 전체 범위를 고려하는 정교한 귀인 방법론이 필요해요.','Disentangling natural variability from anthropogenic forcing requires sophisticated methodologies','"Disentangle A from B"는 복잡하게 얽힌 두 요소를 분리한다는 뜻이에요. 동명사로 문장을 시작하는 학술 문체예요.','기후 귀인 방법론 토론','C2','weather','pattern',NULL,3),
('s_weather_C2_04','The convergence of thermohaline circulation weakening, sea ice albedo feedback, and permafrost carbon release represents a compound risk that integrated assessment models may systematically underestimate.','열염 순환 약화, 해빙 알베도 피드백, 영구 동토층 탄소 방출의 수렴은 통합 평가 모델이 체계적으로 과소평가할 수 있는 복합적 위험을 나타내요.','convergence of... represents a compound risk that models may underestimate','세 가지 병렬 명사구를 "The convergence of A, B, and C"로 묶어 논지를 구성하는 고급 학술 구조예요.','기후 복합 위험 논의','C2','weather','pattern',NULL,4),
('s_weather_C2_05','Dendroclimatological reconstructions corroborate instrumentally derived temperature anomalies, lending credibility to projections that current forcing trajectories will breach Holocene temperature bounds within decades.','수목 연륜 기후학적 재구성은 기기로 도출된 기온 편차를 입증하며, 현재 강제력 궤적이 수십 년 내에 홀로세 기온 한계를 돌파할 것이라는 전망에 신뢰성을 부여해요.','corroborate, lending credibility to projections that will breach','"corroborate"는 "입증하다·확증하다"는 C2급 어휘예요. "lending credibility"는 분사구문으로 결과를 연결해요.','고기후 자료 해석 토론','C2','weather','pattern',NULL,5),
('s_weather_C2_06','Radiative forcing from short-lived climate pollutants, particularly black carbon and tropospheric ozone, constitutes a non-trivial fraction of total anthropogenic warming that near-term mitigation could rapidly reverse.','단기 기후 오염 물질, 특히 블랙 카본과 대류권 오존에 의한 복사 강제력은 근기간 완화를 통해 신속하게 되돌릴 수 있는 전체 인위적 온난화의 비무시적 비율을 구성해요.','short-lived climate pollutants, non-trivial fraction, mitigation could rapidly reverse','"non-trivial"은 "무시할 수 없는·상당한"을 뜻하는 학술 부정 수식어예요. 관계절(that near-term mitigation could rapidly reverse)이 핵심 논거를 담아요.','기후 완화 정책 학술 토론','C2','weather','pattern',NULL,6),
('s_weather_C2_07','The epistemological challenge of projecting abrupt, threshold-crossing climate transitions lies in the inherently nonlinear dynamics of Earth system feedbacks, which resist reliable quantification within current modelling frameworks.','임계점을 넘는 갑작스러운 기후 전환을 예측하는 인식론적 과제는 현재 모델링 프레임워크 내에서 신뢰할 수 있는 정량화에 저항하는 지구 시스템 피드백의 본질적으로 비선형적인 역학에 있어요.','epistemological challenge, nonlinear dynamics, resist reliable quantification','"epistemological"은 지식의 한계를 논하는 철학 용어예요. 가장 높은 수준의 기후 과학 담론에서 나타나는 문장 구조와 어휘를 담고 있어요.','기후 과학 철학적 논의','C2','weather','pattern',NULL,7)
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
